CODEX_PROMPT_DIRECTIVES = ("/fast",)


def apply_codex_prompt_directives(prompt: str) -> str:
    body = str(prompt or "").lstrip()
    if not body:
        return "\n".join(CODEX_PROMPT_DIRECTIVES)
    for directive in CODEX_PROMPT_DIRECTIVES:
        if body.startswith(f"{directive}\n") or body == directive:
            return body
    return "\n".join(CODEX_PROMPT_DIRECTIVES) + "\n\n" + body


def utc_now() -> dt.datetime:
    return dt.datetime.now(UTC)


def iso(ts: Optional[dt.datetime]) -> Optional[str]:
    return ts.astimezone(UTC).replace(microsecond=0).isoformat().replace("+00:00", "Z") if ts else None


def parse_iso(value: Optional[str]) -> Optional[dt.datetime]:
    if not value:
        return None
    if value.endswith("Z"):
        value = value[:-1] + "+00:00"
    try:
        return dt.datetime.fromisoformat(value).astimezone(UTC)
    except ValueError:
        return None


def new_service_trace_id(service: str, *, started_at: Optional[dt.datetime] = None) -> str:
    stamp = (started_at or utc_now()).strftime("%Y%m%dT%H%M%SZ").lower()
    token = uuid.uuid4().hex[:12]
    clean_service = re.sub(r"[^a-z0-9]+", "-", str(service or "").strip().lower()).strip("-") or "fleet"
    return f"{clean_service}-{stamp}-{token}"


def float_or_none(value: Any) -> Optional[float]:
    try:
        if value is None:
            return None
        if isinstance(value, str) and not value.strip():
            return None
        return float(value)
    except Exception:
        return None


def wall_seconds(started_at: Optional[str], finished_at: Optional[str]) -> Optional[float]:
    started = parse_iso(started_at)
    finished = parse_iso(finished_at)
    if not started or not finished:
        return None
    seconds = (finished - started).total_seconds()
    if seconds <= 0:
        return None
    return seconds


def median_seconds(values: List[float]) -> Optional[float]:
    ordered = sorted(value for value in values if value > 0)
    if not ordered:
        return None
    mid = len(ordered) // 2
    if len(ordered) % 2 == 1:
        return ordered[mid]
    return (ordered[mid - 1] + ordered[mid]) / 2.0


def human_duration(seconds: Optional[float]) -> str:
    if seconds is None:
        return ""
    total = max(0, int(round(seconds)))
    if total == 0:
        return "0s"
    days, rem = divmod(total, 86400)
    hours, rem = divmod(rem, 3600)
    minutes, secs = divmod(rem, 60)
    parts: List[str] = []
    if days:
        parts.append(f"{days}d")
    if hours:
        parts.append(f"{hours}h")
    if minutes:
        parts.append(f"{minutes}m")
    if not parts and secs:
        parts.append(f"{secs}s")
    return " ".join(parts[:2])


def runtime_completion_state(runtime_status: str, lifecycle: str) -> str:
    status = str(runtime_status or "").strip().lower()
    lifecycle_state = normalize_lifecycle_state(lifecycle, "dispatchable")
    if status == "signoff_only" or lifecycle_state == "signoff_only":
        return "signoff_only"
    if status in {"starting", "running", "verifying"}:
        return "in_progress"
    if status in REVIEW_VISIBLE_STATUSES:
        return "review_gate"
    if status in {HEALING_STATUS, QUEUE_REFILLING_STATUS, DECISION_REQUIRED_STATUS, SOURCE_BACKLOG_OPEN_STATUS, "blocked"}:
        return "recovery_pending"
    if status in {CONFIGURED_QUEUE_COMPLETE_STATUS, "complete"}:
        return "runtime_complete"
    if status == SCAFFOLD_QUEUE_COMPLETE_STATUS or lifecycle_state == "scaffold":
        return "scaffold_complete"
    if status == COMPLETED_SIGNED_OFF_STATUS:
        return "signed_off"
    if status == READY_STATUS:
        return "dispatch_ready"
    return status or "unknown"


def project_public_runtime_status(project: Dict[str, Any]) -> str:
    status = str(project.get("status") or project.get("runtime_status") or "").strip().lower()
    if status:
        return status
    return project_runtime_status(project).lower()


def design_completion_state(
    *,
    milestone_coverage_complete: bool,
    design_coverage_complete: bool,
    group_signed_off: bool,
) -> str:
    if group_signed_off and milestone_coverage_complete and design_coverage_complete:
        return "signed_off"
    if milestone_coverage_complete and design_coverage_complete:
        return "covered_pending_signoff"
    if design_coverage_complete:
        return "design_covered_pending_milestones"
    if milestone_coverage_complete:
        return "milestones_mapped_pending_design"
    return "incomplete"


def truncate_title(text: str, max_len: int = 72) -> str:
    clean = " ".join(str(text or "").strip().split())
    if len(clean) <= max_len:
        return clean or "fleet slice"
    return clean[: max_len - 1].rstrip() + "…"


def _ensure_writable_dir(path: pathlib.Path, *, fallback_leaf: str) -> pathlib.Path:
    try:
        path.mkdir(parents=True, exist_ok=True)
    except PermissionError:
        pass
    if path.exists() and os.access(path, os.W_OK | os.X_OK):
        return path
    fallback = RUNTIME_FALLBACK_ROOT / fallback_leaf
    fallback.mkdir(parents=True, exist_ok=True)
    return fallback


def _ensure_writable_file_path(path: pathlib.Path, *, fallback_leaf: str) -> pathlib.Path:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
    except PermissionError:
        pass
    if path.parent.exists() and os.access(path.parent, os.W_OK | os.X_OK):
        return path
    fallback = RUNTIME_FALLBACK_ROOT / fallback_leaf
    fallback.parent.mkdir(parents=True, exist_ok=True)
    return fallback


def ensure_dirs() -> None:
    global DB_PATH, LOG_DIR, WORKTREE_ROOT, CONTROLLER_HEARTBEAT_PATH, CODEX_HOME_ROOT, GROUP_ROOT, MAIL_OUTBOX_ROOT, MAIL_STATE_PATH

    DB_PATH = _ensure_writable_file_path(DB_PATH, fallback_leaf="fleet.db")
    LOG_DIR = _ensure_writable_dir(LOG_DIR, fallback_leaf="logs")
    WORKTREE_ROOT = _ensure_writable_dir(WORKTREE_ROOT, fallback_leaf="worktrees")
    CONTROLLER_HEARTBEAT_PATH = _ensure_writable_file_path(
        CONTROLLER_HEARTBEAT_PATH,
        fallback_leaf="controller-heartbeat.json",
    )
    CODEX_HOME_ROOT = _ensure_writable_dir(CODEX_HOME_ROOT, fallback_leaf="codex-homes")
    GROUP_ROOT = _ensure_writable_dir(GROUP_ROOT, fallback_leaf="groups")

    resolved_mail_outbox = _ensure_writable_dir(mail_outbox_root(), fallback_leaf="mail-outbox")
    MAIL_OUTBOX_ROOT = resolved_mail_outbox
    MAIL_STATE_PATH = _ensure_writable_file_path(mail_state_path(), fallback_leaf="mail-state.json")


def write_controller_heartbeat(*, status: str, detail: str = "") -> None:
    payload = {
        "updated_at": iso(utc_now()),
        "status": str(status or "").strip() or "unknown",
        "detail": str(detail or "").strip(),
        "pid": os.getpid(),
    }
    CONTROLLER_HEARTBEAT_PATH.parent.mkdir(parents=True, exist_ok=True)
    tmp_path = CONTROLLER_HEARTBEAT_PATH.with_suffix(".tmp")
    tmp_path.parent.mkdir(parents=True, exist_ok=True)
    tmp_path.write_text(json.dumps(payload, sort_keys=True), encoding="utf-8")
    tmp_path.replace(CONTROLLER_HEARTBEAT_PATH)


def controller_heartbeat_loop(stop_event: threading.Event, interval_seconds: float = 5.0) -> None:
    interval = max(float(interval_seconds), 1.0)
    while not stop_event.is_set():
        write_controller_heartbeat(status="running", detail="controller_loop_alive")
        stop_event.wait(interval)


def db() -> sqlite3.Connection:
    ensure_dirs()
    conn = sqlite3.connect(DB_PATH, timeout=30.0)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA foreign_keys=ON")
    conn.execute("PRAGMA busy_timeout=30000")
    global _DB_WAL_READY
    if not _DB_WAL_READY:
        with _DB_WAL_LOCK:
            if not _DB_WAL_READY:
                try:
                    conn.execute("PRAGMA journal_mode=WAL")
                except sqlite3.OperationalError as exc:
                    if "locked" not in str(exc).lower():
                        raise
                else:
                    _DB_WAL_READY = True
    return conn


def mail_outbox_root() -> pathlib.Path:
    return pathlib.Path(MAIL_OUTBOX_ROOT) if MAIL_OUTBOX_ROOT else (DB_PATH.parent / "mail-outbox")


def mail_state_path() -> pathlib.Path:
    return pathlib.Path(MAIL_STATE_PATH) if MAIL_STATE_PATH else (DB_PATH.parent / "mail-state.json")


def table_exists(name: str) -> bool:
    if not DB_PATH.exists():
        return False
    with db() as conn:
        row = conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (name,)).fetchone()
    return bool(row)


