def normalize_scope_path(value: Any) -> str:
    text = str(value or "").strip().replace("\\", "/").strip("/")
    return text


def scope_claim_conflicts(
    left_type: str,
    left_value: str,
    right_type: str,
    right_value: str,
) -> bool:
    lt = str(left_type or "").strip().lower()
    rt = str(right_type or "").strip().lower()
    lv = normalize_scope_path(left_value)
    rv = normalize_scope_path(right_value)
    if not (lt and rt and lv and rv):
        return False
    if lt == "build_root" or rt == "build_root":
        return lv == rv
    if lt == "surface" and rt == "surface":
        return lv == rv
    if lt == "path" and rt == "path":
        if any(token in lv for token in "*?[") or any(token in rv for token in "*?["):
            return fnmatch.fnmatch(lv, rv) or fnmatch.fnmatch(rv, lv)
        return lv == rv or lv.startswith(rv + "/") or rv.startswith(lv + "/")
    return False


def default_package_id(project_id: str, title: str, queue_index: int) -> str:
    digest = hashlib.sha1(f"{project_id}|{queue_index}|{title}".encode("utf-8")).hexdigest()[:10]
    return f"{package_safe_token(project_id)}-{queue_index:04d}-{package_safe_token(title)[:40]}-{digest}"


def default_package_branch(project_id: str, package_id: str) -> str:
    return package_safe_token(f"fleet/{project_id}/{package_id}").replace("-", "/fleet-", 1) if "/" not in package_id else package_id


def default_worktree_root(project_id: str, package_id: str) -> pathlib.Path:
    return WORKTREE_ROOT / package_safe_token(project_id) / package_safe_token(package_id)


def work_package_source_queue_fingerprint(items: Sequence[Any]) -> str:
    payload = json.dumps(
        queue_fingerprint_source_items(items),
        sort_keys=True,
        separators=(",", ":"),
        ensure_ascii=True,
        default=str,
    )
    return hashlib.sha1(payload.encode("utf-8")).hexdigest()


def project_configured_queue_source_items(project_cfg: Dict[str, Any]) -> List[Any]:
    source_items = project_cfg.get("_configured_queue_source_items")
    if isinstance(source_items, list):
        return queue_fingerprint_source_items(source_items)
    queue = queue_fingerprint_source_items(project_cfg.get("queue") or [])
    if bool(project_cfg.get("_queue_is_effective")):
        return queue
    for source_cfg in project_cfg.get("queue_sources") or []:
        queue = apply_queue_source(project_cfg, queue, source_cfg)
    return queue_fingerprint_source_items(queue)


def project_configured_queue_source_fingerprint(project_cfg: Dict[str, Any]) -> str:
    explicit = str(project_cfg.get("_configured_queue_source_fingerprint") or "").strip()
    if explicit:
        return explicit
    return work_package_source_queue_fingerprint(project_configured_queue_source_items(project_cfg))


def project_effective_queue_source_items(project_cfg: Dict[str, Any]) -> List[Any]:
    source_items = project_cfg.get("_effective_queue_source_items")
    if isinstance(source_items, list):
        return queue_fingerprint_source_items(source_items)
    return queue_fingerprint_source_items(project_cfg.get("queue") or [])


def project_effective_queue_source_fingerprint(project_cfg: Dict[str, Any]) -> str:
    explicit = str(project_cfg.get("_effective_queue_source_fingerprint") or "").strip()
    if explicit:
        return explicit
    return work_package_source_queue_fingerprint(project_effective_queue_source_items(project_cfg))


def generated_work_packages_match_effective_queue(
    project_cfg: Dict[str, Any],
    raw_packages: Sequence[Any],
    *,
    lanes: Optional[Dict[str, Any]] = None,
) -> bool:
    queue_items = list(project_effective_queue_source_items(project_cfg))
    package_rows = [dict(item) for item in raw_packages if isinstance(item, dict)]
    if not queue_items or len(package_rows) != len(queue_items):
        return False
    if any(isinstance(item, dict) for item in queue_items):
        # Only self-heal stale fingerprints for text-only queue overlays.
        # Dict-backed queue items can carry richer dispatch contract fields
        # that require an explicit recompile instead of optimistic rebinding.
        return False
    project_id = str(project_cfg.get("id") or "").strip()
    if not project_id:
        return False
    for index, (queue_item, package_row) in enumerate(zip(queue_items, package_rows)):
        task_meta = normalize_task_queue_item(queue_item, lanes=lanes)
        title = str(task_meta.get("title") or normalize_slice_text(queue_item) or f"Package {index + 1}").strip()
        if not title:
            return False
        raw_queue_item = dict(queue_item) if isinstance(queue_item, dict) else {}
        expected_package_id = (
            str(task_meta.get("package_id") or raw_queue_item.get("package_id") or "").strip()
            or default_package_id(project_id, title, index)
        )
        actual_package_id = str(package_row.get("package_id") or "").strip()
        actual_title = str(package_row.get("title") or "").strip()
        if actual_package_id != expected_package_id or actual_title != title:
            return False
    return True


def rebind_generated_work_packages_source_fingerprint(
    project_cfg: Dict[str, Any],
    *,
    path: pathlib.Path,
    payload: Dict[str, Any],
    raw_packages: Sequence[Any],
    current_queue_fingerprint: str,
) -> bool:
    if not current_queue_fingerprint or not generated_work_packages_match_effective_queue(project_cfg, raw_packages):
        return False
    updated_payload = dict(payload)
    updated_payload["source_queue_fingerprint"] = current_queue_fingerprint
    path.write_text(yaml.safe_dump(updated_payload, sort_keys=False), encoding="utf-8")
    return True


def package_scope_matches(path: str, patterns: Sequence[str]) -> bool:
    clean = normalize_scope_path(path)
    if not clean:
        return False
    return any(fnmatch.fnmatch(clean, str(pattern).strip()) for pattern in patterns if str(pattern).strip())


def normalize_package_kind(value: Any) -> str:
    return str(value or "implementation").strip().lower() or "implementation"


def horizon_lock_surface_value(package_kind: Any, horizon_family: Any) -> str:
    clean_kind = normalize_package_kind(package_kind)
    clean_family = package_safe_token(str(horizon_family or "").strip())
    if not clean_family or clean_kind not in HORIZON_LOCKED_PACKAGE_KINDS:
        return ""
    return f"horizon_family:{clean_kind}:{clean_family}"


def load_generated_work_packages(project_cfg: Dict[str, Any]) -> List[Dict[str, Any]]:
    path = work_packages_generated_path(project_cfg)
    if not path.exists() or not path.is_file():
        return []
    try:
        data = yaml.safe_load(path.read_text(encoding="utf-8")) or {}
    except Exception:
        return []
    if isinstance(data, list):
        raw_items = data
    elif isinstance(data, dict):
        raw_items = data.get("packages")
        if raw_items is None:
            raw_items = data.get("items")
        if raw_items is None:
            raw_items = data.get("work_packages")
        if raw_items is None:
            raw_items = []
    else:
        raw_items = []
    expected_queue_fingerprint = ""
    if isinstance(data, dict):
        expected_queue_fingerprint = str(data.get("source_queue_fingerprint") or data.get("queue_fingerprint") or "").strip()
    current_queue_fingerprint = project_effective_queue_source_fingerprint(project_cfg)
    if expected_queue_fingerprint:
        if expected_queue_fingerprint != current_queue_fingerprint:
            if not (
                isinstance(data, dict)
                and rebind_generated_work_packages_source_fingerprint(
                    project_cfg,
                    path=path,
                    payload=data,
                    raw_packages=raw_items,
                    current_queue_fingerprint=current_queue_fingerprint,
                )
            ):
                return []
    elif project_effective_queue_source_items(project_cfg):
        return []
    packages: List[Dict[str, Any]] = []
    for item in raw_items or []:
        if isinstance(item, dict):
            packages.append(dict(item))
    return packages


def apply_generated_work_package_policy(
    task_meta: Dict[str, Any],
    *,
    allowed_paths: Sequence[str],
    denied_paths: Sequence[str],
    package_kind: Any = "",
    horizon_family: Any = "",
) -> Dict[str, Any]:
    policy = dict(task_meta or {})
    clean_package_kind = normalize_package_kind(package_kind or policy.get("package_kind"))
    clean_horizon_family = str(horizon_family or policy.get("horizon_family") or "").strip()
    policy["package_kind"] = clean_package_kind
    if clean_horizon_family:
        policy["horizon_family"] = clean_horizon_family
    effective_denied_paths = [
        normalize_scope_path(item)
        for item in denied_paths
        if normalize_scope_path(item)
    ]

    def add_default_denied_patterns(patterns: Sequence[str]) -> None:
        for pattern in patterns:
            clean_pattern = normalize_scope_path(pattern)
            if clean_pattern and clean_pattern not in effective_denied_paths:
                effective_denied_paths.append(clean_pattern)

    package_compile_target = f".codex-studio/published/{WORKPACKAGES_FILENAME}"
    immutable_generated_paths = [path for path in allowed_paths if package_scope_matches(path, IMMUTABLE_PUBLISHED_GENERATED_SCOPE_PATTERNS)]
    if clean_package_kind == PACKAGE_COMPILE_PACKAGE_KIND:
        immutable_generated_paths = [
            path
            for path in immutable_generated_paths
            if normalize_scope_path(path) != normalize_scope_path(package_compile_target)
        ]
    if immutable_generated_paths:
        policy["dispatchability_state"] = "blocked"
        policy["dispatchability_reason"] = (
            "generated published artifacts must be rebuilt from source compilers, not edited directly: "
            + ", ".join(sorted(immutable_generated_paths))
        )
    if clean_package_kind != PACKAGE_COMPILE_PACKAGE_KIND:
        add_default_denied_patterns(IMMUTABLE_PUBLISHED_GENERATED_SCOPE_PATTERNS)

    authority_only_paths = [path for path in allowed_paths if package_scope_matches(path, AUTHORITY_ONLY_PACKAGE_SCOPE_PATTERNS)]
    if clean_package_kind == PACKAGE_COMPILE_PACKAGE_KIND:
        authority_only_paths = [
            path
            for path in authority_only_paths
            if normalize_scope_path(path) != normalize_scope_path(package_compile_target)
        ]
    if authority_only_paths:
        allowed_lanes = [
            str(item or "").strip().lower()
            for item in policy.get("allowed_lanes") or []
            if str(item or "").strip()
        ]
        allowed_lanes = [lane for lane in allowed_lanes if lane not in {"core", "core_booster"}]
        policy["allowed_lanes"] = ["core_authority", *[lane for lane in allowed_lanes if lane != "core_authority"]]
        policy["review_lane"] = "core_authority"
        policy["merge_owner_lane"] = "core_authority"
        policy["required_reviewer_lane"] = "core_authority"
        policy["final_reviewer_lane"] = "core_authority"
        policy["landing_lane"] = "core_authority"
        policy["requires_contract_authority"] = True
        policy["authority_only_paths"] = sorted(authority_only_paths)
    if clean_package_kind in AUTHORITY_PACKAGE_KINDS:
        allowed_lanes = [
            str(item or "").strip().lower()
            for item in policy.get("allowed_lanes") or []
            if str(item or "").strip()
        ]
        allowed_lanes = [lane for lane in allowed_lanes if lane not in {"core", "core_booster"}]
        policy["allowed_lanes"] = ["core_authority", *[lane for lane in allowed_lanes if lane != "core_authority"]]
        policy["review_lane"] = "core_authority"
        policy["merge_owner_lane"] = "core_authority"
        policy["required_reviewer_lane"] = "core_authority"
        policy["final_reviewer_lane"] = "core_authority"
        policy["landing_lane"] = "core_authority"
        policy["requires_contract_authority"] = True
        add_default_denied_patterns(DESIGN_PROPOSAL_SCOPE_PATTERNS)
    if clean_package_kind == PACKAGE_COMPILE_PACKAGE_KIND:
        if not allowed_paths:
            policy["dispatchability_state"] = "blocked"
            policy["dispatchability_reason"] = "package_compile packages must declare explicit allowed_paths for WORKPACKAGES.generated.yaml"
        else:
            out_of_compile_scope = [
                path
                for path in allowed_paths
                if normalize_scope_path(path) != normalize_scope_path(package_compile_target)
            ]
            if out_of_compile_scope:
                policy["dispatchability_state"] = "blocked"
                policy["dispatchability_reason"] = (
                    "package_compile packages may only rebuild WORKPACKAGES.generated.yaml: "
                    + ", ".join(sorted(out_of_compile_scope))
                )
    if clean_package_kind == "design_proposal":
        if not allowed_paths:
            policy["dispatchability_state"] = "blocked"
            policy["dispatchability_reason"] = "design_proposal packages must declare explicit allowed_paths inside proposal-only surfaces"
        else:
            out_of_proposal_scope = [path for path in allowed_paths if not package_scope_matches(path, DESIGN_PROPOSAL_SCOPE_PATTERNS)]
            if out_of_proposal_scope:
                policy["dispatchability_state"] = "blocked"
                policy["dispatchability_reason"] = (
                    "design_proposal packages must stay inside proposal-only surfaces: "
                    + ", ".join(sorted(out_of_proposal_scope))
                )
        add_default_denied_patterns(AUTHORITY_ONLY_PACKAGE_SCOPE_PATTERNS)
    elif clean_package_kind == "implementation":
        proposal_scope_paths = [path for path in allowed_paths if package_scope_matches(path, DESIGN_PROPOSAL_SCOPE_PATTERNS)]
        if proposal_scope_paths:
            policy["dispatchability_state"] = "blocked"
            policy["dispatchability_reason"] = (
                "implementation packages cannot write proposal-only surfaces: "
                + ", ".join(sorted(proposal_scope_paths))
            )
        add_default_denied_patterns(DESIGN_PROPOSAL_SCOPE_PATTERNS)
    if effective_denied_paths:
        policy["denied_paths"] = effective_denied_paths
    return policy


def compiled_scope_claims_for_package(package: Dict[str, Any]) -> List[Dict[str, str]]:
    package_id = str(package.get("package_id") or "").strip()
    project_id = str(package.get("project_id") or "").strip()
    claims: List[Dict[str, str]] = []
    allowed_paths = [normalize_scope_path(item) for item in package.get("allowed_paths") or [] if normalize_scope_path(item)]
    owned_surfaces = [str(item).strip() for item in package.get("owned_surfaces") or [] if str(item).strip()]
    horizon_surface = horizon_lock_surface_value(package.get("package_kind"), package.get("horizon_family"))
    if allowed_paths:
        for path in allowed_paths:
            claims.append(
                {
                    "package_id": package_id,
                    "project_id": project_id,
                    "claim_type": "path",
                    "claim_value": path,
                    "scope_key": f"path:{path}",
                }
            )
    if owned_surfaces:
        for surface in owned_surfaces:
            claims.append(
                {
                    "package_id": package_id,
                    "project_id": project_id,
                    "claim_type": "surface",
                    "claim_value": surface,
                    "scope_key": f"surface:{surface}",
                }
            )
    if horizon_surface:
        claims.append(
            {
                "package_id": package_id,
                "project_id": project_id,
                "claim_type": "surface",
                "claim_value": horizon_surface,
                "scope_key": f"surface:{horizon_surface}",
            }
        )
    if not claims:
        claims.append(
            {
                "package_id": package_id,
                "project_id": project_id,
                "claim_type": "build_root",
                "claim_value": project_id,
                "scope_key": f"build_root:{project_id}",
            }
        )
    return claims


def task_meta_allows_booster_lane(task_meta: Dict[str, Any], *, lanes: Optional[Dict[str, Any]] = None) -> bool:
    allowed_lanes = expand_serviceable_lanes(
        list(task_meta.get("allowed_lanes") or ["easy", "repair", "core"]),
        task_meta=task_meta,
        lanes=lanes,
    )
    if not bool(task_meta.get("allow_credit_burn")) and not bool(task_meta.get("premium_required")):
        return False
    return any(str(lane).strip().lower() in {"core", "core_booster"} for lane in allowed_lanes)


def task_meta_has_explicit_package_scope(task_meta: Dict[str, Any], raw_item: Any) -> bool:
    raw = dict(raw_item) if isinstance(raw_item, dict) else {}
    allowed_paths = [normalize_scope_path(item) for item in (task_meta.get("allowed_paths") or raw.get("allowed_paths") or []) if normalize_scope_path(item)]
    owned_surfaces = [str(item).strip() for item in (task_meta.get("owned_surfaces") or raw.get("owned_surfaces") or []) if str(item).strip()]
    return bool(allowed_paths or owned_surfaces)


RAW_QUEUE_TERMINAL_STATUSES = {"done", "complete", "completed", "shipped", "archived", "cancelled", "canceled", "skipped"}


def raw_queue_item_terminal_status(raw_item: Any, task_meta: Optional[Dict[str, Any]] = None) -> str:
    raw = dict(raw_item) if isinstance(raw_item, dict) else {}
    meta = dict(task_meta or {})
    status = str(meta.get("status") or raw.get("status") or "").strip().lower()
    return status if status in RAW_QUEUE_TERMINAL_STATUSES else ""


def existing_work_package_terminal_status(raw_item: Any, task_meta: Optional[Dict[str, Any]] = None) -> str:
    raw = dict(raw_item) if isinstance(raw_item, dict) else {}
    meta = dict(task_meta or {})
    package_id = str(meta.get("package_id") or raw.get("package_id") or "").strip()
    if not package_id:
        return ""
    try:
        row = work_package_row(package_id)
    except Exception:
        return ""
    status = str((row or {}).get("status") or "").strip().lower()
    if status == "complete" or status in RAW_QUEUE_TERMINAL_STATUSES:
        return status
    return ""


def queue_item_terminal_status(raw_item: Any, task_meta: Optional[Dict[str, Any]] = None) -> str:
    raw = dict(raw_item) if isinstance(raw_item, dict) else {}
    meta = dict(task_meta or {})
    explicit_status = str(meta.get("status") or raw.get("status") or "").strip().lower()
    if explicit_status:
        return explicit_status if explicit_status in RAW_QUEUE_TERMINAL_STATUSES else ""
    return existing_work_package_terminal_status(raw_item, task_meta)


def build_package_compile_work_item(
    project_cfg: Dict[str, Any],
    raw_items: Sequence[Dict[str, Any]],
) -> Dict[str, Any]:
    project_id = str(project_cfg.get("id") or "").strip()
    queue_fingerprint = project_effective_queue_source_fingerprint(project_cfg) or work_package_source_queue_fingerprint(raw_items)
    target_relpath = f".codex-studio/published/{WORKPACKAGES_FILENAME}"
    return {
        "package_id": f"{package_safe_token(project_id)}-package-compile-{queue_fingerprint[:10]}",
        "queue_index": -1,
        "priority": -100,
        "title": "Compile booster-ready work packages from queue truth",
        "package_kind": PACKAGE_COMPILE_PACKAGE_KIND,
        "source_ref": "quartermaster.package_compile",
        "allowed_lanes": ["core_booster", "core_authority"],
        "allow_credit_burn": False,
        "premium_required": False,
        "required_reviewer_lane": "core_authority",
        "final_reviewer_lane": "core_authority",
        "review_lane": "core_authority",
        "merge_owner_lane": "core_authority",
        "landing_lane": "core_authority",
        "allowed_paths": [target_relpath],
        "owned_surfaces": [f"package_compile:{project_id}"],
        "dependencies": [],
        "package_compile_target_path": target_relpath,
        "package_compile_source_queue_fingerprint": queue_fingerprint,
        "package_compile_goal": (
            "Materialize WORKPACKAGES.generated.yaml into small, explicit, scope-safe packages so quartermaster "
            "can keep a real booster-ready reserve instead of a serial raw queue."
        ),
    }


def project_requires_package_compile(
    project_cfg: Dict[str, Any],
    raw_items: Sequence[Dict[str, Any]],
    *,
    lanes: Optional[Dict[str, Any]] = None,
) -> bool:
    if not raw_items:
        return False
    booster_candidates = 0
    scoped_booster_candidates = 0
    for raw_item in raw_items:
        task_meta = normalize_task_queue_item(raw_item, lanes=lanes)
        if queue_item_terminal_status(raw_item, task_meta):
            continue
        if not task_meta_allows_booster_lane(task_meta, lanes=lanes):
            continue
        booster_candidates += 1
        if task_meta_has_explicit_package_scope(task_meta, raw_item):
            scoped_booster_candidates += 1
    return booster_candidates > 0 and scoped_booster_candidates < booster_candidates


def queue_package_needs_serial_dependency(task_meta: Dict[str, Any], raw_item: Any) -> bool:
    raw = dict(raw_item) if isinstance(raw_item, dict) else {}
    if task_meta_has_explicit_package_scope(task_meta, raw_item):
        return False
    if str(task_meta.get("package_kind") or raw.get("package_kind") or "").strip().lower() in AUTHORITY_PACKAGE_KINDS:
        return False
    return True


def compile_project_work_packages(project_cfg: Dict[str, Any], *, lanes: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    project_id = str(project_cfg.get("id") or "").strip()
    if not project_id:
        return []
    explicit_packages = load_generated_work_packages(project_cfg)
    raw_items: List[Dict[str, Any]] = explicit_packages if explicit_packages else [
        {
            **(dict(item) if isinstance(item, dict) else {"title": normalize_slice_text(item)}),
            "queue_index": index,
        }
        for index, item in enumerate(project_cfg.get("queue") or [])
    ]
    package_compile_id = ""
    if not explicit_packages and project_requires_package_compile(project_cfg, raw_items, lanes=lanes):
        compile_item = build_package_compile_work_item(project_cfg, raw_items)
        package_compile_id = str(compile_item.get("package_id") or "").strip()
        raw_items = [compile_item, *raw_items]
    compiled: List[Dict[str, Any]] = []
    previous_queue_package_id = ""
    for index, raw_item in enumerate(raw_items):
        task_meta = normalize_task_queue_item(raw_item, lanes=lanes)
        title = str(task_meta.get("title") or normalize_slice_text(raw_item) or f"Package {index + 1}").strip()
        if not title:
            continue
        raw_queue_index = raw_item.get("queue_index") if isinstance(raw_item, dict) else None
        queue_index = int(raw_queue_index) if raw_queue_index is not None else index
        package_id = str(task_meta.get("package_id") or raw_item.get("package_id") or "").strip() or default_package_id(project_id, title, queue_index)
        dependencies = [str(item).strip() for item in (task_meta.get("dependencies") or raw_item.get("dependencies") or []) if str(item).strip()]
        package_kind = normalize_package_kind(task_meta.get("package_kind") or raw_item.get("package_kind") or "implementation")
        declared_status = queue_item_terminal_status(raw_item, task_meta)
        if package_compile_id and package_id != package_compile_id and package_compile_id not in dependencies:
            dependencies = [package_compile_id, *dependencies]
        if (
            not explicit_packages
            and previous_queue_package_id
            and queue_package_needs_serial_dependency(task_meta, raw_item)
            and previous_queue_package_id not in dependencies
        ):
            dependencies = [*dependencies, previous_queue_package_id]
        branch_name = str(task_meta.get("branch_name") or raw_item.get("branch_name") or "").strip() or f"fleet/{package_safe_token(project_id)}/{package_safe_token(package_id)}"
        allowed_paths = [normalize_scope_path(item) for item in (task_meta.get("allowed_paths") or raw_item.get("allowed_paths") or []) if normalize_scope_path(item)]
        denied_paths = [normalize_scope_path(item) for item in (task_meta.get("denied_paths") or raw_item.get("denied_paths") or []) if normalize_scope_path(item)]
        owned_surfaces = [str(item).strip() for item in (task_meta.get("owned_surfaces") or raw_item.get("owned_surfaces") or []) if str(item).strip()]
        horizon_family = str(task_meta.get("horizon_family") or raw_item.get("horizon_family") or "").strip()
        task_meta = apply_generated_work_package_policy(
            task_meta,
            allowed_paths=allowed_paths,
            denied_paths=denied_paths,
            package_kind=package_kind,
            horizon_family=horizon_family,
        )
        denied_paths = [
            normalize_scope_path(item)
            for item in (task_meta.get("denied_paths") or denied_paths)
            if normalize_scope_path(item)
        ]
        package = {
            "package_id": package_id,
            "project_id": project_id,
            "queue_index": queue_index,
            "title": title,
            "slice_name": title,
            "package_kind": normalize_package_kind(task_meta.get("package_kind") or raw_item.get("package_kind") or "implementation"),
            "horizon_family": str(task_meta.get("horizon_family") or raw_item.get("horizon_family") or "").strip(),
            "source_kind": "generated" if explicit_packages else "queue",
            "source_ref": (
                str(work_packages_generated_path(project_cfg).relative_to(pathlib.Path(project_cfg["path"])).as_posix())
                if explicit_packages
                else str(raw_item.get("source_ref") or f"queue[{queue_index}]")
            ),
            "task_meta": task_meta,
            "allowed_paths": allowed_paths,
            "denied_paths": denied_paths,
            "owned_surfaces": owned_surfaces,
            "dependencies": dependencies,
            "review_lane": str(task_meta.get("review_lane") or raw_item.get("review_lane") or task_meta.get("required_reviewer_lane") or "").strip().lower(),
            "audit_lane": str(task_meta.get("audit_lane") or raw_item.get("audit_lane") or "audit_shard").strip().lower(),
            "merge_owner_lane": str(task_meta.get("merge_owner_lane") or raw_item.get("merge_owner_lane") or task_meta.get("landing_lane") or "jury").strip().lower(),
            "branch_name": branch_name,
            "base_ref": str(task_meta.get("base_ref") or raw_item.get("base_ref") or (project_review_policy(project_cfg).get("base_branch") or "HEAD")).strip(),
            "worktree_root": str(default_worktree_root(project_id, package_id)),
            "sponsor_source": str(task_meta.get("sponsor_source") or raw_item.get("sponsor_source") or "").strip(),
            "max_touched_files": int(task_meta.get("max_touched_files") or raw_item.get("max_touched_files") or 0),
            "priority": int(task_meta.get("priority") or raw_item.get("priority") or index),
            "ttl_seconds": int(task_meta.get("ttl_seconds") or raw_item.get("ttl_seconds") or 0),
            "declared_status": declared_status,
        }
        compiled.append(package)
        if package_kind != PACKAGE_COMPILE_PACKAGE_KIND:
            previous_queue_package_id = package_id
    return compiled


def work_package_dependencies_satisfied(package: Dict[str, Any]) -> bool:
    dependencies = [str(item).strip() for item in package.get("dependencies") or [] if str(item).strip()]
    if not dependencies:
        return True
    placeholders = ", ".join("?" for _ in dependencies)
    with db() as conn:
        rows = conn.execute(
            f"SELECT package_id, status FROM work_packages WHERE package_id IN ({placeholders})",
            tuple(dependencies),
        ).fetchall()
    status_by_package = {str(row["package_id"] or "").strip(): str(row["status"] or "").strip().lower() for row in rows}
    return all(status_by_package.get(dep) in TERMINAL_WORK_PACKAGE_STATUSES for dep in dependencies)


def sync_work_packages_to_db(config: Dict[str, Any]) -> None:
    if not table_exists("work_packages"):
        return
    now_text = iso(utc_now())
    seen: set[str] = set()
    compiled_by_project: Dict[str, List[Dict[str, Any]]] = {}
    for project_cfg in config.get("projects") or []:
        packages = compile_project_work_packages(project_cfg, lanes=config.get("lanes") or {})
        compiled_by_project[str(project_cfg.get("id") or "")] = packages
        with db() as conn:
            for package in packages:
                package_id = str(package.get("package_id") or "").strip()
                if not package_id:
                    continue
                seen.add(package_id)
                existing = conn.execute(
                    "SELECT status, runtime_state, latest_run_id, latest_pr_id, completed_at, created_at FROM work_packages WHERE package_id=?",
                    (package_id,),
                ).fetchone()
                runtime_state = str((existing["runtime_state"] if existing else "idle") or "idle").strip().lower() or "idle"
                existing_status = str((existing["status"] if existing else "") or "").strip().lower()
                completed_at = str((existing["completed_at"] if existing else "") or "").strip()
                declared_status = str(package.get("declared_status") or "").strip().lower()
                dispatchability = str(((package.get("task_meta") or {}).get("dispatchability_state")) or "dispatchable").strip().lower()
                if completed_at:
                    status = "complete"
                elif declared_status == "archived":
                    status = "archived"
                elif declared_status in RAW_QUEUE_TERMINAL_STATUSES:
                    status = "complete"
                elif runtime_state in ACTIVE_WORK_PACKAGE_RUNTIME_STATES:
                    status = "awaiting_review" if runtime_state == "awaiting_review" else "running"
                elif dispatchability != "dispatchable":
                    status = "blocked"
                elif existing_status in {"failed", WAITING_CAPACITY_STATUS, "awaiting_account"}:
                    status = existing_status
                else:
                    status = "ready"
                conn.execute(
                    """
                    INSERT INTO work_packages(
                        package_id, project_id, queue_index, title, slice_name, package_kind, horizon_family, source_kind, source_ref,
                        task_meta_json, allowed_paths_json, denied_paths_json, owned_surfaces_json, dependencies_json, review_lane,
                        audit_lane, merge_owner_lane, branch_name, base_ref, worktree_root, sponsor_source, max_touched_files,
                        priority, ttl_seconds, status, runtime_state, latest_run_id, latest_pr_id, completed_at, created_at, updated_at
                    )
                    VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    ON CONFLICT(package_id) DO UPDATE SET
                        project_id=excluded.project_id,
                        queue_index=excluded.queue_index,
                        title=excluded.title,
                        slice_name=excluded.slice_name,
                        package_kind=excluded.package_kind,
                        horizon_family=excluded.horizon_family,
                        source_kind=excluded.source_kind,
                        source_ref=excluded.source_ref,
                        task_meta_json=excluded.task_meta_json,
                        allowed_paths_json=excluded.allowed_paths_json,
                        denied_paths_json=excluded.denied_paths_json,
                        owned_surfaces_json=excluded.owned_surfaces_json,
                        dependencies_json=excluded.dependencies_json,
                        review_lane=excluded.review_lane,
                        audit_lane=excluded.audit_lane,
                        merge_owner_lane=excluded.merge_owner_lane,
                        branch_name=excluded.branch_name,
                        base_ref=excluded.base_ref,
                        worktree_root=excluded.worktree_root,
                        sponsor_source=excluded.sponsor_source,
                        max_touched_files=excluded.max_touched_files,
                        priority=excluded.priority,
                        ttl_seconds=excluded.ttl_seconds,
                        status=excluded.status,
                        updated_at=excluded.updated_at
                    """,
                    (
                        package_id,
                        package["project_id"],
                        int(package.get("queue_index") or 0),
                        str(package.get("title") or ""),
                        str(package.get("slice_name") or ""),
                        str(package.get("package_kind") or "implementation"),
                        str(package.get("horizon_family") or ""),
                        str(package.get("source_kind") or "queue"),
                        str(package.get("source_ref") or ""),
                        json.dumps(dict(package.get("task_meta") or {}), sort_keys=True),
                        json.dumps(list(package.get("allowed_paths") or []), sort_keys=True),
                        json.dumps(list(package.get("denied_paths") or []), sort_keys=True),
                        json.dumps(list(package.get("owned_surfaces") or []), sort_keys=True),
                        json.dumps(list(package.get("dependencies") or []), sort_keys=True),
                        str(package.get("review_lane") or ""),
                        str(package.get("audit_lane") or ""),
                        str(package.get("merge_owner_lane") or ""),
                        str(package.get("branch_name") or ""),
                        str(package.get("base_ref") or ""),
                        str(package.get("worktree_root") or ""),
                        str(package.get("sponsor_source") or ""),
                        int(package.get("max_touched_files") or 0),
                        int(package.get("priority") or 0),
                        int(package.get("ttl_seconds") or 0),
                        status,
                        runtime_state,
                        int((existing["latest_run_id"] if existing else 0) or 0) or None,
                        int((existing["latest_pr_id"] if existing else 0) or 0) or None,
                        completed_at or None,
                        str((existing["created_at"] if existing else now_text) or now_text),
                        now_text,
                    ),
                )
                existing_claim_rows = conn.execute(
                    """
                    SELECT claim_type, claim_value, claim_state, created_at, activated_at, released_at
                    FROM scope_claims
                    WHERE package_id=?
                    """,
                    (package_id,),
                ).fetchall()
                existing_claims = {
                    (str(row["claim_type"] or "").strip(), str(row["claim_value"] or "").strip()): dict(row)
                    for row in existing_claim_rows
                }
                desired_claims = compiled_scope_claims_for_package(package)
                desired_claim_keys = {
                    (str(claim.get("claim_type") or "").strip(), str(claim.get("claim_value") or "").strip())
                    for claim in desired_claims
                }
                stale_claim_keys = [key for key in existing_claims if key not in desired_claim_keys]
                if stale_claim_keys:
                    stale_params: List[Any] = [package_id]
                    stale_clauses: List[str] = []
                    for claim_type, claim_value in stale_claim_keys:
                        stale_clauses.append("(claim_type=? AND claim_value=?)")
                        stale_params.extend([claim_type, claim_value])
                    conn.execute(
                        f"DELETE FROM scope_claims WHERE package_id=? AND ({' OR '.join(stale_clauses)})",
                        tuple(stale_params),
                    )
                runtime_claim_active = runtime_state in {"scheduled", "running", "verifying"}
                initial_claim_state = "active" if runtime_claim_active else "prepared"
                for claim in desired_claims:
                    claim_type = str(claim["claim_type"] or "").strip()
                    claim_value = str(claim["claim_value"] or "").strip()
                    existing_claim = existing_claims.get((claim_type, claim_value)) or {}
                    claim_state = (
                        "active"
                        if runtime_claim_active
                        else str(existing_claim.get("claim_state") or initial_claim_state).strip() or initial_claim_state
                    )
                    created_at = str(existing_claim.get("created_at") or now_text).strip() or now_text
                    activated_at = (
                        str(existing_claim.get("activated_at") or "").strip()
                        or (now_text if claim_state == "active" else "")
                    )
                    released_at = "" if claim_state == "active" else str(existing_claim.get("released_at") or "").strip()
                    conn.execute(
                        """
                        INSERT INTO scope_claims(package_id, project_id, claim_type, claim_value, scope_key, claim_state, created_at, activated_at, released_at)
                        VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?)
                        ON CONFLICT(package_id, claim_type, claim_value) DO UPDATE SET
                            project_id=excluded.project_id,
                            scope_key=excluded.scope_key,
                            claim_state=excluded.claim_state,
                            created_at=excluded.created_at,
                            activated_at=excluded.activated_at,
                            released_at=excluded.released_at
                        """,
                        (
                            claim["package_id"],
                            claim["project_id"],
                            claim_type,
                            claim_value,
                            claim["scope_key"],
                            claim_state,
                            created_at,
                            activated_at or None,
                            released_at or None,
                        ),
                    )
            if seen:
                placeholders = ", ".join("?" for _ in seen)
                conn.execute(
                    f"""
                    UPDATE work_packages
                    SET status='archived', updated_at=?
                    WHERE package_id NOT IN ({placeholders})
                      AND status NOT IN ('complete', 'archived')
                      AND runtime_state='idle'
                    """,
                    (now_text, *sorted(seen)),
                )
    with db() as conn:
        rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT package_id, dependencies_json, task_meta_json, status, runtime_state
                FROM work_packages
                ORDER BY project_id, queue_index, package_id
                """
            ).fetchall()
        ]
    status_by_package = {
        str(row.get("package_id") or "").strip(): str(row.get("status") or "").strip().lower()
        for row in rows
        if str(row.get("package_id") or "").strip()
    }
    status_updates: List[Tuple[str, str, str]] = []
    for row in rows:
        package_id = str(row.get("package_id") or "").strip()
        if not package_id:
            continue
        current_status = str(row.get("status") or "").strip().lower()
        runtime_state = str(row.get("runtime_state") or "").strip().lower()
        if current_status in TERMINAL_WORK_PACKAGE_STATUSES or runtime_state in ACTIVE_WORK_PACKAGE_RUNTIME_STATES:
            continue
        dependencies = [str(item).strip() for item in json_field(row.get("dependencies_json"), []) if str(item).strip()]
        task_meta = json_field(row.get("task_meta_json"), {})
        dependencies_ready = all(status_by_package.get(dep) in TERMINAL_WORK_PACKAGE_STATUSES for dep in dependencies)
        next_status = "ready" if dependencies_ready and current_status != "blocked" else "waiting_dependency"
        if str((task_meta or {}).get("dispatchability_state") or "dispatchable").strip().lower() != "dispatchable":
            next_status = "blocked"
        if next_status != current_status:
            status_updates.append((next_status, now_text, package_id))
    if status_updates:
        with db() as conn:
            conn.executemany(
                "UPDATE work_packages SET status=?, updated_at=? WHERE package_id=?",
                status_updates,
            )
    for project_cfg in config.get("projects") or []:
        project_id = str(project_cfg.get("id") or "").strip()
        if not project_id or not project_uses_package_scheduler(config, project_id):
            continue
        sync_project_progress_from_packages(project_id)


def representative_work_package_for_project(project_id: str) -> Optional[Dict[str, Any]]:
    rows = work_package_rows(project_id=project_id)
    if not rows:
        return None
    status_rank = {
        "running": 0,
        "verifying": 1,
        "scheduled": 2,
        "ready": 3,
        WAITING_CAPACITY_STATUS: 4,
        "awaiting_account": 5,
        "waiting_dependency": 6,
        "awaiting_review": 7,
        "review_requested": 8,
        "awaiting_pr": 9,
        "local_review": 10,
        "failed": 11,
        "blocked": 12,
        "complete": 13,
        "archived": 14,
    }
    return sorted(
        rows,
        key=lambda row: (
            status_rank.get(str(row.get("runtime_state") or "").strip().lower(), 99),
            status_rank.get(str(row.get("status") or "").strip().lower(), 99),
            int(row.get("queue_index") or 0),
            int(row.get("priority") or 0),
            str(row.get("package_id") or ""),
        ),
    )[0]


def sync_project_progress_from_packages(project_id: str) -> None:
    clean = str(project_id or "").strip()
    if not clean or not table_exists("work_packages") or not table_exists("projects"):
        return
    rows = work_package_rows(project_id=clean)
    if not rows:
        return
    contiguous_complete = 0
    ordered = sorted(rows, key=lambda row: (int(row.get("queue_index") or 0), int(row.get("priority") or 0), str(row.get("package_id") or "")))
    for row in ordered:
        if normalize_package_kind(row.get("package_kind")) == PACKAGE_COMPILE_PACKAGE_KIND:
            continue
        if str(row.get("status") or "").strip().lower() in TERMINAL_WORK_PACKAGE_STATUSES:
            contiguous_complete += 1
            continue
        break
    active_rows = [
        row
        for row in ordered
        if str(row.get("runtime_state") or "").strip().lower() in ACTIVE_WORK_PACKAGE_RUNTIME_STATES
    ]
    dispatchable_ready_rows = [
        row
        for row in ordered
        if str(row.get("status") or "").strip().lower() == "ready"
    ]
    waiting_capacity_rows = [
        row
        for row in ordered
        if str(row.get("status") or "").strip().lower() == WAITING_CAPACITY_STATUS
    ]
    awaiting_account_rows = [
        row
        for row in ordered
        if str(row.get("status") or "").strip().lower() == "awaiting_account"
    ]
    waiting_dependency_rows = [
        row
        for row in ordered
        if str(row.get("status") or "").strip().lower() == "waiting_dependency"
    ]
    review_rows = [
        row
        for row in ordered
        if str(row.get("status") or "").strip().lower() in {"awaiting_review", "review_requested", "awaiting_pr", "local_review"}
    ]
    blocked_rows = [row for row in ordered if str(row.get("status") or "").strip().lower() in {"blocked", "failed"}]
    rep = (
        (active_rows[0] if active_rows else None)
        or (dispatchable_ready_rows[0] if dispatchable_ready_rows else None)
        or (waiting_capacity_rows[0] if waiting_capacity_rows else None)
        or (awaiting_account_rows[0] if awaiting_account_rows else None)
        or (waiting_dependency_rows[0] if waiting_dependency_rows else None)
        or (review_rows[0] if review_rows else None)
        or (blocked_rows[0] if blocked_rows else None)
        or representative_work_package_for_project(clean)
        or {}
    )
    rep_status = str(rep.get("status") or "").strip().lower()
    rep_runtime = str(rep.get("runtime_state") or "").strip().lower()
    if rep_runtime == "verifying":
        runtime_status = "verifying"
    elif rep_runtime in {"scheduled", "running"}:
        runtime_status = "running"
    elif dispatchable_ready_rows:
        runtime_status = READY_STATUS
    elif waiting_capacity_rows:
        runtime_status = WAITING_CAPACITY_STATUS
    elif awaiting_account_rows:
        runtime_status = "awaiting_account"
    elif waiting_dependency_rows:
        runtime_status = "waiting_dependency"
    elif review_rows:
        runtime_status = rep_status or "awaiting_review"
    elif blocked_rows:
        runtime_status = "blocked"
    else:
        runtime_status = "complete"
    active_run_id = int(rep.get("latest_run_id") or 0) or None if rep_runtime in ACTIVE_WORK_PACKAGE_RUNTIME_STATES else None
    current_slice_name = str(rep.get("slice_name") or "").strip() or None
    with db() as conn:
        row = conn.execute("SELECT * FROM projects WHERE id=?", (clean,)).fetchone()
    if not row:
        return
    update_project_status(
        clean,
        status=runtime_status,
        current_slice=current_slice_name,
        active_run_id=active_run_id,
        cooldown_until=parse_iso(row["cooldown_until"]),
        last_run_at=parse_iso(row["last_run_at"]),
        last_error=row["last_error"],
        consecutive_failures=int(row["consecutive_failures"] or 0),
        spider_tier=row["spider_tier"],
        spider_model=row["spider_model"],
        spider_reason=row["spider_reason"],
    )
    with db() as conn:
        conn.execute(
            "UPDATE projects SET queue_index=?, current_slice=?, active_run_id=?, updated_at=? WHERE id=?",
            (contiguous_complete, current_slice_name, active_run_id, iso(utc_now()), clean),
        )


def active_scope_claims_for_project(project_id: str, *, exclude_package_id: str = "") -> List[Dict[str, Any]]:
    claims = scope_claim_rows(project_id=project_id, claim_states=list(SCOPE_CLAIM_ACTIVE_STATES))
    if exclude_package_id:
        claims = [claim for claim in claims if str(claim.get("package_id") or "").strip() != str(exclude_package_id or "").strip()]
    return claims


def work_package_scope_conflict(
    package: Dict[str, Any],
    *,
    reserved_claims: Optional[List[Dict[str, Any]]] = None,
) -> Optional[str]:
    project_id = str(package.get("project_id") or "").strip()
    package_id = str(package.get("package_id") or "").strip()
    desired_claims = compiled_scope_claims_for_package(package)
    active_claims = active_scope_claims_for_project(project_id, exclude_package_id=package_id)
    if reserved_claims:
        active_claims.extend(dict(item) for item in reserved_claims)
    for desired in desired_claims:
        for active in active_claims:
            if scope_claim_conflicts(
                str(desired.get("claim_type") or ""),
                str(desired.get("claim_value") or ""),
                str(active.get("claim_type") or ""),
                str(active.get("claim_value") or ""),
            ):
                return f"scope conflict with {str(active.get('package_id') or 'unknown')} on {str(active.get('claim_type') or '')}:{str(active.get('claim_value') or '')}"
    return None


def activate_work_package_scope_claims(package_id: str) -> None:
    clean = str(package_id or "").strip()
    if not clean:
        return
    now_text = iso(utc_now())
    with db() as conn:
        conn.execute(
            """
            UPDATE scope_claims
            SET claim_state='active',
                activated_at=COALESCE(activated_at, ?)
            WHERE package_id=?
            """,
            (now_text, clean),
        )


def release_work_package_scope_claims(package_id: str) -> None:
    clean = str(package_id or "").strip()
    if not clean:
        return
    now_text = iso(utc_now())
    with db() as conn:
        conn.execute(
            """
            UPDATE scope_claims
            SET claim_state='released',
                released_at=COALESCE(released_at, ?)
            WHERE package_id=?
            """,
            (now_text, clean),
        )


def update_work_package_runtime(
    package_id: str,
    *,
    status: Optional[str] = None,
    runtime_state: Optional[str] = None,
    latest_run_id: Optional[int] = None,
    latest_pr_id: Optional[int] = None,
    completed_at: Optional[dt.datetime] = None,
) -> None:
    clean = str(package_id or "").strip()
    if not clean or not table_exists("work_packages"):
        return
    updates: List[str] = ["updated_at=?"]
    params: List[Any] = [iso(utc_now())]
    if status is not None:
        updates.append("status=?")
        params.append(str(status or "").strip())
    if runtime_state is not None:
        updates.append("runtime_state=?")
        params.append(str(runtime_state or "").strip())
    if latest_run_id is not None:
        updates.append("latest_run_id=?")
        params.append(int(latest_run_id) if latest_run_id else None)
    if latest_pr_id is not None:
        updates.append("latest_pr_id=?")
        params.append(int(latest_pr_id) if latest_pr_id else None)
    if completed_at is not None:
        updates.append("completed_at=?")
        params.append(iso(completed_at))
    params.append(clean)
    with db() as conn:
        conn.execute(f"UPDATE work_packages SET {', '.join(updates)} WHERE package_id=?", tuple(params))
        row = conn.execute("SELECT project_id FROM work_packages WHERE package_id=?", (clean,)).fetchone()
    if row:
        sync_project_progress_from_packages(str(row["project_id"] or ""))


def terminal_work_package_resolution(
    run_status: str,
    *,
    current_status: str = "",
) -> Tuple[str, str]:
    clean_run_status = str(run_status or "").strip().lower()
    clean_current_status = str(current_status or "").strip().lower()
    if clean_run_status == "complete":
        return ("complete", "idle")
    if clean_run_status in {"awaiting_review", "review_requested", "awaiting_pr"}:
        return ("awaiting_review", "awaiting_review")
    if clean_run_status in {"failed", "review_failed", "blocked"}:
        return ("failed", "idle")
    if clean_run_status in {"rejected", "rate_limited"}:
        return ("awaiting_account", "idle")
    if clean_run_status in {"abandoned", "paused"}:
        return (WAITING_CAPACITY_STATUS, "idle")
    if clean_current_status in {"failed", "blocked", "awaiting_account"}:
        return (clean_current_status, "idle")
    return (WAITING_CAPACITY_STATUS, "idle")


def reconcile_stuck_work_package_runtime_links() -> int:
    if not table_exists("work_packages"):
        return 0
    with db() as conn:
        rows = conn.execute(
            """
            SELECT wp.package_id,
                   wp.status,
                   wp.runtime_state,
                   wp.latest_run_id,
                   wp.completed_at,
                   r.status AS run_status,
                   r.finished_at AS run_finished_at,
                   rt.task_state AS task_state
            FROM work_packages wp
            LEFT JOIN runs r ON r.id = wp.latest_run_id
            LEFT JOIN runtime_tasks rt ON rt.package_id = wp.package_id
            WHERE wp.runtime_state IN ('scheduled', 'running', 'verifying')
            ORDER BY wp.project_id ASC, wp.queue_index ASC, wp.priority ASC, wp.package_id ASC
            """
        ).fetchall()
    reconciled = 0
    for row in rows:
        package_id = str(row["package_id"] or "").strip()
        if not package_id:
            continue
        task_state = str(row["task_state"] or "").strip().lower()
        if task_state in ACTIVE_RUNTIME_TASK_STATES:
            continue
        run_status = str(row["run_status"] or "").strip().lower()
        if run_status in ACTIVE_RUN_STATUSES:
            continue
        package_status, runtime_state = terminal_work_package_resolution(
            run_status,
            current_status=str(row["status"] or ""),
        )
        finished_at = parse_iso(row["run_finished_at"])
        completed_at = finished_at if package_status == "complete" else None
        update_work_package_runtime(
            package_id,
            status=package_status,
            runtime_state=runtime_state,
            latest_run_id=int(row["latest_run_id"] or 0) or None,
            completed_at=completed_at,
        )
        release_work_package_scope_claims(package_id)
        reconciled += 1
    return reconciled


def ready_work_package_rows(project_id: Optional[str] = None) -> List[Dict[str, Any]]:
    rows = work_package_rows(project_id=project_id)
    return [
        row
        for row in rows
        if str(row.get("status") or "").strip().lower() in {"ready", WAITING_CAPACITY_STATUS, "awaiting_account"}
        and str(row.get("runtime_state") or "").strip().lower() == "idle"
        and work_package_dependencies_satisfied(row)
    ]


def work_package_scope_capacity(
    *,
    project_id: Optional[str] = None,
    include_active: bool = True,
) -> Dict[str, Any]:
    ready_rows = ready_work_package_rows(project_id)
    active_rows = (
        work_package_rows(project_id=project_id, runtime_states=list(ACTIVE_WORK_PACKAGE_RUNTIME_STATES))
        if include_active
        else []
    )
    selected_claims: List[Dict[str, Any]] = []
    selected_active: List[Dict[str, Any]] = []
    for package in sorted(
        active_rows,
        key=lambda row: (
            int(row.get("queue_index") or 0),
            int(row.get("priority") or 0),
            str(row.get("package_id") or ""),
        ),
    ):
        selected_active.append(package)
        selected_claims.extend(compiled_scope_claims_for_package(package))
    selected_ready: List[Dict[str, Any]] = []
    for package in sorted(
        ready_rows,
        key=lambda row: (
            int(row.get("queue_index") or 0),
            int(row.get("priority") or 0),
            str(row.get("package_id") or ""),
        ),
    ):
        if work_package_scope_conflict(package, reserved_claims=selected_claims):
            continue
        selected_ready.append(package)
        selected_claims.extend(compiled_scope_claims_for_package(package))
    return {
        "active_packages": selected_active,
        "ready_packages": selected_ready,
        "selected_package_ids": [str(row.get("package_id") or "") for row in (selected_active + selected_ready)],
        "scope_cap": len(selected_active) + len(selected_ready),
        "ready_scope_cap": len(selected_ready),
    }


def project_booster_pool_contract(config: Dict[str, Any], project_cfg: Dict[str, Any]) -> Dict[str, Any]:
    project_id = str(project_cfg.get("id") or "").strip()
    if not project_id:
        return {}
    contract = dict(project_cfg.get("booster_pool_contract") or {})
    pool_name = str(contract.get("pool") or "").strip()
    pools = dict(load_yaml(CONFIG_PATH.with_name("booster_pools.yaml")).get("booster_pools") or {})
    pool = dict(pools.get(pool_name) or {}) if pool_name else {}
    merged = dict(pool)
    merged.update(contract)
    pool_safety = dict(pool.get("safety") or {})
    contract_safety = dict(contract.get("safety") or {})
    merged_safety = dict(pool_safety)
    merged_safety.update(contract_safety)
    if merged_safety:
        merged["safety"] = merged_safety
    if "default_project_cap" not in merged and merged_safety.get("default_project_cap") not in (None, ""):
        merged["default_project_cap"] = merged_safety.get("default_project_cap")
    if "hard_project_cap" not in merged and merged_safety.get("hard_project_cap") not in (None, ""):
        merged["hard_project_cap"] = merged_safety.get("hard_project_cap")
    merged["pool"] = pool_name or str(merged.get("pool") or "")
    return merged


def contract_requires_scope_lease(config: Dict[str, Any], project_cfg: Dict[str, Any], *, target_lane: str) -> bool:
    contract = project_booster_pool_contract(config, project_cfg)
    clean_target_lane = str(target_lane or "").strip().lower()
    managed_lanes = {
        str(contract.get("worker_lane") or contract.get("booster_lane") or "").strip().lower(),
        str(contract.get("rescue_lane") or "").strip().lower(),
        str(contract.get("authority_lane") or "").strip().lower(),
    }
    if clean_target_lane not in managed_lanes:
        return False
    lease = dict(contract.get("lease") or {})
    return bool(lease.get("require_scope_lease"))


def project_runtime_concurrency_cap(config: Dict[str, Any], project_cfg: Dict[str, Any]) -> int:
    project_id = str(project_cfg.get("id") or "").strip()
    if not project_id:
        return 1
    contract = project_booster_pool_contract(config, project_cfg)
    explicit_cap = int(contract.get("project_safety_cap") or 0)
    default_cap = int(contract.get("default_project_cap") or 0)
    hard_cap = int(contract.get("hard_project_cap") or 0)
    if explicit_cap > 0:
        return min(explicit_cap, hard_cap) if hard_cap > 0 else explicit_cap
    if default_cap > 0:
        return min(default_cap, hard_cap) if hard_cap > 0 else default_cap
    return 1


def normalize_core_backends_config(raw: Any) -> Dict[str, Dict[str, Any]]:
    defaults: Dict[str, Dict[str, Any]] = {
        "ea_managed": {
            "auth_class": "ea",
            "runtime_model": "ea-coder-hard-batch",
            "provider_hint_order": ["onemin"],
            "merge_authority": False,
            "owner_category": "operator",
        },
        "chatgpt_participant": {
            "auth_class": "chatgpt_auth_json",
            "runtime_model": "gpt-5.4",
            "provider_hint_order": ["chatgpt_direct"],
            "merge_authority": False,
            "owner_category": PARTICIPANT_OWNER_CATEGORY,
        },
        "chatgpt_deep": {
            "auth_class": "chatgpt_auth_json",
            "runtime_model": "gpt-5.4",
            "provider_hint_order": ["chatgpt_direct", "chatplayground"],
            "merge_authority": False,
            "owner_category": PARTICIPANT_OWNER_CATEGORY,
        },
    }
    normalized: Dict[str, Dict[str, Any]] = {}
    raw_map = raw if isinstance(raw, dict) else {}
    for backend_name, backend_defaults in defaults.items():
        merged = dict(backend_defaults)
        override = raw_map.get(backend_name) or {}
        if isinstance(override, dict):
            merged.update(dict(override))
        merged["auth_class"] = str(merged.get("auth_class") or backend_defaults["auth_class"]).strip()
        merged["runtime_model"] = str(merged.get("runtime_model") or backend_defaults["runtime_model"]).strip()
        merged["provider_hint_order"] = [
            str(item or "").strip()
            for item in merged.get("provider_hint_order") or backend_defaults["provider_hint_order"]
            if str(item or "").strip()
        ]
        merged["merge_authority"] = bool(merged.get("merge_authority", False))
        merged["owner_category"] = str(merged.get("owner_category") or backend_defaults.get("owner_category") or "").strip()
        normalized[backend_name] = merged
    return normalized


def participant_burst_policy(project_cfg: Dict[str, Any]) -> Dict[str, Any]:
    raw = dict(project_cfg.get("participant_burst") or {})
    enabled = bool(raw.get("enabled", False))
    try:
        max_active_workers = max(0, int(raw.get("max_active_workers") or 0))
    except Exception:
        max_active_workers = 0
    credit_guard_raw = dict(raw.get("credit_guard") or {})
    role_defaults: Dict[str, Dict[str, Any]] = {
        "coding": {
            "dispatch_lane": "core",
            "backend": "chatgpt_participant",
            "min_authorization_tier": "free",
        },
        "review": {
            "dispatch_lane": "review_light",
            "backend": "chatgpt_participant",
            "min_authorization_tier": "plus",
        },
        "deep_review": {
            "dispatch_lane": "jury",
            "backend": "chatgpt_deep",
            "min_authorization_tier": "pro",
        },
    }
    normalized_roles: Dict[str, Dict[str, Any]] = {}
    for role_name, defaults in role_defaults.items():
        merged = dict(defaults)
        override = raw.get("roles", {}).get(role_name) if isinstance(raw.get("roles"), dict) else None
        if isinstance(override, dict):
            merged.update(dict(override))
        normalized_roles[role_name] = {
            "dispatch_lane": str(merged.get("dispatch_lane") or defaults["dispatch_lane"]).strip().lower() or defaults["dispatch_lane"],
            "backend": str(merged.get("backend") or defaults["backend"]).strip() or defaults["backend"],
            "min_authorization_tier": normalize_participant_authorization_tier(
                merged.get("min_authorization_tier") or defaults["min_authorization_tier"]
            ),
        }
    autoscale_raw = dict(raw.get("autoscale") or {})
    autoscale_authority = str(autoscale_raw.get("authority") or ("local" if autoscale_raw.get("enabled", False) else "disabled")).strip().lower()
    if autoscale_authority not in {"local", "capacity_plan_hint_only", "disabled"}:
        autoscale_authority = "local"
    increase_when = dict(autoscale_raw.get("increase_when") or {})
    decrease_when = dict(autoscale_raw.get("decrease_when") or {})
    modes_raw = dict(raw.get("modes") or {})
    normal_mode = dict(modes_raw.get("normal") or {})
    surge_mode = dict(modes_raw.get("surge") or {})
    return {
        "enabled": enabled,
        "max_active_workers": max_active_workers,
        "allow_chatgpt_accounts": bool(raw.get("allow_chatgpt_accounts", enabled)),
        "eligible_task_classes": [
            str(item or "").strip()
            for item in raw.get("eligible_task_classes") or []
            if str(item or "").strip()
        ],
        "landing_lane": str(raw.get("landing_lane") or "jury").strip().lower() or "jury",
        "require_jury_before_land": bool(raw.get("require_jury_before_land", True)),
        "preferred_models": [
            str(item or "").strip()
            for item in raw.get("preferred_models") or ["gpt-5.4", "gpt-5.3-codex"]
            if str(item or "").strip()
        ],
        "credit_guard": {
            "enabled": bool(credit_guard_raw.get("enabled", False)),
            "provider": str(credit_guard_raw.get("provider") or "onemin").strip().lower() or "onemin",
            "require_survive_until_next_topup": bool(credit_guard_raw.get("require_survive_until_next_topup", True)),
            "minimum_headroom_hours": max(0.0, float_or_none(credit_guard_raw.get("minimum_headroom_hours")) or 0.0),
        },
        "roles": normalized_roles,
        "autoscale": {
            "enabled": bool(autoscale_raw.get("enabled", False)),
            "authority": autoscale_authority,
            "min_active_workers": max(0, int(autoscale_raw.get("min_active_workers") or 0)),
            "max_active_workers": max(max_active_workers, int(autoscale_raw.get("max_active_workers") or max_active_workers)),
            "increase_when": {
                "sponsor_ready_lanes_gte": max(0, int(increase_when.get("sponsor_ready_lanes_gte") or 0)),
                "jury_oldest_wait_seconds_lt": max(0, int(increase_when.get("jury_oldest_wait_seconds_lt") or 0)),
                "premium_queue_depth_gte": max(0, int(increase_when.get("premium_queue_depth_gte") or 0)),
            },
            "decrease_when": {
                "jury_oldest_wait_seconds_gt": max(0, int(decrease_when.get("jury_oldest_wait_seconds_gt") or 0)),
                "jury_queue_depth_gt": max(0, int(decrease_when.get("jury_queue_depth_gt") or 0)),
                "premium_queue_depth_eq": max(0, int(decrease_when.get("premium_queue_depth_eq") or 0)),
            },
        },
        "modes": {
            "normal": {
                "premium_first": bool(normal_mode.get("premium_first", False)),
                "eligible_task_classes": [
                    str(item or "").strip()
                    for item in normal_mode.get("eligible_task_classes") or []
                    if str(item or "").strip()
                ],
            },
            "surge": {
                "premium_first": bool(surge_mode.get("premium_first", False)),
                "eligible_task_classes": [
                    str(item or "").strip()
                    for item in surge_mode.get("eligible_task_classes") or []
                    if str(item or "").strip()
                ],
            },
        },
    }


def participant_lanes_root() -> pathlib.Path:
    path = CODEX_HOME_ROOT / "participants"
    path.mkdir(parents=True, exist_ok=True)
    return path


def participant_lane_home(lane_id: str) -> pathlib.Path:
    clean = str(lane_id or "").strip()
    return participant_lanes_root() / clean


def participant_lane_status_path(lane_id: str) -> pathlib.Path:
    return participant_lane_home(lane_id) / "device-auth-status.json"


def participant_lane_auth_path(lane_id: str) -> pathlib.Path:
    return participant_lane_home(lane_id) / "auth.json"


def participant_lane_account_alias(lane_id: str) -> str:
    clean = re.sub(r"[^a-z0-9-]+", "", str(lane_id or "").strip().lower())
    if not clean:
        clean = uuid.uuid4().hex[:10]
    return f"{PARTICIPANT_ACCOUNT_PREFIX}{clean[:24]}"


def normalize_participant_lane_role(value: Any) -> str:
    clean = str(value or "").strip().lower()
    if clean in {"review", "participant_review"}:
        return "review"
    if clean in {"deep_review", "participant_jury_deep", "jury_deep"}:
        return "deep_review"
    return "coding"


def participant_tier_priority(value: Any) -> int:
    normalized = normalize_participant_authorization_tier(value)
    if normalized == "enterprise":
        return 6
    if normalized == "business":
        return 5
    if normalized == "edu":
        return 4
    if normalized == "pro":
        return 3
    if normalized == "plus":
        return 2
    if normalized == "go":
        return 1
    if normalized == "free":
        return 0
    return -1


def participant_role_policy(policy: Dict[str, Any], role: Any) -> Dict[str, Any]:
    normalized_role = normalize_participant_lane_role(role)
    roles = dict(policy.get("roles") or {})
    role_policy = dict(roles.get(normalized_role) or {})
    if not role_policy:
        if normalized_role == "review":
            role_policy = {
                "dispatch_lane": "review_light",
                "backend": "chatgpt_participant",
                "min_authorization_tier": "plus",
            }
        elif normalized_role == "deep_review":
            role_policy = {
                "dispatch_lane": "jury",
                "backend": "chatgpt_deep",
                "min_authorization_tier": "pro",
            }
        else:
            role_policy = {
                "dispatch_lane": "core",
                "backend": "chatgpt_participant",
                "min_authorization_tier": "free",
            }
    role_policy["role"] = normalized_role
    role_policy["dispatch_lane"] = str(role_policy.get("dispatch_lane") or "core").strip().lower() or "core"
    role_policy["backend"] = str(role_policy.get("backend") or "chatgpt_participant").strip() or "chatgpt_participant"
    role_policy["min_authorization_tier"] = normalize_participant_authorization_tier(role_policy.get("min_authorization_tier"))
    return role_policy


def participant_lane_dispatch_lane(role: Any, policy: Optional[Dict[str, Any]] = None) -> str:
    role_policy = participant_role_policy(policy or {}, role)
    return str(role_policy.get("dispatch_lane") or "core").strip().lower() or "core"


def participant_lane_backend_key(role: Any, policy: Optional[Dict[str, Any]] = None) -> str:
    role_policy = participant_role_policy(policy or {}, role)
    return str(role_policy.get("backend") or "chatgpt_participant").strip() or "chatgpt_participant"


def participant_lane_role_allowed(role: Any, authorization_tier: Any, policy: Dict[str, Any]) -> bool:
    role_policy = participant_role_policy(policy, role)
    minimum = str(role_policy.get("min_authorization_tier") or "free").strip()
    if minimum == "unknown":
        minimum = "free"
    if normalize_participant_lane_role(role) == "coding" and normalize_participant_authorization_tier(authorization_tier) == "unknown":
        return True
    return participant_tier_priority(authorization_tier) >= participant_tier_priority(minimum)


def participant_lane_rows(
    *,
    project_id: Optional[str] = None,
    statuses: Optional[Sequence[str]] = None,
    refresh: bool = False,
) -> List[Dict[str, Any]]:
    if not table_exists("participant_lanes"):
        return []
    clauses: List[str] = []
    params: List[Any] = []
    if project_id:
        clauses.append("project_id=?")
        params.append(str(project_id).strip())
    if statuses:
        clean_statuses = [str(item or "").strip() for item in statuses if str(item or "").strip()]
        if clean_statuses:
            placeholders = ",".join("?" for _ in clean_statuses)
            clauses.append(f"status IN ({placeholders})")
            params.extend(clean_statuses)
    query = "SELECT * FROM participant_lanes"
    if clauses:
        query += " WHERE " + " AND ".join(clauses)
    query += " ORDER BY created_at DESC, lane_id"
    with db() as conn:
        rows = [dict(row) for row in conn.execute(query, tuple(params)).fetchall()]
    items = [hydrate_participant_lane_row(row, refresh=refresh) for row in rows]
    return items


def participant_lane_row(lane_id: str, *, refresh: bool = False) -> Optional[Dict[str, Any]]:
    clean = str(lane_id or "").strip()
    if not clean or not table_exists("participant_lanes"):
        return None
    with db() as conn:
        row = conn.execute("SELECT * FROM participant_lanes WHERE lane_id=?", (clean,)).fetchone()
    if not row:
        return None
    return hydrate_participant_lane_row(dict(row), refresh=refresh)


def participant_lane_row_for_alias(account_alias: str, *, refresh: bool = False) -> Optional[Dict[str, Any]]:
    clean = str(account_alias or "").strip()
    if not clean or not table_exists("participant_lanes"):
        return None
    with db() as conn:
        row = conn.execute("SELECT * FROM participant_lanes WHERE account_alias=?", (clean,)).fetchone()
    if not row:
        return None
    return hydrate_participant_lane_row(dict(row), refresh=refresh)


def participant_lane_event_rows(lane_id: str, *, limit: int = 100) -> List[Dict[str, Any]]:
    clean = str(lane_id or "").strip()
    if not clean or not table_exists("participant_lane_events"):
        return []
    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, lane_id, event_kind, message, payload_json, created_at
            FROM participant_lane_events
            WHERE lane_id=?
            ORDER BY id DESC
            LIMIT ?
            """,
            (clean, max(1, int(limit))),
        ).fetchall()
    items: List[Dict[str, Any]] = []
    for row in rows:
        item = dict(row)
        item["payload"] = json_field(item.pop("payload_json"), {})
        items.append(item)
    items.reverse()
    return items


def record_participant_lane_event(lane_id: str, event_kind: str, message: str, *, payload: Optional[Dict[str, Any]] = None) -> None:
    clean_lane = str(lane_id or "").strip()
    clean_kind = str(event_kind or "").strip()
    if not clean_lane or not clean_kind or not table_exists("participant_lane_events"):
        return
    with db() as conn:
        conn.execute(
            """
            INSERT INTO participant_lane_events(lane_id, event_kind, message, payload_json, created_at)
            VALUES(?, ?, ?, ?, ?)
            """,
            (
                clean_lane,
                clean_kind,
                str(message or "").strip(),
                json.dumps(dict(payload or {}), sort_keys=True),
                iso(utc_now()),
            ),
        )


def participant_lane_status_payload(status_path: pathlib.Path) -> Dict[str, Any]:
    if not status_path.exists():
        return {}
    try:
        payload = json.loads(status_path.read_text(encoding="utf-8") or "{}")
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def sync_participant_lane_account(conn: sqlite3.Connection, lane_row: Dict[str, Any], account_cfg: Dict[str, Any]) -> None:
    alias = str(lane_row.get("account_alias") or "").strip()
    if not alias:
        return
    allowed_models = normalize_allowed_models_for_account(
        str(account_cfg.get("auth_kind") or "chatgpt_auth_json"),
        account_cfg.get("allowed_models") or [],
    )
    status = str(lane_row.get("status") or "").strip()
    health_state = "ready" if status == PARTICIPANT_LANE_ACTIVE else "auth_stale" if status == PARTICIPANT_LANE_PENDING_AUTH else "disabled"
    conn.execute(
        """
        INSERT INTO accounts(alias, auth_kind, api_key_file, api_key_env, auth_json_file, allowed_models_json, daily_budget_usd, monthly_budget_usd, max_parallel_runs, health_state, updated_at)
        VALUES(?, ?, '', '', ?, ?, NULL, NULL, ?, ?, ?)
        ON CONFLICT(alias) DO UPDATE SET
            auth_kind=excluded.auth_kind,
            auth_json_file=excluded.auth_json_file,
            allowed_models_json=excluded.allowed_models_json,
            max_parallel_runs=excluded.max_parallel_runs,
            health_state=CASE
                WHEN excluded.health_state IN ('disabled', 'draining', 'exhausted') THEN excluded.health_state
                WHEN accounts.health_state='auth_stale' THEN accounts.health_state
                ELSE excluded.health_state
            END,
            updated_at=excluded.updated_at
        """,
        (
            alias,
            str(account_cfg.get("auth_kind") or "chatgpt_auth_json"),
            str(account_cfg.get("auth_json_file") or ""),
            json.dumps(allowed_models),
            int(account_cfg.get("max_parallel_runs") or 1),
            health_state,
            iso(utc_now()),
        ),
    )


def participant_lane_account_config(lane_row: Dict[str, Any], core_backends: Dict[str, Dict[str, Any]]) -> Dict[str, Any]:
    backend_key = str(lane_row.get("backend_key") or "chatgpt_participant").strip()
    backend_cfg = dict(core_backends.get(backend_key) or core_backends.get("chatgpt_participant") or {})
    lane_role = normalize_participant_lane_role(lane_row.get("lane_role"))
    allowed_models = [
        str(item or "").strip()
        for item in (
            lane_row.get("allowed_models")
            if isinstance(lane_row.get("allowed_models"), list)
            else (json_field(lane_row.get("allowed_models_json"), []) or [])
        )
        if str(item or "").strip()
    ]
    if not allowed_models:
        allowed_models = [
            str(item or "").strip()
            for item in backend_cfg.get("allowed_models") or [backend_cfg.get("runtime_model"), "gpt-5.3-codex"]
            if str(item or "").strip()
        ]
    lane_home = str(lane_row.get("lane_home") or "").strip()
    subject_label = str(lane_row.get("subject_label") or lane_row.get("subject_id") or lane_row.get("account_alias") or "").strip()
    return {
        "auth_kind": str(backend_cfg.get("auth_class") or "chatgpt_auth_json").strip(),
        "auth_json_file": str(lane_row.get("auth_json_file") or "").strip(),
        "allowed_models": allowed_models,
        "spark_enabled": False,
        "health_state": "ready" if str(lane_row.get("status") or "") == PARTICIPANT_LANE_ACTIVE else "auth_stale",
        "max_parallel_runs": 1,
        "lane": participant_lane_dispatch_lane(lane_role),
        "backend": backend_key,
        "bridge_name": subject_label or str(lane_row.get("account_alias") or "").strip(),
        "bridge_identity": subject_label or str(lane_row.get("subject_id") or "").strip(),
        "owner_category": str(lane_row.get("owner_category") or PARTICIPANT_OWNER_CATEGORY).strip(),
        "account_class": PARTICIPANT_FUNDED_ACCOUNT_CLASS,
        "funding_class": PARTICIPANT_FUNDED_ACCOUNT_CLASS,
        "drain_policy": "first",
        "eligible_pools": ["participant_burst"],
        "explicit_consent": True,
        "token_pool_state": "valid" if str(lane_row.get("status") or "").strip() == PARTICIPANT_LANE_ACTIVE else "invalid",
        "participant_lane_id": str(lane_row.get("lane_id") or "").strip(),
        "participant_subject_id": str(lane_row.get("subject_id") or "").strip(),
        "participant_project_id": str(lane_row.get("project_id") or "").strip(),
        "participant_hub_user_id": str(lane_row.get("hub_user_id") or "").strip(),
        "participant_hub_group_id": str(lane_row.get("hub_group_id") or "").strip(),
        "participant_sponsor_session_id": str(lane_row.get("sponsor_session_id") or "").strip(),
        "participant_lane_role": lane_role,
        "participant_burst_lane": True,
        "codex_home": lane_home,
        "home_dir": lane_home,
    }


def hydrate_participant_lane_row(row: Dict[str, Any], *, refresh: bool = False) -> Dict[str, Any]:
    item = dict(row)
    item["allowed_models"] = [
        str(entry or "").strip()
        for entry in json_field(item.pop("allowed_models_json", "[]"), []) or []
        if str(entry or "").strip()
    ]
    item["telemetry"] = json_field(item.pop("telemetry_json", "{}"), {})
    status_payload = participant_lane_status_payload(pathlib.Path(str(item.get("device_auth_status_path") or "").strip()))
    if refresh and status_payload:
        sync_participant_lane_runtime(str(item.get("lane_id") or "").strip(), status_payload=status_payload)
        refreshed = participant_lane_row(str(item.get("lane_id") or "").strip(), refresh=False)
        if refreshed is not None:
            item = refreshed
            status_payload = participant_lane_status_payload(pathlib.Path(str(item.get("device_auth_status_path") or "").strip()))
    item["device_auth"] = status_payload
    telemetry = dict(item.get("telemetry") or {})
    item["lane_role"] = normalize_participant_lane_role(item.get("lane_role") or telemetry.get("lane_role"))
    item["authorization_tier"] = normalize_participant_authorization_tier(telemetry.get("authorization_tier"))
    item["tier_source"] = normalize_participant_tier_source(telemetry.get("tier_source"))
    item["events"] = participant_lane_event_rows(str(item.get("lane_id") or "").strip(), limit=40)
    return item


def sync_participant_lane_runtime(lane_id: str, *, status_payload: Optional[Dict[str, Any]] = None) -> None:
    clean = str(lane_id or "").strip()
    if not clean or not table_exists("participant_lanes"):
        return
    with db() as conn:
        row = conn.execute("SELECT * FROM participant_lanes WHERE lane_id=?", (clean,)).fetchone()
    if not row:
        return
    lane_row = dict(row)
    payload = status_payload if isinstance(status_payload, dict) else participant_lane_status_payload(pathlib.Path(str(lane_row.get("device_auth_status_path") or "").strip()))
    if not payload:
        return
    helper_pid = payload.get("pid")
    auth_ready = bool(payload.get("auth_ready")) or participant_lane_auth_path(clean).exists()
    status = str(lane_row.get("status") or "").strip()
    next_status = status if status in PARTICIPANT_LANE_STATUS_VALUES else PARTICIPANT_LANE_PENDING_AUTH
    last_error = str(payload.get("last_error") or "").strip() or None
    verification_uri = str(payload.get("verification_uri") or "").strip()
    user_code = str(payload.get("user_code") or "").strip()
    telemetry = dict(json_field(lane_row.get("telemetry_json"), {}) or {})
    if verification_uri:
        telemetry["verification_uri"] = verification_uri
    if user_code:
        telemetry["user_code"] = user_code
    if auth_ready:
        telemetry["auth_ready"] = True
    detected_tier = normalize_participant_authorization_tier(payload.get("authorization_tier") or telemetry.get("authorization_tier"))
    detected_tier_source = normalize_participant_tier_source(payload.get("tier_source") or telemetry.get("tier_source"))
    if detected_tier != "unknown":
        telemetry["authorization_tier"] = detected_tier
    if detected_tier_source != "unknown":
        telemetry["tier_source"] = detected_tier_source
    now = utc_now()
    with db() as conn:
        conn.execute(
            """
            UPDATE participant_lanes
            SET status=?,
                helper_pid=?,
                last_heartbeat_at=?,
                auth_completed_at=CASE WHEN ? THEN COALESCE(auth_completed_at, ?) ELSE auth_completed_at END,
                telemetry_json=?,
                last_error=?,
                updated_at=?
            WHERE lane_id=?
            """,
            (
                next_status,
                int(helper_pid) if helper_pid else None,
                str(payload.get("updated_at") or iso(now)),
                1 if auth_ready else 0,
                iso(now),
                json.dumps(telemetry, sort_keys=True),
                last_error,
                iso(now),
                clean,
            ),
        )


def active_participant_lane_count(project_id: str) -> int:
    return len(participant_lane_rows(project_id=project_id, statuses=[PARTICIPANT_LANE_ACTIVE], refresh=True))


def participant_lane_aliases_for_project(project_id: str, *, statuses: Optional[Sequence[str]] = None) -> List[str]:
    aliases: List[str] = []
    for lane_row in participant_lane_rows(project_id=project_id, statuses=statuses or [PARTICIPANT_LANE_ACTIVE], refresh=True):
        alias = str(lane_row.get("account_alias") or "").strip()
        if alias and alias not in aliases:
            aliases.append(alias)
    return aliases


def participant_receipt_target_urls() -> List[str]:
    targets: List[str] = []
    for value in (HUB_LEDGER_RECEIPT_URL, HUB_AI_RECEIPT_URL):
        clean = str(value or "").strip()
        if clean and clean not in targets:
            targets.append(clean)
    return targets


def participant_receipt_signature(payload: Dict[str, Any]) -> str:
    serialized = json.dumps(dict(payload or {}), ensure_ascii=True, sort_keys=True, separators=(",", ":")).encode("utf-8")
    if FLEET_RECEIPT_SIGNING_SECRET:
        digest = hmac.new(FLEET_RECEIPT_SIGNING_SECRET.encode("utf-8"), serialized, hashlib.sha256).hexdigest()
        return f"hmac-sha256:{digest}"
    return f"sha256:{hashlib.sha256(serialized).hexdigest()}"


def participant_receipt_id(*parts: object) -> str:
    material = "|".join(str(part or "").strip() for part in parts if str(part or "").strip())
    digest = hashlib.sha256(material.encode("utf-8")).hexdigest()[:24]
    return f"rcpt-{digest}"


def queue_recovery_dir() -> pathlib.Path:
    configured = str(os.environ.get("FLEET_QUEUE_RECOVERY_DIR") or "").strip()
    if configured:
        return pathlib.Path(configured)
    queue_root = pathlib.Path(QUEUE_RECOVERY_DIR)
    default_root = pathlib.Path("/var/lib/codex-fleet/queue-recovery")
    if queue_root == default_root and DB_PATH.parent != default_root.parent:
        return DB_PATH.parent / "queue-recovery"
    return queue_root


def queue_recovery_receipt_id(*parts: object) -> str:
    material = "|".join(str(part or "").strip() for part in parts if str(part or "").strip())
    digest = hashlib.sha256(material.encode("utf-8")).hexdigest()[:24]
    return f"queue-recovery-{digest}"


def queue_recovery_receipt_signature(payload: Dict[str, Any]) -> str:
    return participant_receipt_signature(payload)


def write_queue_recovery_receipt(payload: Dict[str, Any]) -> Dict[str, Any]:
    receipt = dict(payload or {})
    generated_at = str(receipt.get("generated_at") or iso(utc_now()) or "").strip()
    project_id = str(receipt.get("project_id") or "unknown").strip() or "unknown"
    receipt_id = str(receipt.get("receipt_id") or "").strip()
    if not receipt_id:
        receipt_id = queue_recovery_receipt_id(
            project_id,
            receipt.get("trigger"),
            receipt.get("run_id"),
            generated_at,
            receipt.get("current_slice"),
        )
    receipt["contract_name"] = "fleet.queue_recovery_receipt"
    receipt["schema_version"] = 1
    receipt["generated_at"] = generated_at
    receipt["receipt_id"] = receipt_id
    receipt["signed_by_fleet"] = queue_recovery_receipt_signature(receipt)
    target_dir = queue_recovery_dir() / project_id
    target_dir.mkdir(parents=True, exist_ok=True)
    target = target_dir / f"{receipt_id}.generated.json"
    target.write_text(json.dumps(receipt, indent=2, sort_keys=True), encoding="utf-8")
    receipt["receipt_path"] = str(target)
    return receipt


def record_project_auto_requeue(
    project_id: str,
    *,
    trigger: str,
    reason: str,
    current_slice: Optional[str],
    run_id: Optional[int],
    queue_index: Optional[int],
    runtime_task_id: Optional[int] = None,
    package_id: Optional[str] = None,
    previous_status: Optional[str] = None,
    next_status: Optional[str] = None,
    evidence: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    payload = {
        "project_id": str(project_id or "").strip(),
        "trigger": str(trigger or "").strip(),
        "reason": str(reason or "").strip(),
        "current_slice": str(current_slice or "").strip(),
        "run_id": int(run_id or 0) or None,
        "queue_index": int(queue_index or 0) if queue_index is not None else None,
        "runtime_task_id": int(runtime_task_id or 0) or None,
        "package_id": str(package_id or "").strip(),
        "previous_status": str(previous_status or "").strip(),
        "next_status": str(next_status or "").strip(),
        "evidence": dict(evidence or {}),
    }
    receipt = write_queue_recovery_receipt(payload)
    with db() as conn:
        conn.execute(
            """
            UPDATE projects
            SET last_auto_requeue_at=?,
                last_auto_requeue_reason=?,
                last_auto_requeue_trigger=?,
                last_auto_requeue_receipt_id=?,
                last_auto_requeue_receipt_path=?,
                updated_at=?
            WHERE id=?
            """,
            (
                receipt.get("generated_at"),
                receipt.get("reason"),
                receipt.get("trigger"),
                receipt.get("receipt_id"),
                receipt.get("receipt_path"),
                iso(utc_now()),
                project_id,
            ),
        )
    return receipt


def mark_participant_lane_receipt_status(
    lane_id: str,
    *,
    status: str,
    error: str = "",
    receipt_id: str = "",
    event_kind: str = "",
) -> None:
    clean_lane = str(lane_id or "").strip()
    if not clean_lane or not table_exists("participant_lanes"):
        return
    with db() as conn:
        row = conn.execute("SELECT telemetry_json FROM participant_lanes WHERE lane_id=?", (clean_lane,)).fetchone()
        telemetry = json_field(str(row["telemetry_json"] or "{}"), {}) if row else {}
        receipts = dict(telemetry.get("receipts") or {})
        receipts.update(
            {
                "last_status": str(status or "").strip(),
                "last_error": str(error or "").strip(),
                "last_receipt_id": str(receipt_id or "").strip(),
                "last_event_kind": str(event_kind or "").strip(),
                "updated_at": iso(utc_now()),
            }
        )
        telemetry["receipts"] = receipts
        conn.execute(
            """
            UPDATE participant_lanes
            SET reward_receipt_status=?,
                reward_receipt_error=?,
                telemetry_json=?,
                updated_at=?
            WHERE lane_id=?
            """,
            (
                str(status or "").strip(),
                str(error or "").strip(),
                json.dumps(telemetry, sort_keys=True),
                iso(utc_now()),
                clean_lane,
            ),
        )


def participant_receipt_post(url: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    clean_url = str(url or "").strip()
    if not clean_url:
        raise ValueError("receipt url is required")
    data = json.dumps(payload, ensure_ascii=True, sort_keys=True).encode("utf-8")
    request = urllib.request.Request(
        clean_url,
        data=data,
        headers={
            "Content-Type": "application/json",
            "User-Agent": "codex-fleet-controller",
            "X-Fleet-Receipt-Signature": str(payload.get("signed_by_fleet") or ""),
        },
        method="POST",
    )
    with urllib.request.urlopen(request, timeout=20) as response:
        raw = response.read().decode("utf-8", errors="replace")
    if not raw.strip():
        return {}
    try:
        loaded = json.loads(raw)
    except Exception:
        return {"raw": raw}
    return loaded if isinstance(loaded, dict) else {"data": loaded}


def build_participant_contribution_receipt(
    lane_row: Dict[str, Any],
    *,
    event_kind: str,
    project_id: str,
    slice_id: str = "",
    workflow_kind: str = "",
    review_rounds_used: int = 0,
    accepted_on_round: str = "",
    landed_sha: str = "",
    landed_at: Optional[str] = None,
    verified: bool = False,
    cheap_loop_only: bool = False,
    paid_lane_used: bool = True,
    groundwork_ms: int = 0,
    review_ms: int = 0,
    jury_ms: int = 0,
    core_ms: int = 0,
    files_touched: int = 0,
    diff_size: int = 0,
    issue_fingerprints: Optional[Sequence[str]] = None,
    consumption_trace: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    clean_event = str(event_kind or "").strip() or "lane_event"
    lane_id = str(lane_row.get("lane_id") or "").strip()
    ended_at_value = str(landed_at or lane_row.get("stopped_at") or lane_row.get("revoked_at") or "").strip()
    started_at_value = str(lane_row.get("activated_at") or lane_row.get("auth_completed_at") or lane_row.get("created_at") or "").strip()
    telemetry = dict(lane_row.get("telemetry") or json_field(lane_row.get("telemetry_json"), {}) or {})
    authorization_tier = normalize_participant_authorization_tier(
        lane_row.get("authorization_tier")
        or telemetry.get("authorization_tier")
    )
    tier_source = normalize_participant_tier_source(
        lane_row.get("tier_source")
        or telemetry.get("tier_source")
    )
    lane_role = normalize_participant_lane_role(
        lane_row.get("lane_role")
        or telemetry.get("lane_role")
    )
    consent_trace = {
        "consented_at_utc": str(lane_row.get("consented_at") or "").strip() or None,
        "auth_completed_at_utc": str(lane_row.get("auth_completed_at") or "").strip() or None,
        "authorization_tier": authorization_tier,
        "tier_source": tier_source or None,
        "public_contribution_visibility": str(lane_row.get("public_contribution_visibility") or "").strip() or None,
    }
    sponsor_billing_attribution = {
        "user_id": str(lane_row.get("hub_user_id") or "").strip() or None,
        "group_id": str(lane_row.get("hub_group_id") or "").strip() or None,
        "boost_campaign_id": str(lane_row.get("boost_campaign_id") or "").strip() or None,
        "sponsor_session_id": str(lane_row.get("sponsor_session_id") or "").strip() or None,
    }
    receipt = {
        "receipt_id": participant_receipt_id(
            lane_id,
            clean_event,
            str(slice_id or "").strip() or str(lane_row.get("current_slice") or "").strip(),
            str(landed_sha or "").strip(),
            ended_at_value or started_at_value,
        ),
        "event_kind": clean_event,
        "lane_id": lane_id,
        "project_id": str(project_id or lane_row.get("project_id") or "").strip(),
        "user_id": str(lane_row.get("hub_user_id") or "").strip() or None,
        "group_id": str(lane_row.get("hub_group_id") or "").strip() or None,
        "sponsor_session_id": str(lane_row.get("sponsor_session_id") or "").strip() or None,
        "auth_class": "chatgpt_auth_json",
        "lane_type": "participant_burst",
        "lane_role": lane_role,
        "started_at_utc": started_at_value or None,
        "ended_at_utc": ended_at_value or None,
        "slice_id": str(slice_id or "").strip() or None,
        "workflow_kind": str(workflow_kind or "").strip() or None,
        "review_rounds_used": max(0, int(review_rounds_used or 0)),
        "accepted_on_round": str(accepted_on_round or "").strip() or None,
        "landed_sha": str(landed_sha or "").strip() or None,
        "landed_at_utc": str(landed_at or "").strip() or None,
        "consent_trace": consent_trace,
        "sponsor_billing_attribution": sponsor_billing_attribution,
        "verified": bool(verified),
        "cheap_loop_only": bool(cheap_loop_only),
        "paid_lane_used": bool(paid_lane_used),
        "groundwork_ms": max(0, int(groundwork_ms or 0)),
        "review_ms": max(0, int(review_ms or 0)),
        "jury_ms": max(0, int(jury_ms or 0)),
        "core_ms": max(0, int(core_ms or 0)),
        "files_touched": max(0, int(files_touched or 0)),
        "diff_size": max(0, int(diff_size or 0)),
        "issue_fingerprints": [str(item or "").strip() for item in (issue_fingerprints or []) if str(item or "").strip()],
        "credit_burn_estimate": 0,
        "authorization_tier_at_receipt": authorization_tier,
        "tier_source": tier_source or None,
        "consumption_trace": dict(consumption_trace or {}),
    }
    receipt["signed_by_fleet"] = participant_receipt_signature(receipt)
    return receipt


def emit_participant_receipt(
    lane_row: Dict[str, Any],
    *,
    event_kind: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    lane_id = str(lane_row.get("lane_id") or "").strip()
    receipt_id = str(payload.get("receipt_id") or "").strip()
    urls = participant_receipt_target_urls()
    if not urls:
        mark_participant_lane_receipt_status(
            lane_id,
            status="not_configured",
            error="no receipt targets configured",
            receipt_id=receipt_id,
            event_kind=event_kind,
        )
        return {"status": "not_configured", "targets": []}
    delivered: List[str] = []
    errors: List[str] = []
    for url in urls:
        try:
            participant_receipt_post(url, payload)
            delivered.append(url)
        except Exception as exc:
            errors.append(f"{url}: {str(exc).strip() or exc.__class__.__name__}")
    if delivered and not errors:
        mark_participant_lane_receipt_status(lane_id, status=f"sent:{event_kind}", receipt_id=receipt_id, event_kind=event_kind)
    elif delivered:
        mark_participant_lane_receipt_status(
            lane_id,
            status=f"partial:{event_kind}",
            error=" ; ".join(errors),
            receipt_id=receipt_id,
            event_kind=event_kind,
        )
    else:
        mark_participant_lane_receipt_status(
            lane_id,
            status=f"failed:{event_kind}",
            error=" ; ".join(errors) or "receipt delivery failed",
            receipt_id=receipt_id,
            event_kind=event_kind,
        )
    return {"status": "ok" if delivered and not errors else "partial" if delivered else "failed", "targets": delivered, "errors": errors}


def emit_participant_lane_event_receipt(
    lane_row: Dict[str, Any],
    *,
    event_kind: str,
    landed_at: Optional[str] = None,
) -> None:
    payload = build_participant_contribution_receipt(
        lane_row,
        event_kind=event_kind,
        project_id=str(lane_row.get("project_id") or "").strip(),
        landed_at=landed_at,
        paid_lane_used=True,
    )
    result = emit_participant_receipt(lane_row, event_kind=event_kind, payload=payload)
    record_participant_lane_event(
        str(lane_row.get("lane_id") or "").strip(),
        f"receipt_{event_kind}",
        f"receipt {result.get('status') or 'unknown'} for {event_kind}",
        payload={"receipt_id": payload.get("receipt_id"), "targets": result.get("targets") or [], "errors": result.get("errors") or []},
    )


def emit_participant_slice_landed_receipts(
    project_cfg: Dict[str, Any],
    *,
    telemetry_payload: Dict[str, Any],
) -> None:
    project_id = str(project_cfg.get("id") or "").strip()
    aliases = [
        str(item or "").strip()
        for item in telemetry_payload.get("implementation_workers_used") or []
        if str(item or "").strip()
    ]
    if not aliases:
        return
    timing = dict(telemetry_payload.get("timing_ms") or {})
    issue_fingerprints = list(telemetry_payload.get("issue_fingerprints") or [])
    review_rounds = int(telemetry_payload.get("review_rounds_used") or 0)
    cheap_loop_only = not bool(telemetry_payload.get("needs_core_rescue")) and int((telemetry_payload.get("usage_estimates") or {}).get("core_runs") or 0) <= 0
    paid_lane_used = True
    allowance_burn_by_lane = dict(telemetry_payload.get("allowance_burn_by_lane") or {})
    participant_run_count = len(aliases)
    managed_run_count = max(
        0,
        int((telemetry_payload.get("usage_estimates") or {}).get("groundwork_runs") or 0)
        + int((telemetry_payload.get("usage_estimates") or {}).get("jury_reviews") or 0)
        + int((telemetry_payload.get("usage_estimates") or {}).get("core_runs") or 0)
        - participant_run_count,
    )
    estimated_cost_usd = round(
        sum(float(dict(item or {}).get("estimated_cost_usd") or 0.0) for item in allowance_burn_by_lane.values() if isinstance(item, dict)),
        6,
    )
    for alias in aliases:
        lane_row = participant_lane_row_for_alias(alias, refresh=True)
        if lane_row is None:
            continue
        payload = build_participant_contribution_receipt(
            lane_row,
            event_kind="slice_landed",
            project_id=project_id,
            slice_id=str(telemetry_payload.get("slice_id") or "").strip(),
            workflow_kind=str(telemetry_payload.get("workflow_kind") or "").strip(),
            review_rounds_used=review_rounds,
            accepted_on_round=str(telemetry_payload.get("accepted_on_round") or "").strip(),
            landed_sha=str(telemetry_payload.get("landed_sha") or "").strip(),
            landed_at=str(telemetry_payload.get("landed_at") or "").strip(),
            verified=bool(telemetry_payload.get("verify_passed")),
            cheap_loop_only=cheap_loop_only,
            paid_lane_used=paid_lane_used,
            groundwork_ms=int(timing.get("groundwork_total") or 0),
            review_ms=int(timing.get("review_total") or 0),
            jury_ms=int(timing.get("jury_total") or 0),
            core_ms=int(timing.get("core_total") or 0),
            files_touched=int(telemetry_payload.get("files_touched") or 0),
            diff_size=max(0, int(telemetry_payload.get("diff_added") or 0)) + max(0, int(telemetry_payload.get("diff_removed") or 0)),
            issue_fingerprints=issue_fingerprints,
            consumption_trace={
                "estimated_cost_usd": estimated_cost_usd,
                "allowance_burn_by_lane": allowance_burn_by_lane,
                "participant_run_count": participant_run_count,
                "managed_run_count": managed_run_count,
                "participant_worker_aliases": aliases,
            },
        )
        result = emit_participant_receipt(lane_row, event_kind="slice_landed", payload=payload)
        record_participant_lane_event(
            str(lane_row.get("lane_id") or "").strip(),
            "receipt_slice_landed",
            f"slice landed receipt {result.get('status') or 'unknown'}",
            payload={
                "receipt_id": payload.get("receipt_id"),
                "slice_id": payload.get("slice_id"),
                "landed_sha": payload.get("landed_sha"),
                "targets": result.get("targets") or [],
                "errors": result.get("errors") or [],
            },
        )


def emit_participant_slice_reviewed_receipts(
    config: Dict[str, Any],
    project_cfg: Dict[str, Any],
    *,
    slice_name: str,
    workflow_kind: str,
    review_round: int,
    accepted_on_round: str,
    review_duration_ms: int,
    verified: bool,
    issue_fingerprints: Sequence[str],
    reviewed_at: str,
) -> None:
    project_id = str(project_cfg.get("id") or "").strip()
    run_rows = slice_run_rows(project_id, slice_name)
    if not run_rows:
        return
    implementation_aliases: List[str] = []
    for row in run_rows:
        if str(row.get("job_kind") or "").strip() not in {"coding", "healing"}:
            continue
        alias = str(row.get("account_alias") or "").strip()
        if alias and alias not in implementation_aliases:
            implementation_aliases.append(alias)
    for alias in implementation_aliases:
        lane_row = participant_lane_row_for_alias(alias, refresh=True)
        if lane_row is None:
            continue
        estimated_cost_usd = round(
            sum(
                float(row.get("estimated_cost_usd") or 0.0)
                for row in run_rows
                if str(row.get("account_alias") or "").strip() == alias
            ),
            6,
        )
        payload = build_participant_contribution_receipt(
            lane_row,
            event_kind="slice_reviewed",
            project_id=project_id,
            slice_id=review_slice_key(slice_name),
            workflow_kind=workflow_kind,
            review_rounds_used=max(0, int(review_round or 0)),
            accepted_on_round=str(accepted_on_round or "").strip(),
            landed_at=str(reviewed_at or "").strip(),
            verified=bool(verified),
            paid_lane_used=True,
            review_ms=max(0, int(review_duration_ms or 0)),
            issue_fingerprints=[str(item or "").strip() for item in issue_fingerprints if str(item or "").strip()],
            consumption_trace={
                "estimated_cost_usd": estimated_cost_usd,
                "participant_run_count": 1,
                "managed_run_count": 0,
                "participant_worker_aliases": [alias],
            },
        )
        result = emit_participant_receipt(lane_row, event_kind="slice_reviewed", payload=payload)
        record_participant_lane_event(
            str(lane_row.get("lane_id") or "").strip(),
            "receipt_slice_reviewed",
            f"slice reviewed receipt {result.get('status') or 'unknown'}",
            payload={
                "receipt_id": payload.get("receipt_id"),
                "slice_id": payload.get("slice_id"),
                "accepted_on_round": payload.get("accepted_on_round"),
                "targets": result.get("targets") or [],
                "errors": result.get("errors") or [],
            },
        )


def participant_burst_task_eligible(project_cfg: Dict[str, Any], decision: Dict[str, Any], account_cfg: Dict[str, Any]) -> bool:
    if not bool(account_cfg.get("participant_burst_lane")) and not account_is_participant_funded(account_cfg):
        return True
    policy = participant_burst_policy(project_cfg)
    if not bool(policy.get("enabled")) or not bool(policy.get("allow_chatgpt_accounts")):
        return False
    lane_role = normalize_participant_lane_role(account_cfg.get("participant_lane_role") or "coding")
    project_id = str(project_cfg.get("id") or "").strip()
    participant_project_id = str(account_cfg.get("participant_project_id") or "").strip()
    if participant_project_id and participant_project_id != project_id:
        return False
    decision_lane = str(decision.get("lane") or "").strip().lower()
    expected_lane = participant_lane_dispatch_lane(lane_role, policy)
    if decision_lane != expected_lane:
        return False
    if lane_role in {"review", "deep_review"}:
        return True
    task_meta = dict(decision.get("task_meta") or {})
    if not (
        bool(task_meta.get("participant_eligible"))
        or bool(task_meta.get("premium_required"))
        or bool(task_meta.get("premium_beneficial"))
    ):
        return False
    eligible_classes = {
        str(item or "").strip()
        for item in policy.get("eligible_task_classes") or PARTICIPANT_LANE_TASK_CLASSES
        if str(item or "").strip()
    }
    if eligible_classes and str(decision.get("tier") or "").strip() not in eligible_classes:
        return False
    return True


def task_done(task: Any) -> bool:
    try:
        return bool(task.done())
    except Exception:
        return False


def runtime_task_rows_for_project(project_id: str) -> List[Dict[str, Any]]:
    project = str(project_id or "").strip()
    if not project or not table_exists("runtime_tasks"):
        return []
    with db() as conn:
        rows = conn.execute(
            """
            SELECT *
            FROM runtime_tasks
            WHERE project_id=?
            ORDER BY
                CASE task_state WHEN 'running' THEN 0 WHEN 'scheduled' THEN 1 ELSE 2 END,
                updated_at DESC,
                package_id ASC
            """,
            (project,),
        ).fetchall()
    items: List[Dict[str, Any]] = []
    for row in rows:
        item = dict(row)
        payload = json_field(item.get("payload_json"), {})
        item["payload"] = payload if isinstance(payload, dict) else {}
        items.append(item)
    return items


def live_runtime_task_handle(project_or_package_id: str) -> Optional[Any]:
    clean = str(project_or_package_id or "").strip()
    if not clean:
        return None
    task = state.tasks.get(clean)
    if task is None:
        matching_keys = [key for key in list(state.tasks) if key == clean]
        if not matching_keys:
            matching_keys = [
                key
                for key, row in runtime_task_rows().items()
                if str(row.get("project_id") or "").strip() == clean and key in state.tasks
            ]
        if len(matching_keys) == 1:
            task = state.tasks.get(matching_keys[0])
    if task is None:
        return None
    if task_done(task):
        for key, candidate in list(state.tasks.items()):
            if candidate is task:
                state.tasks.pop(key, None)
        save_runtime_task_cache_snapshot()
        return None
    return task


def persisted_runtime_task_active(package_or_project_id: str, row: Optional[Dict[str, Any]] = None) -> bool:
    task_row = row or runtime_task_row(package_or_project_id)
    if not task_row:
        return False
    task_state = str(task_row.get("task_state") or "").strip().lower()
    if task_state == "scheduled":
        scheduled_at = parse_iso(str(task_row.get("scheduled_at") or "")) or parse_iso(str(task_row.get("updated_at") or ""))
        if scheduled_at is None:
            return True
        return (utc_now() - scheduled_at).total_seconds() <= RUNTIME_TASK_SCHEDULED_GRACE_SECONDS
    if task_state != "running":
        return False
    task_kind = str(task_row.get("task_kind") or "").strip().lower()
    run_id = int(task_row.get("run_id") or 0)
    project_id = str(task_row.get("project_id") or package_or_project_id or "").strip()
    with db() as conn:
        project_row = conn.execute(
            "SELECT status, active_run_id FROM projects WHERE id=?",
            (project_id,),
        ).fetchone()
        run_row = conn.execute(
            "SELECT status, finished_at FROM runs WHERE id=?",
            (run_id,),
        ).fetchone() if run_id else None
    runtime_status = str((project_row["status"] if project_row else "") or "").strip().lower()
    if task_kind == "local_review" and active_local_review_run(project_id):
        return True
    if project_row and int(project_row["active_run_id"] or 0) == run_id and runtime_status in ACTIVE_RUN_STATUSES:
        return True
    return bool(
        run_row
        and str(run_row["status"] or "").strip().lower() in ACTIVE_RUN_STATUSES
        and not parse_iso(run_row["finished_at"])
    )


def project_has_runtime_task(project_id: str) -> bool:
    project = str(project_id or "").strip()
    if not project:
        return False
    for row in runtime_task_rows_for_project(project):
        package_id = str(row.get("package_id") or "").strip()
        if package_id and live_runtime_task_handle(package_id) is not None:
            return True
        if persisted_runtime_task_active(package_id or project, row):
            return True
    clear_runtime_task(project)
    return False


def project_active_runtime_task_count(
    project_id: str,
    *,
    task_kinds: Optional[Sequence[str]] = None,
) -> int:
    project = str(project_id or "").strip()
    if not project:
        return 0
    allowed_kinds = {
        str(item or "").strip().lower()
        for item in (task_kinds or [])
        if str(item or "").strip()
    }
    count = 0
    for row in runtime_task_rows_for_project(project):
        task_kind = str(row.get("task_kind") or "").strip().lower()
        if allowed_kinds and task_kind not in allowed_kinds:
            continue
        package_id = str(row.get("package_id") or "").strip()
        if package_id and live_runtime_task_handle(package_id) is not None:
            count += 1
            continue
        if persisted_runtime_task_active(package_id or project, row):
            count += 1
            continue
        clear_runtime_task(package_id or project)
    return count


def project_active_coding_runtime_count(project_id: str) -> int:
    return project_active_runtime_task_count(project_id, task_kinds=("coding", "healing"))


def active_coding_runtime_keys(project_rows: Sequence[sqlite3.Row]) -> Set[str]:
    active: Set[str] = set()
    for package_id, row in runtime_task_rows().items():
        task_kind = str(row.get("task_kind") or "").strip().lower()
        if task_kind not in {"coding", "healing"}:
            continue
        if persisted_runtime_task_active(package_id, row):
            active.add(package_id)
        else:
            clear_runtime_task(package_id)
    run_ids = [int(row["active_run_id"]) for row in project_rows if row["active_run_id"]]
    runs_by_id: Dict[int, sqlite3.Row] = {}
    if run_ids:
        placeholders = ",".join("?" for _ in run_ids)
        with db() as conn:
            for run in conn.execute(
                f"SELECT id, package_id, job_kind, status, finished_at FROM runs WHERE id IN ({placeholders})",
                tuple(run_ids),
            ).fetchall():
                runs_by_id[int(run["id"])] = run
    for row in project_rows:
        project_id = str(row["id"] or "").strip()
        if not project_id:
            continue
        run = runs_by_id.get(int(row["active_run_id"] or 0)) if row["active_run_id"] else None
        run_status = str((run["status"] if run else row["status"]) or "").strip().lower()
        run_kind = str((run["job_kind"] if run else "coding") or "coding").strip().lower() or "coding"
        if run_kind not in {"coding", "healing"}:
            continue
        if run_status not in ACTIVE_RUN_STATUSES:
            continue
        runtime_key = str((run["package_id"] if run and "package_id" in run.keys() else "") or "").strip() or project_id
        if runtime_key not in runtime_task_rows():
            active.add(runtime_key)
    return active


def project_dispatch_slots_remaining(
    config: Dict[str, Any],
    project_cfg: Dict[str, Any],
    *,
    reserved_launch_count: int = 0,
) -> int:
    project_id = str(project_cfg.get("id") or "").strip()
    if not project_id:
        return 0
    if not project_uses_package_scheduler(config, project_id):
        return 0 if project_has_runtime_task(project_id) or reserved_launch_count > 0 else 1
    cap = max(1, project_runtime_concurrency_cap(config, project_cfg))
    active_count = project_active_coding_runtime_count(project_id)
    return max(0, cap - active_count - max(0, int(reserved_launch_count)))


def runtime_task_project_ids() -> Set[str]:
    ids: Set[str] = set()
    for task_key in list(state.tasks):
        row = runtime_task_row(task_key)
        project_id = str((row or {}).get("project_id") or "").strip()
        if live_runtime_task_handle(task_key) is not None and project_id:
            ids.add(project_id)
    for package_id, row in runtime_task_rows().items():
        project_id = str(row.get("project_id") or "").strip()
        if persisted_runtime_task_active(package_id, row):
            if project_id:
                ids.add(project_id)
        else:
            clear_runtime_task(package_id)
    return ids


def project_enabled_in_desired_state(project_id: str) -> bool:
    clean = str(project_id or "").strip()
    if not clean:
        return True
    try:
        project_cfg = get_project_cfg(normalize_config(), clean)
    except Exception:
        return True
    return bool(project_cfg.get("enabled", True))


def interrupt_runtime_outcome(
    runtime_key: str,
    *,
    project_id: Optional[str] = None,
    local_review: bool = False,
    current_slice_name: Optional[str] = None,
) -> Dict[str, Any]:
    clean_runtime_key = str(runtime_key or "").strip()
    clean_project_id = str(project_id or clean_runtime_key).strip()
    override = dict(_RUNTIME_INTERRUPT_OVERRIDES.pop(clean_runtime_key, {}) or {})
    paused = bool(override.get("paused")) if "paused" in override else (not project_enabled_in_desired_state(clean_project_id))
    status = str(
        override.get("status")
        or ("paused" if paused else (review_hold_status_for_project(clean_project_id) if local_review else READY_STATUS))
    ).strip() or ("paused" if paused else READY_STATUS)
    cooldown_until = override.get("cooldown_until") if "cooldown_until" in override else (None if paused else utc_now() + dt.timedelta(seconds=1))
    message = str(override.get("message") or ("pause requested by operator" if paused else "runtime task cancelled")).strip()
    slice_name = (
        str(override.get("slice_name") or current_slice_name or "").strip()
        or (review_slice_name(clean_project_id) if local_review else "")
        or f"Review {clean_project_id}"
        if local_review
        else None
    )
    return {
        "paused": paused,
        "status": status,
        "cooldown_until": cooldown_until,
        "message": message,
        "error_class": str(override.get("error_class") or ("operator_pause" if paused else "cancelled")).strip() or ("operator_pause" if paused else "cancelled"),
        "run_status": str(override.get("run_status") or ("paused" if paused else "abandoned")).strip() or ("paused" if paused else "abandoned"),
        "slice_name": slice_name,
    }


def interrupt_project_runtime(project_id: str, *, reason: Optional[str] = None) -> Dict[str, Any]:
    clean = str(project_id or "").strip()
    if not clean:
        raise HTTPException(400, "project_id is required")
    config = normalize_config()
    get_project_cfg(config, clean)
    with db() as conn:
        row = conn.execute("SELECT * FROM projects WHERE id=?", (clean,)).fetchone()
    if not row:
        raise HTTPException(404, f"unknown project: {clean}")
    task = live_runtime_task_handle(clean)
    task_row = runtime_task_row(clean)
    run_id = int((task_row or {}).get("run_id") or row["active_run_id"] or 0)
    now = utc_now()
    message = str(reason or "").strip() or "pause requested by operator"
    had_live_task = task is not None
    cancel_requested = False
    if task is not None:
        try:
            cancel_requested = bool(task.cancel())
        except Exception:
            cancel_requested = False
    elif task_row:
        if run_id:
            with db() as conn:
                conn.execute(
                    """
                    UPDATE runs
                    SET status='paused', finished_at=?, error_class='operator_pause', error_message=?
                    WHERE id=?
                    """,
                    (iso(now), message, run_id),
                )
        clear_runtime_task(clean)
    update_project_status(
        clean,
        status="paused",
        current_slice=current_slice(row),
        active_run_id=None,
        cooldown_until=None,
        last_run_at=now,
        last_error=message,
        consecutive_failures=row["consecutive_failures"],
        spider_tier=row["spider_tier"],
        spider_model=row["spider_model"],
        spider_reason=row["spider_reason"],
    )
    return {
        "ok": True,
        "project_id": clean,
        "status": "paused",
        "interrupt_reason": message,
        "had_live_task": had_live_task,
        "cancel_requested": cancel_requested,
        "run_id": run_id or None,
    }


def attach_runtime_task_handle(
    project_id: str,
    coroutine: Any,
    *,
    clear_on_failure: bool = False,
) -> bool:
    project = str(project_id or "").strip()
    if not project:
        with contextlib.suppress(Exception):
            coroutine.close()
        return False
    if live_runtime_task_handle(project) is not None:
        with contextlib.suppress(Exception):
            coroutine.close()
        return False
    loop = state.controller_loop

    def _cleanup_failed_task(task: Any) -> None:
        try:
            if hasattr(task, "cancelled") and task.cancelled():
                return
            exc = task.exception()
        except (asyncio.CancelledError, concurrent.futures.CancelledError):
            return
        except Exception as callback_exc:
            exc = callback_exc
        if exc is None:
            return
        traceback.print_exception(type(exc), exc, exc.__traceback__)
        state.tasks.pop(project, None)
        if clear_on_failure:
            clear_runtime_task(project)

    try:
        running_loop = asyncio.get_running_loop()
    except RuntimeError:
        running_loop = None
    if loop and loop.is_running() and running_loop is not loop:
        task = asyncio.run_coroutine_threadsafe(coroutine, loop)
    elif running_loop is not None:
        task = asyncio.create_task(coroutine)
    elif loop and loop.is_running():
        task = asyncio.run_coroutine_threadsafe(coroutine, loop)
    else:
        with contextlib.suppress(Exception):
            coroutine.close()
        if clear_on_failure:
            clear_runtime_task(project)
        return False
    if hasattr(task, "add_done_callback"):
        task.add_done_callback(_cleanup_failed_task)
    state.tasks[project] = task
    save_runtime_task_cache_snapshot()
    return True


def run_duration_ms(started_at: Optional[str], finished_at: Optional[str]) -> int:
    started = parse_iso(str(started_at or ""))
    finished = parse_iso(str(finished_at or ""))
    if not started or not finished:
        return 0
    return max(0, int((finished - started).total_seconds() * 1000))


def _round_metric_list(raw: Any) -> List[int]:
    values = json_field(raw if isinstance(raw, str) else json.dumps(raw), []) if not isinstance(raw, list) else raw
    result: List[int] = []
    for item in values:
        try:
            result.append(int(item))
        except Exception:
            result.append(0)
    return result


def _set_round_metric(raw: Any, round_number: int, value: int) -> str:
    values = _round_metric_list(raw)
    while len(values) < round_number:
        values.append(0)
    idx = max(0, round_number - 1)
    values[idx] = max(int(values[idx] or 0), int(value))
    return json.dumps(values, sort_keys=True)


def _merge_issue_fingerprints(raw: Any, issue_ids: Sequence[str]) -> str:
    current = [str(item).strip() for item in (json_field(raw if isinstance(raw, str) else json.dumps(raw), []) if not isinstance(raw, list) else raw) if str(item).strip()]
    for issue_id in issue_ids:
        clean = str(issue_id).strip()
        if clean and clean not in current:
            current.append(clean)
    return json.dumps(current, sort_keys=True)


def _merge_allowance_burn(raw: Any, lane_name: str, estimated_cost_usd: Optional[float]) -> str:
    payload = json_field(raw if isinstance(raw, str) else json.dumps(raw), {}) if not isinstance(raw, dict) else dict(raw)
    lane = str(lane_name or "").strip().lower()
    if not lane:
        return json.dumps(payload, sort_keys=True)
    row = dict(payload.get(lane) or {})
    row["runs"] = int(row.get("runs") or 0) + 1
    if estimated_cost_usd is not None:
        row["estimated_cost_usd"] = round(float(row.get("estimated_cost_usd") or 0.0) + float(estimated_cost_usd), 6)
    payload[lane] = row
    return json.dumps(payload, sort_keys=True)


def changed_paths_since_snapshot(repo_path: str, baseline_snapshot: Optional[Dict[str, str]]) -> List[str]:
    current_snapshot = git_dirty_snapshot(repo_path)
    if baseline_snapshot is None:
        return sorted(current_snapshot)
    return sorted(path for path, fingerprint in current_snapshot.items() if baseline_snapshot.get(path) != fingerprint)


def review_packet_payload(
    *,
    project_id: str,
    slice_name: str,
    decision: Dict[str, Any],
    changed_paths: Sequence[str],
    verify_rc: Optional[int],
    run_id: int,
) -> Dict[str, Any]:
    return {
        "slice_id": f"{project_id}:{review_slice_key(slice_name)}:{run_id}",
        "title": slice_name,
        "selected_lane": str(decision.get("lane") or ""),
        "required_reviewer_lane": str(decision.get("required_reviewer_lane") or ""),
        "final_reviewer_lane": str(((decision.get("task_meta") or {}).get("final_reviewer_lane") or "")),
        "acceptance_level": str(((decision.get("task_meta") or {}).get("acceptance_level") or "")),
        "review_round": int(((decision.get("task_meta") or {}).get("review_round") or 0)),
        "changed_files": list(changed_paths),
        "verify_exit_code": verify_rc,
    }


def provider_slot_state(provider_payload: Dict[str, Any]) -> str:
    explicit = str(provider_payload.get("state") or "").strip().lower()
    if explicit:
        return explicit
    slot_states = [str(item.get("state") or "").strip().lower() for item in provider_payload.get("slots") or [] if str(item.get("state") or "").strip()]
    if any(state == "ready" for state in slot_states):
        return "ready"
    if any(state in {"degraded", "cooldown"} for state in slot_states):
        return "degraded"
    if slot_states:
        return slot_states[0]
    return "unknown"


def ea_codex_profiles(force: bool = False, *, cache_only: bool = False) -> Dict[str, Any]:
    now = time.time()
    cached = _EA_PROFILE_CACHE.get("payload")
    fetched_at = float(_EA_PROFILE_CACHE.get("fetched_at") or 0.0)
    if not force and cached and (now - fetched_at) < EA_STATUS_CACHE_SECONDS:
        return cached if isinstance(cached, dict) else {}
    persisted_payload, persisted_fetched_at = load_runtime_cache(RUNTIME_CACHE_KEY_EA_CODEX_PROFILES)
    if cache_only:
        payload = persisted_payload if persisted_payload else (cached if isinstance(cached, dict) else {})
        if payload:
            cache_now = now
            if persisted_fetched_at is not None:
                cache_now = max(0.0, persisted_fetched_at.timestamp())
            _EA_PROFILE_CACHE["fetched_at"] = cache_now
            _EA_PROFILE_CACHE["payload"] = payload
        return payload if isinstance(payload, dict) else {}
    runtime_settings = resolved_ea_runtime_settings()
    status_base_url = str(runtime_settings.get("base_url") or EA_STATUS_BASE_URL).strip()
    status_api_token = str(runtime_settings.get("api_token") or EA_STATUS_API_TOKEN).strip()
    status_principal_id = str(runtime_settings.get("principal_id") or EA_STATUS_PRINCIPAL_ID).strip() or EA_STATUS_PRINCIPAL_ID
    if not status_base_url:
        if persisted_payload:
            _EA_PROFILE_CACHE["fetched_at"] = now
            _EA_PROFILE_CACHE["payload"] = persisted_payload
            return persisted_payload
        return {}
    request = urllib.request.Request(
        f"{status_base_url}/v1/codex/profiles",
        headers={
            **({"Authorization": f"Bearer {status_api_token}"} if status_api_token else {}),
            "X-EA-Principal-ID": status_principal_id,
            "User-Agent": "codex-fleet-controller",
        },
        method="GET",
    )
    try:
        with urllib.request.urlopen(request, timeout=5) as response:
            payload = json.loads(response.read().decode("utf-8"))
    except Exception:
        if persisted_payload:
            payload = persisted_payload
            cache_now = now
            if persisted_fetched_at is not None:
                cache_now = max(0.0, persisted_fetched_at.timestamp())
            _EA_PROFILE_CACHE["fetched_at"] = cache_now
            _EA_PROFILE_CACHE["payload"] = payload
            return payload
        payload = {}
    payload = payload if isinstance(payload, dict) else {}
    _EA_PROFILE_CACHE["fetched_at"] = now
    _EA_PROFILE_CACHE["payload"] = payload
    if payload:
        save_runtime_cache(RUNTIME_CACHE_KEY_EA_CODEX_PROFILES, payload)
    return _EA_PROFILE_CACHE["payload"]


