def _latest_iso_value(values: Sequence[Any]) -> Optional[str]:
    latest_text = ""
    latest_dt: Optional[dt.datetime] = None
    for value in values:
        parsed = parse_iso(value)
        if parsed is None:
            continue
        if latest_dt is None or parsed > latest_dt:
            latest_dt = parsed
            latest_text = str(value or "").strip()
    return latest_text or None


def _normalized_onemin_aggregate_timestamp(value: Any) -> Optional[dt.datetime]:
    if value is None:
        return None
    if isinstance(value, str):
        clean = value.strip()
        if not clean:
            return None
        parsed = parse_iso(clean)
        if parsed is not None:
            return parsed
        value = clean
    numeric = float_or_none(value)
    if numeric is None:
        return None
    try:
        return dt.datetime.fromtimestamp(float(numeric), tz=UTC)
    except (OverflowError, OSError, ValueError):
        return None


def _onemin_manager_aggregate_has_billing_evidence(aggregate: Dict[str, Any]) -> bool:
    if not aggregate:
        return False
    if max(
        0,
        int(float_or_none(aggregate.get("slot_count_with_billing_snapshot")) or 0),
        int(float_or_none(aggregate.get("slot_count_with_member_reconciliation")) or 0),
        int(float_or_none(aggregate.get("actual_billing_account_count")) or 0),
    ) > 0:
        return True
    for item in aggregate.get("accounts") or []:
        if not isinstance(item, dict):
            continue
        if str(item.get("last_billing_snapshot_at") or "").strip():
            return True
        if str(item.get("last_member_reconciliation_at") or "").strip():
            return True
    return False


def _cached_onemin_billing_aggregate_payload() -> Dict[str, Any]:
    if not ONEMIN_AGGREGATE_RUNTIME_ROOT.is_dir():
        return {}

    candidate_paths: List[pathlib.Path] = []
    seen_paths: set[pathlib.Path] = set()
    for pattern in ONEMIN_AGGREGATE_RUNTIME_PATTERNS:
        for path in sorted(ONEMIN_AGGREGATE_RUNTIME_ROOT.glob(pattern)):
            if not path.is_file() or path in seen_paths:
                continue
            seen_paths.add(path)
            candidate_paths.append(path)

    best_payload: Dict[str, Any] = {}
    best_timestamp: Optional[dt.datetime] = None
    for path in candidate_paths:
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(payload, dict):
            continue
        slot_count_with_billing_snapshot = max(0, int(float_or_none(payload.get("slot_count_with_billing_snapshot")) or 0))
        slot_count_with_member_reconciliation = max(
            0,
            int(float_or_none(payload.get("slot_count_with_member_reconciliation")) or 0),
        )
        hours_remaining_at_current_pace_no_topup = float_or_none(payload.get("hours_remaining_at_current_pace_no_topup"))
        hours_until_next_topup = float_or_none(payload.get("hours_until_next_topup"))
        if max(slot_count_with_billing_snapshot, slot_count_with_member_reconciliation) <= 0:
            continue
        if hours_remaining_at_current_pace_no_topup is None or hours_until_next_topup is None:
            continue
        candidate_timestamp = (
            _normalized_onemin_aggregate_timestamp(payload.get("recorded_at_utc"))
            or _normalized_onemin_aggregate_timestamp(payload.get("last_probe_at"))
            or _normalized_onemin_aggregate_timestamp(payload.get("latest_member_reconciliation_at"))
            or _normalized_onemin_aggregate_timestamp(payload.get("last_actual_balance_check_at"))
        )
        if candidate_timestamp is None:
            try:
                candidate_timestamp = dt.datetime.fromtimestamp(path.stat().st_mtime, tz=UTC)
            except OSError:
                candidate_timestamp = None
        if best_timestamp is not None and candidate_timestamp is not None and candidate_timestamp <= best_timestamp:
            continue

        normalized = dict(payload)
        if normalized.get("sum_free_credits") in (None, "") and normalized.get("free_credits") not in (None, ""):
            normalized["sum_free_credits"] = normalized.get("free_credits")
        if normalized.get("remaining_percent_total") in (None, "") and normalized.get("percent_remaining") not in (None, ""):
            normalized["remaining_percent_total"] = normalized.get("percent_remaining")
        for key in ("latest_member_reconciliation_at", "last_actual_balance_check_at", "next_topup_at"):
            parsed = _normalized_onemin_aggregate_timestamp(normalized.get(key))
            if parsed is not None:
                normalized[key] = iso(parsed)
        normalized["hours_remaining_at_current_pace_no_topup"] = hours_remaining_at_current_pace_no_topup
        normalized["hours_until_next_topup"] = hours_until_next_topup
        if normalized.get("source") in (None, ""):
            normalized["source"] = str(normalized.get("payload_source") or "browseract_bootstrap_runtime_cache").strip() or "browseract_bootstrap_runtime_cache"
        if not str(normalized.get("basis_summary") or "").strip():
            normalized["basis_summary"] = str(normalized.get("source") or "browseract_bootstrap_runtime_cache")
        best_payload = normalized
        best_timestamp = candidate_timestamp
    return best_payload


def ea_onemin_manager_status(force: bool = False, *, cache_only: bool = False) -> Dict[str, Any]:
    now = time.time()
    cached = _EA_ONEMIN_MANAGER_CACHE.get("payload")
    fetched_at = float(_EA_ONEMIN_MANAGER_CACHE.get("fetched_at") or 0.0)
    if not force and cached and (now - fetched_at) < EA_STATUS_CACHE_SECONDS:
        return cached if isinstance(cached, dict) else {}
    persisted_payload, persisted_fetched_at = load_runtime_cache(RUNTIME_CACHE_KEY_EA_ONEMIN_MANAGER_STATUS)
    if cache_only:
        payload = persisted_payload if persisted_payload else (cached if isinstance(cached, dict) else {})
        if payload:
            cache_now = now
            if persisted_fetched_at is not None:
                cache_now = max(0.0, persisted_fetched_at.timestamp())
            _EA_ONEMIN_MANAGER_CACHE["fetched_at"] = cache_now
            _EA_ONEMIN_MANAGER_CACHE["payload"] = payload
        return dict(payload) if isinstance(payload, dict) else {}
    runtime_settings = resolved_ea_runtime_settings()
    status_base_url = str(runtime_settings.get("base_url") or EA_STATUS_BASE_URL).strip()
    status_api_token = str(runtime_settings.get("api_token") or EA_STATUS_API_TOKEN).strip()
    status_principal_id = str(runtime_settings.get("principal_id") or EA_STATUS_PRINCIPAL_ID).strip() or EA_STATUS_PRINCIPAL_ID
    if not status_base_url:
        if persisted_payload:
            _EA_ONEMIN_MANAGER_CACHE["fetched_at"] = now
            _EA_ONEMIN_MANAGER_CACHE["payload"] = persisted_payload
            return dict(persisted_payload)
        return {}
    headers = {
        **({"Authorization": f"Bearer {status_api_token}"} if status_api_token else {}),
        "X-EA-Principal-ID": status_principal_id,
        "User-Agent": "codex-fleet-controller",
    }

    def _request_json(path: str) -> Dict[str, Any]:
        request = urllib.request.Request(f"{status_base_url}{path}", headers=headers, method="GET")
        with urllib.request.urlopen(request, timeout=3) as response:
            payload = json.loads(response.read().decode("utf-8"))
        return payload if isinstance(payload, dict) else {}

    def _request_json_global_first(path: str) -> Dict[str, Any]:
        try:
            return _request_json(f"{path}?scope=global")
        except urllib.error.HTTPError as exc:
            if exc.code not in {403, 404, 422}:
                raise
        return _request_json(path)

    try:
        payload = {
            "aggregate": _request_json_global_first("/v1/providers/onemin/aggregate"),
            "runway": _request_json_global_first("/v1/providers/onemin/runway"),
        }
    except Exception:
        if persisted_payload:
            cache_now = now
            if persisted_fetched_at is not None:
                cache_now = max(0.0, persisted_fetched_at.timestamp())
            _EA_ONEMIN_MANAGER_CACHE["fetched_at"] = cache_now
            _EA_ONEMIN_MANAGER_CACHE["payload"] = persisted_payload
            return dict(persisted_payload)
        payload = {}

    payload = payload if isinstance(payload, dict) else {}
    _EA_ONEMIN_MANAGER_CACHE["fetched_at"] = now
    _EA_ONEMIN_MANAGER_CACHE["payload"] = payload
    if payload:
        save_runtime_cache(RUNTIME_CACHE_KEY_EA_ONEMIN_MANAGER_STATUS, payload)
    return dict(payload)


def ea_onemin_manager_billing_aggregate(force: bool = False, *, cache_only: bool = False) -> Dict[str, Any]:
    try:
        manager_payload = ea_onemin_manager_status(force=force, cache_only=cache_only)
    except TypeError:
        manager_payload = ea_onemin_manager_status(force=force)
    aggregate = dict(manager_payload.get("aggregate") or {})
    cached_aggregate = (
        _cached_onemin_billing_aggregate_payload()
        if not _onemin_manager_aggregate_has_billing_evidence(aggregate)
        else {}
    )
    if cached_aggregate:
        runtime_lease_payload = onemin_runtime_lease_payload(cache_only=cache_only)
        reported_active_lease_count = max(0, int(float_or_none(cached_aggregate.get("active_lease_count")) or 0))
        runtime_active_lease_count = max(0, int(runtime_lease_payload.get("active_onemin_codexers") or 0))
        effective_active_lease_count = max(reported_active_lease_count, runtime_active_lease_count)
        active_lease_count_source = (
            "fleet_runtime_backfill"
            if effective_active_lease_count > reported_active_lease_count
            else str(cached_aggregate.get("source") or "browseract_bootstrap_runtime_cache")
        )
        return {
            **cached_aggregate,
            "active_lease_count": effective_active_lease_count,
            "reported_active_lease_count": reported_active_lease_count,
            "runtime_active_lease_count": runtime_active_lease_count,
            "active_lease_count_source": active_lease_count_source,
            "active_onemin_projects": list(runtime_lease_payload.get("active_onemin_projects") or []),
            "active_onemin_accounts": list(runtime_lease_payload.get("active_onemin_accounts") or []),
        }
    runway = dict(manager_payload.get("runway") or {})
    accounts = [dict(item) for item in aggregate.get("accounts") or [] if isinstance(item, dict)]
    if not aggregate:
        legacy_payload = ea_codex_status(window="7d", cache_only=cache_only)
        legacy_aggregate = dict(legacy_payload.get("onemin_billing_aggregate") or {})
        last_actual_balance = str(((legacy_payload.get("topup_summary") or {}).get("last_actual_balance_check_at")) or "").strip()
        if last_actual_balance and not str(legacy_aggregate.get("last_actual_balance_check_at") or "").strip():
            legacy_aggregate["last_actual_balance_check_at"] = last_actual_balance
        return legacy_aggregate

    sum_free_credits = aggregate.get("sum_free_credits")
    sum_max_credits = aggregate.get("sum_max_credits")
    runtime_lease_payload = onemin_runtime_lease_payload(cache_only=cache_only)
    reported_active_lease_count = max(0, int(aggregate.get("active_lease_count") or 0))
    runtime_active_lease_count = max(0, int(runtime_lease_payload.get("active_onemin_codexers") or 0))
    effective_active_lease_count = max(reported_active_lease_count, runtime_active_lease_count)
    active_lease_count_source = (
        "fleet_runtime_backfill"
        if effective_active_lease_count > reported_active_lease_count
        else "ea_onemin_manager"
    )
    remaining_percent_total = None
    try:
        if sum_free_credits is not None and float(sum_max_credits or 0) > 0:
            remaining_percent_total = round((float(sum_free_credits) / float(sum_max_credits)) * 100.0, 2)
    except Exception:
        remaining_percent_total = None

    slot_count_with_billing_snapshot = sum(
        int(item.get("slot_count") or 0)
        for item in accounts
        if str(item.get("last_billing_snapshot_at") or "").strip()
    )
    slot_count_with_member_reconciliation = sum(
        int(item.get("slot_count") or 0)
        for item in accounts
        if str(item.get("last_member_reconciliation_at") or "").strip()
    )
    latest_member_reconciliation_at = _latest_iso_value(item.get("last_member_reconciliation_at") for item in accounts)
    last_actual_balance_check_at = _latest_iso_value(item.get("last_billing_snapshot_at") for item in accounts)
    topup_window = resolve_onemin_topup_window(
        runway=runway,
        aggregate=aggregate,
        last_actual_balance_check_at=last_actual_balance_check_at,
    )
    next_topup_at = topup_window["next_topup_at"]
    hours_until_next_topup = topup_window["hours_until_next_topup"]
    topup_amount = topup_window["topup_amount"]
    topup_eta_source = topup_window["topup_eta_source"]

    current_burn = runway.get("current_burn_per_hour")
    if current_burn in (None, ""):
        current_burn = aggregate.get("current_pace_burn_credits_per_hour")
    hours_remaining_no_topup = runway.get("hours_remaining_current_pace")
    if hours_remaining_no_topup in (None, ""):
        hours_remaining_no_topup = aggregate.get("hours_remaining_at_current_pace")
    hours_remaining_including_topup = None
    try:
        if hours_remaining_no_topup not in (None, ""):
            hours_remaining_including_topup = float(hours_remaining_no_topup)
            if current_burn not in (None, "", 0) and topup_amount not in (None, ""):
                hours_remaining_including_topup += float(topup_amount or 0.0) / float(current_burn)
    except Exception:
        hours_remaining_including_topup = None

    depletes_before_next_topup = None
    try:
        if hours_until_next_topup is not None and hours_remaining_no_topup not in (None, ""):
            depletes_before_next_topup = float(hours_remaining_no_topup) < float(hours_until_next_topup)
    except Exception:
        depletes_before_next_topup = None

    return {
        "source": "ea_onemin_manager",
        "sum_free_credits": sum_free_credits,
        "sum_max_credits": sum_max_credits,
        "remaining_percent_total": remaining_percent_total,
        "active_lease_count": effective_active_lease_count,
        "reported_active_lease_count": reported_active_lease_count,
        "runtime_active_lease_count": runtime_active_lease_count,
        "active_lease_count_source": active_lease_count_source,
        "active_onemin_projects": list(runtime_lease_payload.get("active_onemin_projects") or []),
        "active_onemin_accounts": list(runtime_lease_payload.get("active_onemin_accounts") or []),
        "current_pace_burn_credits_per_hour": current_burn,
        "avg_daily_burn_credits_7d": None,
        "next_topup_at": next_topup_at,
        "topup_amount": topup_amount,
        "topup_eta_source": topup_eta_source,
        "hours_until_next_topup": hours_until_next_topup,
        "hours_remaining_at_current_pace_no_topup": hours_remaining_no_topup,
        "hours_remaining_including_next_topup_at_current_pace": hours_remaining_including_topup,
        "days_remaining_including_next_topup_at_7d_avg": runway.get("days_remaining_7d_avg") or aggregate.get("days_remaining_at_7d_average"),
        "depletes_before_next_topup": depletes_before_next_topup,
        "basis_summary": (
            (
                "ea_onemin_manager.aggregate+runway"
                + ("+billing_cycle_topup_eta" if topup_eta_source == "billing_cycle_fallback" else "")
                + ("+fleet_runtime_leases" if active_lease_count_source == "fleet_runtime_backfill" else "")
            )
        ),
        "basis_counts": {
            "actual_billing_usage_page": slot_count_with_billing_snapshot,
            "member_reconciliation": slot_count_with_member_reconciliation,
        },
        "slot_count_with_billing_snapshot": slot_count_with_billing_snapshot,
        "slot_count_with_member_reconciliation": slot_count_with_member_reconciliation,
        "latest_member_reconciliation_at": latest_member_reconciliation_at,
        "last_actual_balance_check_at": last_actual_balance_check_at,
    }


def onemin_profile_models(*, cache_only: bool = False) -> set[str]:
    try:
        payload = ea_codex_profiles(cache_only=cache_only)
    except TypeError:
        payload = ea_codex_profiles()
    models: set[str] = set()
    for item in payload.get("profiles") or []:
        provider_hints = {
            str(hint or "").strip().lower()
            for hint in (item.get("provider_hint_order") or [])
            if str(hint or "").strip()
        }
        if "onemin" not in provider_hints:
            continue
        model = str(item.get("model") or "").strip()
        if model:
            models.add(model)
    if not models:
        models.update({"ea-coder-hard", "ea-coder-hard-batch"})
    return models


def onemin_topup_cycle_fallback_hours() -> float:
    credit_cfg = dict((normalized_quartermaster_config().get("credit") or {}))
    hours = float_or_none(credit_cfg.get("topup_cycle_hours_fallback"))
    return max(24.0, float(hours or 24.0 * 30.0))


def resolve_onemin_topup_window(
    *,
    runway: Dict[str, Any],
    aggregate: Dict[str, Any],
    last_actual_balance_check_at: Optional[str],
) -> Dict[str, Any]:
    next_topup_at = str(runway.get("next_topup_at") or aggregate.get("next_topup_at") or "").strip() or None
    topup_amount = runway.get("topup_amount")
    if topup_amount in (None, ""):
        topup_amount = aggregate.get("topup_amount")
    topup_eta_source = "ea_onemin_manager" if next_topup_at else None
    hours_until_next_topup = None
    topup_at = parse_iso(next_topup_at or "")
    now = utc_now()
    if (topup_at is None or topup_at <= now) and last_actual_balance_check_at:
        anchor = parse_iso(str(last_actual_balance_check_at or "").strip())
        if anchor is not None:
            cycle_hours = onemin_topup_cycle_fallback_hours()
            fallback_at = anchor
            while fallback_at <= now:
                fallback_at += dt.timedelta(hours=cycle_hours)
            topup_at = fallback_at
            next_topup_at = iso(fallback_at)
            topup_eta_source = "billing_cycle_fallback"
    if topup_at is not None:
        hours_until_next_topup = round(max(0.0, (topup_at - now).total_seconds() / 3600.0), 2)
    return {
        "next_topup_at": next_topup_at,
        "hours_until_next_topup": hours_until_next_topup,
        "topup_amount": topup_amount,
        "topup_eta_source": topup_eta_source,
    }


def onemin_runtime_lease_payload(*, cache_only: bool = False) -> Dict[str, Any]:
    if not table_exists("runs"):
        return {"active_onemin_codexers": 0, "active_onemin_projects": [], "active_onemin_accounts": []}
    onemin_models = onemin_profile_models(cache_only=cache_only)
    with db() as conn:
        rows = conn.execute(
            """
            SELECT r.project_id, r.account_alias, r.model, COALESCE(a.auth_kind, '') AS auth_kind
            FROM runs r
            LEFT JOIN accounts a ON a.alias = r.account_alias
            WHERE r.status IN ('starting', 'running', 'verifying')
            ORDER BY r.id DESC
            """
        ).fetchall()
    active_rows = []
    for row in rows:
        auth_kind = str(row["auth_kind"] or "").strip()
        model = str(row["model"] or "").strip()
        if auth_kind != "ea":
            continue
        if model not in onemin_models:
            continue
        active_rows.append(row)
    return {
        "active_onemin_codexers": len(active_rows),
        "active_onemin_projects": sorted({str(row["project_id"] or "").strip() for row in active_rows if str(row["project_id"] or "").strip()}),
        "active_onemin_accounts": sorted({str(row["account_alias"] or "").strip() for row in active_rows if str(row["account_alias"] or "").strip()}),
    }


def normalized_quartermaster_config() -> Dict[str, Any]:
    return dict((load_yaml(QUARTERMASTER_PATH).get("quartermaster")) or {})


def quartermaster_config_mode() -> str:
    return str(normalized_quartermaster_config().get("mode") or "observe_only").strip().lower() or "observe_only"


def quartermaster_tick_policy() -> Dict[str, Any]:
    raw = normalized_quartermaster_config()
    incidents = dict(raw.get("incidents") or {})
    telemetry = dict(raw.get("telemetry") or {})
    baseline_tick_seconds = max(30, int(raw.get("baseline_tick_seconds") or raw.get("refresh_seconds") or 600))
    event_tick_min_seconds = max(30, int(raw.get("event_tick_min_seconds") or min(baseline_tick_seconds, 90) or 90))
    plan_ttl_seconds = max(event_tick_min_seconds, int(raw.get("plan_ttl_seconds") or max(baseline_tick_seconds, 900)))
    triggers = [
        str(item or "").strip()
        for item in incidents.get("triggers") or []
        if str(item or "").strip()
    ]
    if not triggers:
        triggers = ["review_backpressure", "audit_debt", "booster_idle", "slot_probe_stale"]
    return {
        "enabled": bool(raw.get("enabled", True)),
        "driver": str(raw.get("driver") or "service_poll").strip().lower() or "service_poll",
        "baseline_tick_seconds": baseline_tick_seconds,
        "event_tick_min_seconds": event_tick_min_seconds,
        "plan_ttl_seconds": plan_ttl_seconds,
        "max_scale_up_per_tick": max(0, int(raw.get("max_scale_up_per_tick") or 1)),
        "max_scale_down_per_tick": max(0, int(raw.get("max_scale_down_per_tick") or 1)),
        "min_worker_dwell_seconds": max(0, int(raw.get("min_worker_dwell_seconds") or 0)),
        "idle_drain_seconds": max(0, int(raw.get("idle_drain_seconds") or 0)),
        "triggers": triggers,
        "telemetry": {
            "provider": str(telemetry.get("provider") or "ea_onemin_manager").strip() or "ea_onemin_manager",
            "onemin_manager": str(telemetry.get("onemin_manager") or "ea").strip() or "ea",
            "onemin_query_mode": str(telemetry.get("onemin_query_mode") or "manager").strip() or "manager",
        },
    }


def _quartermaster_status_metadata(payload: Dict[str, Any]) -> Dict[str, Any]:
    status_payload = payload if isinstance(payload, dict) else {}
    return {
        "generated_at": str(status_payload.get("generated_at") or ""),
        "source_generated_at": str(status_payload.get("source_generated_at") or ""),
        "source": str(status_payload.get("source") or ""),
        "degraded": bool(status_payload.get("degraded")),
        "cache_state": str(status_payload.get("cache_state") or ""),
        "tick_reason": str(status_payload.get("tick_reason") or ""),
        "error": str(status_payload.get("error") or ""),
    }


def quartermaster_plan_status(plan: Dict[str, Any]) -> Dict[str, Any]:
    payload = plan if isinstance(plan, dict) else {}
    embedded = payload.get("_quartermaster_status")
    if isinstance(embedded, dict) and embedded:
        return dict(embedded)
    inferred = {
        "generated_at": str(payload.get("generated_at") or ""),
        "source_generated_at": str(payload.get("source_generated_at") or ""),
        "source": str(payload.get("source") or ""),
        "degraded": bool(payload.get("degraded")),
        "cache_state": str(payload.get("cache_state") or ""),
        "tick_reason": str(payload.get("tick_reason") or ""),
        "error": str(payload.get("error") or ""),
    }
    return inferred if any(inferred.values()) else {}


def quartermaster_plan_ttl_seconds(plan: Dict[str, Any]) -> int:
    payload = plan if isinstance(plan, dict) else {}
    controller_tick = dict(payload.get("controller_tick") or {})
    configured_ttl = int(controller_tick.get("plan_ttl_seconds") or 0)
    if configured_ttl > 0:
        return configured_ttl
    return int(quartermaster_tick_policy().get("plan_ttl_seconds") or 0)


def quartermaster_plan_is_fresh(plan: Dict[str, Any]) -> bool:
    payload = plan if isinstance(plan, dict) else {}
    if not payload:
        return False
    status = quartermaster_plan_status(payload)
    if str(status.get("cache_state") or "").strip().lower() == "stale":
        return False
    ttl_seconds = max(0, quartermaster_plan_ttl_seconds(payload))
    generated_at = parse_iso(str(status.get("generated_at") or payload.get("generated_at") or ""))
    if generated_at and ttl_seconds > 0:
        age_seconds = max(0.0, (utc_now() - generated_at).total_seconds())
        if age_seconds > float(ttl_seconds):
            return False
    return True


def quartermaster_plan_is_authoritative(plan: Dict[str, Any]) -> bool:
    payload = plan if isinstance(plan, dict) else {}
    status = quartermaster_plan_status(payload)
    return (
        quartermaster_enforcement_enabled(payload)
        and quartermaster_plan_is_fresh(payload)
        and not bool(status.get("degraded"))
    )


def _quartermaster_plan_from_status_payload(payload: Dict[str, Any]) -> Dict[str, Any]:
    status_payload = payload if isinstance(payload, dict) else {}
    raw_plan = status_payload.get("plan")
    if isinstance(raw_plan, dict) and raw_plan:
        plan = dict(raw_plan)
    elif isinstance(status_payload, dict) and status_payload.get("lane_targets"):
        plan = dict(status_payload)
    else:
        return {}
    plan["_quartermaster_status"] = _quartermaster_status_metadata(status_payload)
    return plan


def _quartermaster_status_fallback_payload() -> Tuple[Dict[str, Any], Optional[dt.datetime]]:
    persisted_payload, persisted_fetched_at = load_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_STATUS)
    if isinstance(persisted_payload, dict) and persisted_payload:
        return persisted_payload, persisted_fetched_at
    legacy_plan, legacy_fetched_at = load_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_PLAN)
    if isinstance(legacy_plan, dict) and legacy_plan:
        return {
            "generated_at": str(legacy_plan.get("generated_at") or ""),
            "source_generated_at": "",
            "source": "persisted_capacity_plan",
            "degraded": False,
            "cache_state": "fresh",
            "tick_reason": "",
            "plan": legacy_plan,
        }, legacy_fetched_at
    return {}, None


def quartermaster_status_payload(force: bool = False) -> Dict[str, Any]:
    now = time.time()
    cached = _QUARTERMASTER_STATUS_CACHE.get("payload")
    cached_payload = cached if isinstance(cached, dict) else {}
    fetched_at = float(_QUARTERMASTER_STATUS_CACHE.get("fetched_at") or 0.0)
    if (
        not force
        and cached_payload
        and (now - fetched_at) < FLEET_QUARTERMASTER_CACHE_SECONDS
    ):
        return dict(cached_payload)

    persisted_payload, persisted_fetched_at = _quartermaster_status_fallback_payload()
    status_base_url = str(FLEET_QUARTERMASTER_BASE_URL).strip()
    if not status_base_url:
        if persisted_payload:
            cache_now = now
            if persisted_fetched_at is not None:
                cache_now = max(0.0, persisted_fetched_at.timestamp())
            _QUARTERMASTER_STATUS_CACHE["fetched_at"] = cache_now
            _QUARTERMASTER_STATUS_CACHE["payload"] = persisted_payload
            return dict(persisted_payload)
        return {}

    request = urllib.request.Request(
        f"{status_base_url}/api/status",
        headers={"User-Agent": "codex-fleet-controller"},
        method="GET",
    )
    try:
        with urllib.request.urlopen(request, timeout=3) as response:
            payload = json.loads(response.read().decode("utf-8"))
    except Exception:
        if persisted_payload:
            cache_now = now
            if persisted_fetched_at is not None:
                cache_now = max(0.0, persisted_fetched_at.timestamp())
            _QUARTERMASTER_STATUS_CACHE["fetched_at"] = cache_now
            _QUARTERMASTER_STATUS_CACHE["payload"] = persisted_payload
            return dict(persisted_payload)
        payload = {}

    payload = payload if isinstance(payload, dict) else {}
    _QUARTERMASTER_STATUS_CACHE["fetched_at"] = now
    _QUARTERMASTER_STATUS_CACHE["payload"] = payload
    if payload:
        save_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_STATUS, payload)
    return dict(payload)


def quartermaster_capacity_plan(force: bool = False) -> Dict[str, Any]:
    now = time.time()
    cached = _QUARTERMASTER_PLAN_CACHE.get("payload")
    cached_payload = cached if isinstance(cached, dict) else {}
    fetched_at = float(_QUARTERMASTER_PLAN_CACHE.get("fetched_at") or 0.0)
    if (
        not force
        and cached_payload
        and (now - fetched_at) < FLEET_QUARTERMASTER_CACHE_SECONDS
    ):
        return dict(cached_payload)

    persisted_payload, persisted_fetched_at = load_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_PLAN)
    status_payload = quartermaster_status_payload(force=force)
    plan = _quartermaster_plan_from_status_payload(status_payload)
    if not plan and isinstance(persisted_payload, dict) and persisted_payload:
        cache_now = now
        if persisted_fetched_at is not None:
            cache_now = max(0.0, persisted_fetched_at.timestamp())
        _QUARTERMASTER_PLAN_CACHE["fetched_at"] = cache_now
        _QUARTERMASTER_PLAN_CACHE["payload"] = persisted_payload
        return dict(persisted_payload)

    _QUARTERMASTER_PLAN_CACHE["fetched_at"] = now
    _QUARTERMASTER_PLAN_CACHE["payload"] = plan
    if plan:
        save_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_PLAN, plan)
    return dict(plan)


def quartermaster_capacity_tick(*, reason: str = "") -> Dict[str, Any]:
    status_base_url = str(FLEET_QUARTERMASTER_BASE_URL).strip()
    if not status_base_url:
        return quartermaster_capacity_plan(force=True)
    url = f"{status_base_url}/api/tick"
    clean_reason = str(reason or "").strip()
    if clean_reason:
        url = f"{url}?reason={urllib.parse.quote(clean_reason)}"
    request = urllib.request.Request(
        url,
        headers={"User-Agent": "codex-fleet-controller"},
        method="POST",
    )
    try:
        with urllib.request.urlopen(request, timeout=5) as response:
            payload = json.loads(response.read().decode("utf-8"))
    except Exception:
        return quartermaster_capacity_plan(force=True)

    payload = payload if isinstance(payload, dict) else {}
    plan = _quartermaster_plan_from_status_payload(payload)
    now = time.time()
    _QUARTERMASTER_STATUS_CACHE["fetched_at"] = now
    _QUARTERMASTER_STATUS_CACHE["payload"] = payload
    if payload:
        save_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_STATUS, payload)
    if plan:
        _QUARTERMASTER_PLAN_CACHE["fetched_at"] = now
        _QUARTERMASTER_PLAN_CACHE["payload"] = plan
        save_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_PLAN, plan)
    return plan


def quartermaster_target_lane_for_decision(decision: Dict[str, Any], task_meta: Optional[Dict[str, Any]]) -> str:
    clean_package_kind = str((task_meta or {}).get("package_kind") or "").strip().lower()
    if clean_package_kind == PACKAGE_COMPILE_PACKAGE_KIND:
        return "core_authority"
    lane = str(decision.get("lane") or "").strip().lower()
    if lane == "core":
        return "core_authority" if bool(decision.get("requires_contract_authority")) else "core_booster"
    if lane in {"core_authority", "core_booster", "core_rescue", "review_shard", "audit_shard", "jury", "review_light", "easy", "repair", "groundwork", "survival"}:
        if lane == "jury":
            return "audit_shard"
        if lane in {"easy", "repair", "groundwork", "survival"}:
            return lane
        return lane
    if task_meta and str(task_meta.get("workflow_kind") or "").strip().lower() == "groundwork_review_loop":
        return "review_shard"
    return lane


def quartermaster_managed_lane(target_lane: str) -> str:
    clean_lane = str(target_lane or "").strip().lower()
    return clean_lane if clean_lane in QUARTERMASTER_MANAGED_LANES else ""


def quartermaster_target_lane_from_runtime_record(
    config: Dict[str, Any],
    *,
    decision: Optional[Dict[str, Any]] = None,
    account_alias: str = "",
    job_kind: str = "coding",
    task_payload: Optional[Dict[str, Any]] = None,
) -> str:
    clean_job_kind = str(job_kind or "coding").strip().lower() or "coding"
    payload = task_payload if isinstance(task_payload, dict) else {}
    explicit_target_lane = str(payload.get("target_lane") or "").strip().lower()
    if explicit_target_lane in {"core_authority", "core_booster", "core_rescue", "review_shard", "audit_shard"}:
        return explicit_target_lane
    if clean_job_kind == "github_review":
        return "audit_shard"
    accounts_cfg = config.get("accounts") or {}
    alias = str(account_alias or "").strip()
    if clean_job_kind == "local_review":
        reviewer_lane = str(payload.get("reviewer_lane") or "").strip().lower()
        if reviewer_lane:
            return "audit_shard" if reviewer_lane == "jury" else "review_shard"
        inferred_lane = infer_account_lane(accounts_cfg.get(alias) or {}, alias=alias)
        return "audit_shard" if inferred_lane == "jury" else "review_shard"
    if isinstance(decision, dict) and decision:
        task_meta = dict(decision.get("task_meta") or {})
        return quartermaster_target_lane_for_decision(decision, task_meta)
    inferred_lane = infer_account_lane(accounts_cfg.get(alias) or {}, alias=alias)
    return quartermaster_target_lane_for_decision({"lane": inferred_lane}, None) if inferred_lane else ""


def quartermaster_active_lane_records(config: Dict[str, Any]) -> List[Dict[str, Any]]:
    records: List[Dict[str, Any]] = []
    counted_runtime_keys: set[str] = set()
    counted_run_ids: set[int] = set()
    latest_decisions = latest_spider_decision_by_project(limit=1000)
    for runtime_row_key, row in runtime_task_rows().items():
        if not persisted_runtime_task_active(runtime_row_key, row):
            continue
        payload = json_field(row.get("payload_json"), {})
        runtime_key = str(row.get("package_id") or runtime_row_key or "").strip()
        project_key = str(row.get("project_id") or runtime_row_key or "").strip()
        if runtime_key in counted_runtime_keys:
            continue
        decision = dict(payload.get("decision") or (latest_decisions.get(project_key) or {}).get("decision_meta") or {})
        target_lane = quartermaster_target_lane_from_runtime_record(
            config,
            decision=decision,
            account_alias=str(payload.get("account_alias") or ""),
            job_kind=str(row.get("task_kind") or "coding"),
            task_payload=payload,
        )
        records.append(
            {
                "runtime_key": runtime_key,
                "package_id": str(row.get("package_id") or "").strip(),
                "project_id": project_key,
                "target_lane": target_lane,
                "task_kind": str(row.get("task_kind") or "coding"),
                "task_state": str(row.get("task_state") or ""),
                "run_id": int(row.get("run_id") or 0) or None,
                "runtime_status": "",
                "slice_name": str(payload.get("slice_name") or ""),
                "scheduled_at": parse_iso(str(row.get("scheduled_at") or "")),
                "started_at": parse_iso(str(row.get("started_at") or "")),
            }
        )
        counted_runtime_keys.add(runtime_key)
        run_id = int(row.get("run_id") or 0)
        if run_id:
            counted_run_ids.add(run_id)
    if table_exists("projects"):
        with db() as conn:
            rows = conn.execute(
                """
                SELECT p.id,
                       p.status,
                       p.active_run_id,
                       p.current_slice,
                       r.package_id,
                       r.account_alias,
                       r.job_kind,
                       r.started_at AS run_started_at,
                       r.status AS run_status
                FROM projects p
                LEFT JOIN runs r ON r.id = p.active_run_id
                WHERE p.active_run_id IS NOT NULL
                   OR p.status IN ('starting', 'running', 'verifying')
                ORDER BY p.id
                """
            ).fetchall()
        for row in rows:
            project_id = str(row["id"] or "").strip()
            run_id = int(row["active_run_id"] or 0) or None
            runtime_key = str(row["package_id"] or "").strip() or project_id
            if project_uses_package_scheduler(config, project_id) and runtime_task_rows_for_project(project_id):
                continue
            if not project_id or runtime_key in counted_runtime_keys or (run_id and run_id in counted_run_ids):
                continue
            decision = dict((latest_decisions.get(project_id) or {}).get("decision_meta") or {})
            target_lane = quartermaster_target_lane_from_runtime_record(
                config,
                decision=decision,
                account_alias=str(row["account_alias"] or ""),
                job_kind=str(row["job_kind"] or "coding"),
            )
            records.append(
                {
                    "runtime_key": runtime_key,
                    "package_id": str(row["package_id"] or "").strip(),
                    "project_id": project_id,
                    "target_lane": target_lane,
                    "task_kind": str(row["job_kind"] or "coding"),
                    "task_state": "running",
                    "run_id": run_id,
                    "runtime_status": str(row["status"] or row["run_status"] or ""),
                    "slice_name": str(row["current_slice"] or ""),
                    "scheduled_at": None,
                    "started_at": parse_iso(str(row["run_started_at"] or "")),
                }
            )
            counted_runtime_keys.add(runtime_key)
            if run_id:
                counted_run_ids.add(run_id)
    return records


def quartermaster_active_lane_usage(config: Dict[str, Any]) -> Dict[str, int]:
    usage: Dict[str, int] = {}
    for record in quartermaster_active_lane_records(config):
        target_lane = quartermaster_managed_lane(record.get("target_lane") or "")
        if not target_lane:
            continue
        usage[target_lane] = int(usage.get(target_lane) or 0) + 1
    return usage


def quartermaster_useful_booster_work_count(
    config: Dict[str, Any],
    *,
    usage_by_lane: Optional[Dict[str, int]] = None,
) -> int:
    usage = usage_by_lane or quartermaster_active_lane_usage(config)
    active_booster_work = int(usage.get("core_booster") or 0)
    scoped_packages = work_package_scope_capacity()
    ready_package_work = 0
    for package in scoped_packages.get("ready_packages") or []:
        task_meta = dict(package.get("task_meta") or {})
        allowed_lanes = {
            str(item or "").strip().lower()
            for item in expand_serviceable_lanes(task_meta.get("allowed_lanes") or [], task_meta=task_meta, lanes=config.get("lanes"))
            if str(item or "").strip()
        }
        if bool(task_meta.get("allow_credit_burn")) and ("core" in allowed_lanes or "core_booster" in allowed_lanes):
            ready_package_work += 1
    queued_booster_work = quartermaster_queued_booster_work_count(config)
    return max(active_booster_work, ready_package_work, queued_booster_work)


def quartermaster_queued_booster_work_count(config: Dict[str, Any]) -> int:
    queued_booster_work = 0
    if not table_exists("projects"):
        return 0
    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, status, active_run_id, current_slice, queue_json, queue_index
            FROM projects
            ORDER BY id
            """
        ).fetchall()
    for row in rows:
        runtime_status = str(row["status"] or "").strip().lower()
        if bool(row["active_run_id"]) or runtime_status in ACTIVE_RUN_STATUSES | {"complete", "paused", SOURCE_BACKLOG_OPEN_STATUS}:
            continue
        queue = json_field(row["queue_json"], [])
        if not isinstance(queue, list):
            queue = []
        queue_index = max(0, int(row["queue_index"] or 0))
        item = (
            queue[queue_index]
            if queue_index < len(queue)
            else row["current_slice"]
            if runtime_status in {READY_STATUS, WAITING_CAPACITY_STATUS, "awaiting_account"}
            else None
        )
        task_meta = normalize_task_queue_item(item, lanes=config.get("lanes"))
        if not str(task_meta.get("title") or "").strip():
            continue
        allowed_lanes = {
            str(item or "").strip().lower()
            for item in expand_serviceable_lanes(task_meta.get("allowed_lanes") or [], task_meta=task_meta, lanes=config.get("lanes"))
            if str(item or "").strip()
        }
        if bool(task_meta.get("allow_credit_burn")) and ("core" in allowed_lanes or "core_booster" in allowed_lanes):
            queued_booster_work += 1
    return queued_booster_work


def quartermaster_package_allows_booster_lane(config: Dict[str, Any], package: Dict[str, Any]) -> bool:
    task_meta = dict(package.get("task_meta") or {})
    allowed_lanes = {
        str(item or "").strip().lower()
        for item in expand_serviceable_lanes(task_meta.get("allowed_lanes") or [], task_meta=task_meta, lanes=config.get("lanes"))
        if str(item or "").strip()
    }
    return bool(task_meta.get("allow_credit_burn")) and ("core" in allowed_lanes or "core_booster" in allowed_lanes)


def quartermaster_booster_package_supply_snapshot(
    config: Dict[str, Any],
    *,
    scope_capacity: Optional[Dict[str, Any]] = None,
    queued_booster_work: int = 0,
    sustainable_booster_cap: int = 0,
) -> Dict[str, Any]:
    scoped_packages = scope_capacity or work_package_scope_capacity()
    ready_booster_packages = sum(
        1
        for package in (scoped_packages.get("ready_packages") or [])
        if quartermaster_package_allows_booster_lane(config, package)
    )
    active_booster_packages = sum(
        1
        for package in (scoped_packages.get("active_packages") or [])
        if quartermaster_package_allows_booster_lane(config, package)
    )
    waiting_dependency_packages = sum(
        1
        for package in work_package_rows(statuses=["waiting_dependency"])
        if quartermaster_package_allows_booster_lane(config, package)
    )
    blocked_packages = sum(
        1
        for package in work_package_rows(statuses=["blocked", "failed"])
        if quartermaster_package_allows_booster_lane(config, package)
    )
    quartermaster_cfg = dict(config.get("quartermaster") or {})
    useful_work_cfg = dict(quartermaster_cfg.get("useful_work") or {})
    ready_reserve_multiplier = max(1, int(useful_work_cfg.get("ready_reserve_multiplier") or 2))
    minimum_ready_packages = max(0, int(useful_work_cfg.get("minimum_ready_packages") or 2))
    plane_caps = dict((((config.get("policies") or {}).get("capacity_plane") or {}).get("plane_caps")) or {})
    global_booster_cap = max(0, int(plane_caps.get("global_booster_cap") or 0))
    project_capacity_total = 0
    for project_cfg in config.get("projects") or []:
        if not project_booster_pool_contract(config, project_cfg):
            continue
        project_capacity_total += max(0, project_runtime_concurrency_cap(config, project_cfg))
    plan_sustainable_cap = max(0, int(sustainable_booster_cap or 0))
    if plan_sustainable_cap <= 0:
        current_plan = quartermaster_capacity_plan()
        plan_inputs = dict(current_plan.get("inputs") or {})
        plan_sustainable_cap = max(
            0,
            int(plan_inputs.get("sustainable_booster_cap") or current_plan.get("effective_booster_cap") or 0),
        )
    reserve_basis_candidates = [value for value in [plan_sustainable_cap, global_booster_cap, project_capacity_total] if value > 0]
    reserve_basis = min(reserve_basis_candidates) if reserve_basis_candidates else 0
    booster_work_present = bool(
        ready_booster_packages > 0
        or active_booster_packages > 0
        or waiting_dependency_packages > 0
        or blocked_packages > 0
        or int(queued_booster_work or 0) > 0
    )
    ready_work_reserve_target = 0
    if reserve_basis > 0 and booster_work_present:
        ready_work_reserve_target = max(minimum_ready_packages, reserve_basis * ready_reserve_multiplier)
    ready_work_reserve_shortfall = max(0, ready_work_reserve_target - ready_booster_packages)
    starved = bool(ready_work_reserve_shortfall > 0 and booster_work_present)
    return {
        "ready_booster_packages": ready_booster_packages,
        "active_booster_packages": active_booster_packages,
        "waiting_dependency_packages": waiting_dependency_packages,
        "blocked_packages": blocked_packages,
        "queued_booster_work": int(queued_booster_work or 0),
        "sustainable_booster_cap": plan_sustainable_cap,
        "ready_work_reserve_target": ready_work_reserve_target,
        "ready_work_reserve_shortfall": ready_work_reserve_shortfall,
        "starved": starved,
    }


def quartermaster_event_snapshot(config: Dict[str, Any]) -> Dict[str, Any]:
    now = utc_now()
    stale_seconds = max(300, int(get_policy(config, "stale_heartbeat_seconds", 1800)))
    open_incidents = 0
    if table_exists("incidents"):
        with db() as conn:
            row = conn.execute("SELECT COUNT(*) AS count FROM incidents WHERE status='open'").fetchone()
        open_incidents = int((row["count"] if row else 0) or 0)

    review_backpressure = 0
    if table_exists("pull_requests"):
        review_states = [
            LOCAL_REVIEW_PENDING_STATUS,
            REVIEW_LIGHT_PENDING_STATUS,
            AWAITING_FIRST_REVIEW_STATUS,
            JURY_REVIEW_PENDING_STATUS,
            JURY_REWORK_REQUIRED_STATUS,
        ]
        placeholders = ", ".join("?" for _ in review_states)
        with db() as conn:
            row = conn.execute(
                f"SELECT COUNT(*) AS count FROM pull_requests WHERE review_status IN ({placeholders})",
                tuple(review_states),
            ).fetchone()
        review_backpressure = int((row["count"] if row else 0) or 0)

    sponsor_ready_lanes = 0
    if table_exists("participant_lanes"):
        with db() as conn:
            participant_rows = conn.execute(
                """
                SELECT lane_id, auth_completed_at, telemetry_json
                FROM participant_lanes
                WHERE status IN ('pending_auth', 'active')
                """
            ).fetchall()
        for row in participant_rows:
            telemetry = json_field(row["telemetry_json"], {})
            auth_ready = bool(telemetry.get("auth_ready")) or bool(row["auth_completed_at"]) or participant_lane_auth_path(str(row["lane_id"] or "").strip()).exists()
            if auth_ready:
                sponsor_ready_lanes += 1

    stale_workers = 0
    if table_exists("projects"):
        with db() as conn:
            project_rows = conn.execute(
                """
                SELECT p.*,
                       r.started_at AS run_started_at,
                       r.log_path AS run_log_path,
                       r.status AS run_status
                FROM projects p
                LEFT JOIN runs r ON r.id = p.active_run_id
                WHERE p.status IN ('starting', 'running', 'verifying')
                ORDER BY p.id
                """
            ).fetchall()
        for row in project_rows:
            project_id = str(row["id"] or "").strip()
            if not project_id:
                continue
            with contextlib.suppress(KeyError):
                project_cfg = get_project_cfg(config, project_id)
                activity_at = latest_worker_activity_at(project_cfg, row, row)
                if activity_at and activity_at <= now - dt.timedelta(seconds=stale_seconds):
                    stale_workers += 1

    premium_queue_depth = 0
    for project_cfg in config.get("projects") or []:
        if not bool((project_cfg.get("participant_burst") or {}).get("enabled")):
            continue
        project_id = str(project_cfg.get("id") or "").strip()
        if not project_id:
            continue
        premium_queue_depth += int(participant_burst_metrics(config, project_id, project_cfg=project_cfg).get("premium_queue_depth") or 0)

    lane_capacities = ea_lane_capacity_snapshot(config.get("lanes") or {}) if (config.get("lanes") or {}) else {}
    core_snapshot = lane_capacities.get("core") or {}
    degraded_slots = sum(int((item or {}).get("degraded_slots") or 0) for item in core_snapshot.get("providers") or [])
    billing = dict(ea_onemin_manager_billing_aggregate() or {})
    participant_pool = quartermaster_participant_pool_snapshot(config, now=now)
    onemin_credit_waste_risk = quartermaster_onemin_credit_waste_risk(config, billing, participant_pool)
    usage = quartermaster_active_lane_usage(config)
    active_boosters = int(usage.get("core_booster") or 0)
    queued_booster_work = quartermaster_queued_booster_work_count(config)
    useful_booster_work = max(
        premium_queue_depth,
        active_boosters,
        queued_booster_work,
        quartermaster_useful_booster_work_count(config, usage_by_lane=usage),
    )
    scope_capacity = work_package_scope_capacity()
    current_plan = quartermaster_capacity_plan()
    current_plan_inputs = dict(current_plan.get("inputs") or {})
    current_sustainable_booster_cap = max(
        0,
        int(current_plan_inputs.get("sustainable_booster_cap") or current_plan.get("effective_booster_cap") or 0),
    )
    quartermaster_cfg = dict(config.get("quartermaster") or {})
    useful_work_cfg = dict(quartermaster_cfg.get("useful_work") or {})
    booster_supply = quartermaster_booster_package_supply_snapshot(
        config,
        scope_capacity=scope_capacity,
        queued_booster_work=queued_booster_work,
        sustainable_booster_cap=current_sustainable_booster_cap,
    )
    review_fabric_cfg = dict((((config.get("review_fabric") or {}).get("default") or {}).get("shards")) or {})
    audit_fabric_cfg = dict(((config.get("audit_fabric") or {}).get("default")) or {})
    plane_caps = dict((((config.get("policies") or {}).get("capacity_plane") or {}).get("plane_caps")) or {})
    project_contracts: List[Dict[str, Any]] = []
    for project_cfg in config.get("projects") or []:
        contract = project_booster_pool_contract(config, project_cfg)
        if not contract:
            continue
        project_contracts.append(
            {
                "project_id": str(project_cfg.get("id") or "").strip(),
                "pool": str(contract.get("pool") or "").strip(),
                "authority_lane": str(contract.get("authority_lane") or "").strip(),
                "booster_lane": str(contract.get("booster_lane") or "").strip(),
                "rescue_lane": str(contract.get("rescue_lane") or "").strip(),
                "project_safety_cap": max(0, int(contract.get("project_safety_cap") or 0)),
                "default_project_cap": max(0, int(contract.get("default_project_cap") or 0)),
                "hard_project_cap": max(0, int(contract.get("hard_project_cap") or 0)),
            }
        )
    project_contracts.sort(key=lambda item: (str(item.get("project_id") or ""), str(item.get("pool") or "")))

    return {
        "onemin_probe_delta": "|".join(
            [
                str(billing.get("basis_summary") or ""),
                str(billing.get("slot_count_with_billing_snapshot") or ""),
                str(billing.get("slot_count_with_member_reconciliation") or ""),
                str(billing.get("remaining_percent_total") or ""),
            ]
        ),
        "topup_eta_changed": "|".join(
            [
                str(billing.get("next_topup_at") or ""),
                str(billing.get("hours_until_next_topup") or ""),
            ]
        ),
        "review_backpressure": review_backpressure,
        "audit_debt": open_incidents,
        "booster_idle": 1 if active_boosters > 0 and useful_booster_work <= 0 else 0,
        "booster_supply_starved": json.dumps(
            booster_supply,
            sort_keys=True,
            separators=(",", ":"),
        ),
        "participant_pool_drainable": json.dumps(
            {
                "drainable": bool(participant_pool.get("drainable")),
                "ready_accounts": list(participant_pool.get("ready_accounts") or []),
            },
            sort_keys=True,
            separators=(",", ":"),
        ),
        "participant_pool_starved": 1 if participant_pool.get("starved") else 0,
        "participant_token_pool_invalid": json.dumps(
            list(participant_pool.get("invalid_accounts") or []),
            sort_keys=True,
            separators=(",", ":"),
        ),
        "participant_consent_missing": json.dumps(
            list(participant_pool.get("missing_consent_accounts") or []),
            sort_keys=True,
            separators=(",", ":"),
        ),
        "onemin_credit_waste_risk": 1 if onemin_credit_waste_risk else 0,
        "worker_no_progress": stale_workers,
        "slot_probe_stale": degraded_slots,
        "sponsor_lane_change": sponsor_ready_lanes,
        "capacity_contract_changed": json.dumps(
            {
                "plane_caps": {
                    str(key): int(max(0, float(value)))
                    for key, value in plane_caps.items()
                    if str(key).strip() and isinstance(value, (int, float, str))
                },
                "quartermaster": {
                    "mode": str(quartermaster_cfg.get("mode") or "").strip().lower(),
                    "max_scale_up_per_tick": max(0, int(quartermaster_cfg.get("max_scale_up_per_tick") or 0)),
                    "max_scale_down_per_tick": max(0, int(quartermaster_cfg.get("max_scale_down_per_tick") or 0)),
                    "plan_ttl_seconds": max(0, int(quartermaster_cfg.get("plan_ttl_seconds") or 0)),
                    "ready_reserve_multiplier": max(0, int(useful_work_cfg.get("ready_reserve_multiplier") or 0)),
                    "minimum_ready_packages": max(0, int(useful_work_cfg.get("minimum_ready_packages") or 0)),
                    "packages_per_authority_worker": max(0, int(useful_work_cfg.get("packages_per_authority_worker") or 0)),
                },
                "review_fabric": {
                    "service_floor": max(0, int(review_fabric_cfg.get("service_floor") or 0)),
                    "target_parallelism": max(0, int(review_fabric_cfg.get("target_parallelism") or 0)),
                    "max_queue_depth_per_active_reviewer": max(
                        0,
                        int(review_fabric_cfg.get("max_queue_depth_per_active_reviewer") or 0),
                    ),
                },
                "audit_fabric": {
                    "service_floor": max(0, int(audit_fabric_cfg.get("service_floor") or 0)),
                    "target_parallelism": max(0, int(audit_fabric_cfg.get("target_parallelism") or 0)),
                },
                "project_contracts": project_contracts,
            },
            sort_keys=True,
            separators=(",", ":"),
        ),
        "scope_ready_changed": json.dumps(
            {
                "scope_cap": max(0, int(scope_capacity.get("scope_cap") or 0)),
                "ready_scope_cap": max(0, int(scope_capacity.get("ready_scope_cap") or 0)),
                "active_packages": sorted(
                    str(row.get("package_id") or "").strip()
                    for row in (scope_capacity.get("active_packages") or [])
                    if str(row.get("package_id") or "").strip()
                ),
                "ready_packages": sorted(
                    str(row.get("package_id") or "").strip()
                    for row in (scope_capacity.get("ready_packages") or [])
                    if str(row.get("package_id") or "").strip()
                ),
            },
            sort_keys=True,
            separators=(",", ":"),
        ),
    }


def quartermaster_event_signature(policy: Dict[str, Any], snapshot: Dict[str, Any]) -> str:
    scoped = {
        str(trigger): snapshot.get(str(trigger))
        for trigger in policy.get("triggers") or []
    }
    return json.dumps(scoped, sort_keys=True, separators=(",", ":"))


def quartermaster_tick_if_due(config: Dict[str, Any]) -> Dict[str, Any]:
    policy = quartermaster_tick_policy()
    if not bool(policy.get("enabled", True)) or str(policy.get("driver") or "") != "controller_tick":
        return quartermaster_capacity_plan()
    now = time.time()
    if not float(_QUARTERMASTER_TICK_CACHE.get("last_tick_at") or 0.0) and not str(_QUARTERMASTER_TICK_CACHE.get("event_signature") or ""):
        persisted, _ = load_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_TICK_STATE)
        if isinstance(persisted, dict):
            _QUARTERMASTER_TICK_CACHE["last_tick_at"] = float(persisted.get("last_tick_at") or 0.0)
            _QUARTERMASTER_TICK_CACHE["event_signature"] = str(persisted.get("event_signature") or "")
    snapshot = quartermaster_event_snapshot(config)
    signature = quartermaster_event_signature(policy, snapshot)
    last_tick_at = float(_QUARTERMASTER_TICK_CACHE.get("last_tick_at") or 0.0)
    baseline_due = last_tick_at <= 0.0 or (now - last_tick_at) >= float(policy.get("baseline_tick_seconds") or 600)
    event_due = (
        bool(policy.get("triggers"))
        and signature != str(_QUARTERMASTER_TICK_CACHE.get("event_signature") or "")
        and (last_tick_at <= 0.0 or (now - last_tick_at) >= float(policy.get("event_tick_min_seconds") or 90))
    )
    if not baseline_due and not event_due:
        return quartermaster_capacity_plan()
    reason = "baseline" if baseline_due and not event_due else "event"
    plan = quartermaster_capacity_tick(reason=reason)
    tick_status = quartermaster_plan_status(plan)
    tick_accepted = bool(plan) and quartermaster_plan_is_fresh(plan) and not bool(tick_status.get("degraded"))
    if tick_accepted:
        _QUARTERMASTER_TICK_CACHE["last_tick_at"] = now
        _QUARTERMASTER_TICK_CACHE["event_signature"] = signature
        save_runtime_cache(
            RUNTIME_CACHE_KEY_QUARTERMASTER_TICK_STATE,
            {
                "last_tick_at": now,
                "event_signature": signature,
                "last_reason": reason,
                "snapshot": snapshot,
            },
        )
    return plan or quartermaster_capacity_plan()


def quartermaster_capacity_reconcile(
    config: Dict[str, Any],
    *,
    plan: Optional[Dict[str, Any]] = None,
    force: bool = False,
) -> Dict[str, Any]:
    resolved_plan = dict(plan or quartermaster_capacity_plan())
    lane_targets = {
        str(key): int(max(0, float(value)))
        for key, value in dict(resolved_plan.get("lane_targets") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    plan_generated_at = str(resolved_plan.get("generated_at") or "")
    now = time.time()
    cached_payload = _QUARTERMASTER_RECONCILE_CACHE.get("payload")
    if (
        not force
        and isinstance(cached_payload, dict)
        and cached_payload
        and str(_QUARTERMASTER_RECONCILE_CACHE.get("plan_generated_at") or "") == plan_generated_at
        and (now - float(_QUARTERMASTER_RECONCILE_CACHE.get("fetched_at") or 0.0)) < 5.0
    ):
        return dict(cached_payload)
    usage_by_lane = quartermaster_active_lane_usage(config)
    delta_by_lane = {
        lane: int(target) - int(usage_by_lane.get(lane) or 0)
        for lane, target in lane_targets.items()
    }
    remaining_by_lane = {
        lane: max(0, int(delta))
        for lane, delta in delta_by_lane.items()
    }
    over_target_by_lane = {
        lane: max(0, int(-delta))
        for lane, delta in delta_by_lane.items()
    }
    payload = {
        "generated_at": iso(utc_now()),
        "plan_generated_at": plan_generated_at,
        "lane_targets": lane_targets,
        "usage_by_lane": usage_by_lane,
        "delta_by_lane": delta_by_lane,
        "over_target_by_lane": over_target_by_lane,
        "remaining_by_lane": remaining_by_lane,
    }
    _QUARTERMASTER_RECONCILE_CACHE["fetched_at"] = now
    _QUARTERMASTER_RECONCILE_CACHE["plan_generated_at"] = plan_generated_at
    _QUARTERMASTER_RECONCILE_CACHE["payload"] = payload
    save_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_RECONCILE, payload)
    return dict(payload)


def _quartermaster_record_sort_key(record: Dict[str, Any]) -> Tuple[int, float, str]:
    task_state = str(record.get("task_state") or "").strip().lower()
    effective_started_at = record.get("started_at") if isinstance(record.get("started_at"), dt.datetime) else None
    effective_scheduled_at = record.get("scheduled_at") if isinstance(record.get("scheduled_at"), dt.datetime) else None
    effective_at = effective_scheduled_at if task_state == "scheduled" and effective_scheduled_at else effective_started_at or effective_scheduled_at
    return (
        0 if task_state == "scheduled" else 1,
        -(effective_at.timestamp() if effective_at is not None else 0.0),
        str(record.get("project_id") or ""),
    )


def quartermaster_capacity_drain(
    config: Dict[str, Any],
    *,
    plan: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    resolved_plan = dict(plan or quartermaster_capacity_plan())
    snapshot = quartermaster_capacity_reconcile(config, plan=resolved_plan)
    over_target_by_lane = {
        str(key): int(max(0, float(value)))
        for key, value in dict(snapshot.get("over_target_by_lane") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    if not quartermaster_plan_is_authoritative(resolved_plan):
        return {
            "authoritative": False,
            "cancelled_count": 0,
            "drained_projects": [],
            "over_target_by_lane": over_target_by_lane,
        }

    policy = quartermaster_tick_policy()
    remaining_budget = max(0, int(policy.get("max_scale_down_per_tick") or 0))
    if remaining_budget <= 0 or not any(int(value) > 0 for value in over_target_by_lane.values()):
        return {
            "authoritative": True,
            "cancelled_count": 0,
            "drained_projects": [],
            "over_target_by_lane": over_target_by_lane,
        }

    finding_types = {
        str(item.get("type") or "").strip().lower()
        for item in resolved_plan.get("typed_findings") or []
        if isinstance(item, dict) and str(item.get("type") or "").strip()
    }
    min_worker_dwell_seconds = max(0, int(policy.get("min_worker_dwell_seconds") or 0))
    idle_drain_seconds = max(0, int(policy.get("idle_drain_seconds") or 0))
    usage_by_lane = {
        str(key): int(max(0, float(value)))
        for key, value in dict(snapshot.get("usage_by_lane") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    lane_targets = {
        str(key): int(max(0, float(value)))
        for key, value in dict(snapshot.get("lane_targets") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    now = utc_now()
    drained_projects: List[str] = []
    active_records = quartermaster_active_lane_records(config)

    for lane_name, lane_surplus in sorted(over_target_by_lane.items()):
        if remaining_budget <= 0 or lane_surplus <= 0:
            continue
        lane_budget = min(remaining_budget, int(lane_surplus))
        dwell_seconds = min_worker_dwell_seconds
        if lane_name == "core_booster" and "booster_idle" in finding_types:
            dwell_seconds = max(dwell_seconds, idle_drain_seconds)
        lane_records = sorted(
            [record for record in active_records if str(record.get("target_lane") or "").strip() == lane_name],
            key=_quartermaster_record_sort_key,
        )
        for record in lane_records:
            if lane_budget <= 0 or remaining_budget <= 0:
                break
            task_state = str(record.get("task_state") or "").strip().lower()
            started_at = record.get("started_at") if isinstance(record.get("started_at"), dt.datetime) else None
            if task_state != "scheduled" and dwell_seconds > 0:
                if started_at is None or started_at > now - dt.timedelta(seconds=dwell_seconds):
                    continue
            project_id = str(record.get("project_id") or "").strip()
            package_id = str(record.get("package_id") or "").strip()
            runtime_key = str(record.get("runtime_key") or package_id or project_id).strip()
            if not project_id:
                continue
            with db() as conn:
                project_row = conn.execute("SELECT * FROM projects WHERE id=?", (project_id,)).fetchone()
            if not project_row:
                clear_runtime_task(runtime_key)
                continue
            message = (
                f"quartermaster drained {lane_name}: target={int(lane_targets.get(lane_name) or 0)} "
                f"usage={int(usage_by_lane.get(lane_name) or 0)}"
            )
            live_task = live_runtime_task_handle(runtime_key)
            if live_task is not None:
                _RUNTIME_INTERRUPT_OVERRIDES[runtime_key] = {
                    "paused": False,
                    "status": WAITING_CAPACITY_STATUS,
                    "cooldown_until": now + dt.timedelta(seconds=1),
                    "message": message,
                    "error_class": "capacity_drain",
                    "run_status": "abandoned",
                    "slice_name": str(record.get("slice_name") or current_slice(project_row) or ""),
                }
                cancel_requested = False
                try:
                    cancel_requested = bool(live_task.cancel())
                except Exception:
                    cancel_requested = False
                if not cancel_requested:
                    _RUNTIME_INTERRUPT_OVERRIDES.pop(runtime_key, None)
                    continue
            else:
                task_row = runtime_task_row(runtime_key)
                run_id = int((task_row or {}).get("run_id") or project_row["active_run_id"] or 0)
                task_state = str((task_row or {}).get("task_state") or "").strip().lower()
                run_row = None
                if run_id:
                    with db() as conn:
                        run_row = conn.execute(
                            "SELECT status, finished_at FROM runs WHERE id=?",
                            (run_id,),
                        ).fetchone()
                run_active = bool(
                    run_row
                    and str(run_row["status"] or "").strip().lower() in ACTIVE_RUN_STATUSES
                    and not parse_iso(run_row["finished_at"])
                )
                if run_id and not run_active and task_state != "scheduled":
                    if task_row:
                        clear_runtime_task(runtime_key)
                    continue
                finished_at = iso(now)
                if run_id:
                    with db() as conn:
                        conn.execute(
                            """
                            UPDATE runs
                            SET status='abandoned', finished_at=?, error_class='capacity_drain', error_message=?
                            WHERE id=?
                              AND status IN ('starting', 'running', 'verifying')
                            """,
                            (finished_at, message, run_id),
                        )
                clear_runtime_task(runtime_key)
                if package_id:
                    update_work_package_runtime(package_id, status=WAITING_CAPACITY_STATUS, runtime_state="idle")
                else:
                    update_project_status(
                        project_id,
                        status=WAITING_CAPACITY_STATUS,
                        current_slice=str(record.get("slice_name") or current_slice(project_row) or ""),
                        active_run_id=None,
                        cooldown_until=now + dt.timedelta(seconds=1),
                        last_run_at=now,
                        last_error=message,
                        consecutive_failures=0,
                        spider_tier=str(project_row["spider_tier"] or ""),
                        spider_model=str(project_row["spider_model"] or ""),
                        spider_reason=str(project_row["spider_reason"] or ""),
                    )
            drained_projects.append(project_id)
            lane_budget -= 1
            remaining_budget -= 1

    return {
        "authoritative": True,
        "cancelled_count": len(drained_projects),
        "drained_projects": drained_projects,
        "over_target_by_lane": over_target_by_lane,
    }


def quartermaster_capacity_snapshot(plan: Dict[str, Any]) -> Dict[str, Any]:
    plan_generated_at = str((plan or {}).get("generated_at") or "")
    cached_payload = _QUARTERMASTER_RECONCILE_CACHE.get("payload")
    if (
        isinstance(cached_payload, dict)
        and cached_payload
        and str(_QUARTERMASTER_RECONCILE_CACHE.get("plan_generated_at") or "") == plan_generated_at
    ):
        return dict(cached_payload)
    persisted_payload, persisted_fetched_at = load_runtime_cache(RUNTIME_CACHE_KEY_QUARTERMASTER_RECONCILE)
    if isinstance(persisted_payload, dict) and str(persisted_payload.get("plan_generated_at") or "") == plan_generated_at:
        cache_now = time.time()
        if persisted_fetched_at is not None:
            cache_now = max(0.0, persisted_fetched_at.timestamp())
        _QUARTERMASTER_RECONCILE_CACHE["fetched_at"] = cache_now
        _QUARTERMASTER_RECONCILE_CACHE["plan_generated_at"] = plan_generated_at
        _QUARTERMASTER_RECONCILE_CACHE["payload"] = persisted_payload
        return dict(persisted_payload)
    lane_targets = {
        str(key): int(max(0, float(value)))
        for key, value in dict((plan or {}).get("lane_targets") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    return {
        "generated_at": iso(utc_now()),
        "plan_generated_at": plan_generated_at,
        "lane_targets": lane_targets,
        "usage_by_lane": {},
        "delta_by_lane": dict(lane_targets),
        "over_target_by_lane": {lane: 0 for lane in lane_targets},
        "remaining_by_lane": dict(lane_targets),
    }


def quartermaster_capacity_remaining(
    *,
    plan: Dict[str, Any],
    target_lane: str,
    reserved_lane_counts: Optional[Dict[str, int]] = None,
) -> Tuple[int, Dict[str, int]]:
    snapshot = quartermaster_capacity_snapshot(plan)
    lane_targets = {
        str(key): int(max(0, float(value)))
        for key, value in dict(snapshot.get("remaining_by_lane") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    reserved = reserved_lane_counts or {}
    lane_remaining = {
        lane: max(0, int(value) - int(reserved.get(lane) or 0))
        for lane, value in lane_targets.items()
    }
    target = str(target_lane).strip().lower() or "core_booster"
    remaining = int(max(0, lane_remaining.get(target) or 0))
    return (remaining, lane_remaining)


def quartermaster_scale_up_cap(plan: Dict[str, Any]) -> int:
    payload = plan if isinstance(plan, dict) else {}
    return max(
        0,
        int(
            ((payload.get("controller_tick") or {}).get("max_scale_up_per_tick"))
            or quartermaster_tick_policy().get("max_scale_up_per_tick")
            or 1
        ),
    )


def quartermaster_lane_admission(
    config: Dict[str, Any],
    *,
    target_lane: str,
    plan: Optional[Dict[str, Any]] = None,
    reserved_lane_counts: Optional[Dict[str, int]] = None,
    reserved_scale_up_count: int = 0,
    refresh_if_due: bool = False,
    force_reconcile: bool = False,
    allow_missing_plan: bool = False,
) -> Dict[str, Any]:
    resolved_plan = dict(plan or {})
    if not resolved_plan:
        resolved_plan = dict((quartermaster_tick_if_due(config) if refresh_if_due else quartermaster_capacity_plan()) or {})
    qm_enforced = quartermaster_enforcement_enabled(resolved_plan)
    if not resolved_plan and allow_missing_plan:
        qm_enforced = False
    qm_authoritative = quartermaster_plan_is_authoritative(resolved_plan) if resolved_plan else False
    qm_status = quartermaster_plan_status(resolved_plan)
    qm_snapshot = (
        quartermaster_capacity_reconcile(config, plan=resolved_plan, force=True)
        if force_reconcile
        else quartermaster_capacity_snapshot(resolved_plan)
    )
    lane_targets = {
        str(key): int(max(0, float(value)))
        for key, value in dict(qm_snapshot.get("remaining_by_lane") or {}).items()
        if str(key).strip() and isinstance(value, (int, float, str))
    }
    reserved = {
        str(key): max(0, int(value))
        for key, value in dict(reserved_lane_counts or {}).items()
        if str(key).strip()
    }
    remaining_by_lane = {
        lane: max(0, int(value) - int(reserved.get(lane) or 0))
        for lane, value in lane_targets.items()
    }
    clean_target_lane = str(target_lane or "").strip().lower()
    managed_target_lane = quartermaster_managed_lane(clean_target_lane)
    if not managed_target_lane:
        return {
            "plan": resolved_plan,
            "snapshot": qm_snapshot,
            "status": qm_status,
            "enforced": qm_enforced,
            "authoritative": qm_authoritative,
            "scale_up_cap": quartermaster_scale_up_cap(resolved_plan),
            "target_lane": clean_target_lane,
            "remaining": 0,
            "remaining_by_lane": remaining_by_lane,
            "blocked": False,
            "blocker": "",
        }
    clean_target_lane = managed_target_lane
    remaining = int(max(0, remaining_by_lane.get(clean_target_lane) or 0))
    scale_up_cap = quartermaster_scale_up_cap(resolved_plan)
    blocker = ""
    if qm_enforced and not qm_authoritative:
        blocker = (
            "quartermaster blocked: plan is not authoritative"
            f" cache_state={str(qm_status.get('cache_state') or 'unknown')}"
            f" degraded={str(bool(qm_status.get('degraded'))).lower()}"
        )
    elif qm_authoritative and scale_up_cap >= 0 and reserved_scale_up_count >= scale_up_cap:
        blocker = (
            f"quartermaster blocked: max_scale_up_per_tick={scale_up_cap}"
            f" reserved_scale_up_count={reserved_scale_up_count}"
        )
    elif qm_authoritative and remaining <= 0:
        blocker = (
            f"quartermaster blocked: target_lane={clean_target_lane} remaining={remaining}"
            f" remaining_by_lane={json.dumps(remaining_by_lane, sort_keys=True)}"
        )
    return {
        "plan": resolved_plan,
        "snapshot": qm_snapshot,
        "status": qm_status,
        "enforced": qm_enforced,
        "authoritative": qm_authoritative,
        "scale_up_cap": scale_up_cap,
        "target_lane": clean_target_lane,
        "remaining": remaining,
        "remaining_by_lane": remaining_by_lane,
        "blocked": bool(blocker),
        "blocker": blocker,
    }


def quartermaster_enforcement_enabled(plan: Dict[str, Any]) -> bool:
    mode = str((plan or {}).get("mode") or "").strip().lower() or quartermaster_config_mode()
    return mode in {"enforce", "active", "authoritative"}


def participant_burst_credit_guard_status(
    policy: Dict[str, Any],
    *,
    sponsor_ready_lanes: int,
    cache_only: bool = False,
) -> Dict[str, Any]:
    guard = dict(policy.get("credit_guard") or {})
    result: Dict[str, Any] = {
        "enabled": bool(guard.get("enabled", False)),
        "provider": str(guard.get("provider") or "onemin").strip().lower() or "onemin",
        "require_survive_until_next_topup": bool(guard.get("require_survive_until_next_topup", True)),
        "minimum_headroom_hours": max(0.0, float_or_none(guard.get("minimum_headroom_hours")) or 0.0),
        "billing_known": False,
        "survives_until_topup": None,
        "next_worker_safe": False,
        "hours_until_next_topup": None,
        "hours_remaining_at_current_pace_no_topup": None,
        "slot_count_with_billing_snapshot": 0,
        "slot_count_with_member_reconciliation": 0,
        "balanced_total_slots": 0,
        "balanced_additional_slots": 0,
        "balanced_active_cap": max(0, int(policy.get("max_active_workers") or 0)),
        "reason": "disabled",
    }
    if not result["enabled"]:
        return result
    if result["provider"] not in {"onemin", "1min", "1min.ai", "oneminai"}:
        result["reason"] = "unsupported_provider"
        return result
    aggregate = dict(ea_onemin_manager_billing_aggregate(cache_only=cache_only) or {})
    if not aggregate:
        result["reason"] = "billing_aggregate_missing"
        return result
    result["hours_until_next_topup"] = float_or_none(aggregate.get("hours_until_next_topup"))
    result["hours_remaining_at_current_pace_no_topup"] = float_or_none(
        aggregate.get("hours_remaining_at_current_pace_no_topup")
    )
    result["slot_count_with_billing_snapshot"] = max(
        0,
        int(float_or_none(aggregate.get("slot_count_with_billing_snapshot")) or 0),
    )
    result["slot_count_with_member_reconciliation"] = max(
        0,
        int(float_or_none(aggregate.get("slot_count_with_member_reconciliation")) or 0),
    )
    current_slots = max(
        result["slot_count_with_billing_snapshot"],
        result["slot_count_with_member_reconciliation"],
    )
    if (
        result["hours_until_next_topup"] is None
        or result["hours_remaining_at_current_pace_no_topup"] is None
        or current_slots <= 0
    ):
        result["reason"] = "billing_aggregate_incomplete"
        return result
    target_hours = float(result["hours_until_next_topup"]) + float(result["minimum_headroom_hours"])
    result["billing_known"] = True
    if target_hours <= 0:
        result["survives_until_topup"] = True
        result["next_worker_safe"] = True
        result["reason"] = "topup_due_now"
        return result
    survives = float(result["hours_remaining_at_current_pace_no_topup"]) >= target_hours
    result["survives_until_topup"] = survives
    if not survives:
        result["reason"] = "depletes_before_topup"
        return result
    ratio = float(result["hours_remaining_at_current_pace_no_topup"]) / target_hours
    balanced_total_slots = max(0, int(math.floor(ratio * current_slots)))
    additional_slots = max(0, balanced_total_slots - current_slots)
    result["balanced_total_slots"] = balanced_total_slots
    result["balanced_additional_slots"] = additional_slots
    result["next_worker_safe"] = additional_slots > 0
    result["balanced_active_cap"] = max(
        int(policy.get("max_active_workers") or 0),
        max(0, int(sponsor_ready_lanes)) + additional_slots,
    )
    result["reason"] = "survives_until_topup" if result["next_worker_safe"] else "balanced_drain_reached"
    return result


def ea_lane_capacity_snapshot(lanes: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    payload = ea_codex_profiles()
    provider_registry = dict(payload.get("provider_registry") or {})
    registry_profiles = {
        str(item.get("profile") or "").strip(): dict(item)
        for item in provider_registry.get("lanes") or []
        if str(item.get("profile") or "").strip()
    }
    profiles = {
        str(item.get("profile") or "").strip(): dict(item)
        for item in payload.get("profiles") or []
        if str(item.get("profile") or "").strip()
    }
    providers = dict(((payload.get("provider_health") or {}).get("providers")) or {})
    snapshots: Dict[str, Dict[str, Any]] = {}
    normalized = normalize_lanes_config(lanes)
    for lane_name in normalized:
        profile_name = EA_PROFILE_NAME_BY_LANE.get(lane_name, lane_name)
        registry_profile = registry_profiles.get(profile_name, {})
        if registry_profile:
            provider_hints = list(registry_profile.get("provider_hint_order") or ((normalized.get(lane_name) or {}).get("provider_hint_order") or []))
            provider_rows: List[Dict[str, Any]] = []
            for provider in registry_profile.get("providers") or []:
                provider_payload = dict(provider or {})
                capacity = dict(provider_payload.get("capacity") or {})
                slot_pool = dict(provider_payload.get("slot_pool") or {})
                provider_rows.append(
                    {
                        "provider_key": str(provider_payload.get("provider_key") or "").strip(),
                        "backend": str(provider_payload.get("backend") or provider_payload.get("provider_key") or "").strip(),
                        "state": str(provider_payload.get("state") or capacity.get("state") or "unknown").strip() or "unknown",
                        "remaining_percent_of_max": capacity.get("remaining_percent_of_max"),
                        "estimated_hours_remaining_at_current_pace": capacity.get("estimated_hours_remaining_at_current_pace"),
                        "estimated_burn_credits_per_hour": capacity.get("estimated_burn_credits_per_hour"),
                        "estimated_remaining_credits_total": capacity.get("estimated_remaining_credits_total"),
                        "max_requests_per_hour": capacity.get("max_requests_per_hour"),
                        "max_credits_per_hour": capacity.get("max_credits_per_hour"),
                        "max_credits_per_day": capacity.get("max_credits_per_day"),
                        "detail": str(provider_payload.get("detail") or capacity.get("detail") or "").strip(),
                        "configured_slots": int(slot_pool.get("configured_slots") or 0),
                        "ready_slots": int(slot_pool.get("ready_slots") or 0),
                        "degraded_slots": int(slot_pool.get("degraded_slots") or 0),
                        "leased_slots": int(slot_pool.get("leased_slots") or 0),
                        "slot_owners": list(slot_pool.get("owners") or []),
                        "lease_holders": list(slot_pool.get("lease_holders") or []),
                        "selection_mode": str(slot_pool.get("selection_mode") or "").strip(),
                    }
                )
            capacity_summary = dict(registry_profile.get("capacity_summary") or {})
            primary_state = str(capacity_summary.get("state") or (provider_rows[0]["state"] if provider_rows else "unknown")).strip() or "unknown"
            snapshots[lane_name] = {
                "lane": lane_name,
                "profile": profile_name,
                "model": str(registry_profile.get("public_model") or "").strip(),
                "brain": str(registry_profile.get("brain") or registry_profile.get("public_model") or "").strip(),
                "backend": str(registry_profile.get("backend") or "").strip(),
                "health_provider_key": str(registry_profile.get("health_provider_key") or "").strip(),
                "provider_hint_order": provider_hints,
                "primary_provider_key": str(registry_profile.get("primary_provider_key") or "").strip(),
                "state": primary_state,
                "providers": provider_rows,
                "review_required": bool(registry_profile.get("review_required")),
                "merge_policy": str(registry_profile.get("merge_policy") or "").strip(),
                "capacity_summary": capacity_summary,
                "provider_registry_contract": str(provider_registry.get("contract_name") or "").strip(),
            }
            continue
        profile = profiles.get(profile_name, {})
        provider_hints = list(profile.get("provider_hint_order") or ((normalized.get(lane_name) or {}).get("provider_hint_order") or []))
        provider_rows: List[Dict[str, Any]] = []
        for provider_key in provider_hints:
            provider_payload = dict(providers.get(provider_key) or {})
            provider_rows.append(
                {
                    "provider_key": provider_key,
                    "state": provider_slot_state(provider_payload),
                    "remaining_percent_of_max": provider_payload.get("remaining_percent_of_max"),
                    "estimated_hours_remaining_at_current_pace": provider_payload.get("estimated_hours_remaining_at_current_pace"),
                    "estimated_burn_credits_per_hour": provider_payload.get("estimated_burn_credits_per_hour"),
                    "estimated_remaining_credits_total": provider_payload.get("estimated_remaining_credits_total"),
                    "max_requests_per_hour": provider_payload.get("max_requests_per_hour"),
                    "max_credits_per_hour": provider_payload.get("max_credits_per_hour"),
                    "max_credits_per_day": provider_payload.get("max_credits_per_day"),
                    "detail": str(provider_payload.get("detail") or "").strip(),
                }
            )
        primary_state = provider_rows[0]["state"] if provider_rows else "unknown"
        fallback_ready = any(str(item.get("state") or "") == "ready" for item in provider_rows[1:])
        lane_state = "fallback_ready" if primary_state != "ready" and fallback_ready else primary_state
        snapshots[lane_name] = {
            "lane": lane_name,
            "profile": profile_name,
            "model": str(profile.get("model") or "").strip(),
            "brain": str(profile.get("model") or "").strip(),
            "backend": str(profile.get("backend") or "").strip(),
            "health_provider_key": str(profile.get("health_provider_key") or "").strip(),
            "provider_hint_order": provider_hints,
            "state": lane_state,
            "providers": provider_rows,
            "review_required": bool(profile.get("review_required")),
            "merge_policy": str(profile.get("merge_policy") or "").strip(),
        }
    return snapshots


def lane_snapshot_remaining_percent(snapshot: Dict[str, Any]) -> Optional[float]:
    providers = snapshot.get("providers") or []
    for provider in providers:
        value = provider.get("remaining_percent_of_max")
        try:
            if value is None:
                continue
            return float(value)
        except Exception:
            continue
    return None


def lane_capacity_available(snapshot: Dict[str, Any]) -> bool:
    state = str(snapshot.get("state") or "").strip().lower()
    if state not in {"ready", "fallback_ready"}:
        return False
    declared_backend = str(snapshot.get("backend") or "").strip().lower()
    if declared_backend:
        provider_hints = {
            str(item or "").strip().lower()
            for item in (snapshot.get("provider_hint_order") or [])
            if str(item or "").strip()
        }
        live_provider_keys = {
            str(item.get("provider_key") or item.get("backend") or "").strip().lower()
            for item in (snapshot.get("providers") or [])
            if isinstance(item, dict) and str(item.get("provider_key") or item.get("backend") or "").strip()
        }
        if provider_hints and declared_backend not in provider_hints and declared_backend not in live_provider_keys:
            return False
    return True


def lane_capacity_tight(snapshot: Dict[str, Any]) -> bool:
    remaining = lane_snapshot_remaining_percent(snapshot)
    if remaining is None:
        return False
    return remaining <= EA_ONEMIN_TIGHT_PERCENT


def reviewer_runtime_model_for_lane(lanes: Dict[str, Any], reviewer_lane: str) -> str:
    lane_cfg = normalize_lanes_config(lanes).get(str(reviewer_lane or "").strip().lower()) or {}
    return str(lane_cfg.get("runtime_model") or "").strip()


def ordered_lane_preferences(tier_prefs: Dict[str, Any], allowed_lanes: List[str]) -> List[str]:
    configured = [str(item).strip().lower() for item in tier_prefs.get("lane_preferences") or [] if str(item).strip()]
    ordered = [lane for lane in configured if lane in allowed_lanes]
    ordered.extend(lane for lane in allowed_lanes if lane not in ordered)
    return ordered or list(allowed_lanes)


def lane_allowance_burn_snapshot(lane_name: str, lanes: Dict[str, Any], lane_snapshot: Dict[str, Any]) -> Dict[str, Any]:
    lane_cfg = normalize_lanes_config(lanes).get(str(lane_name or "").strip().lower()) or {}
    provider = next(iter(lane_snapshot.get("providers") or []), {})
    return {
        "lane": str(lane_name or "").strip().lower(),
        "profile": EA_PROFILE_NAME_BY_LANE.get(str(lane_name or "").strip().lower(), str(lane_name or "").strip().lower()),
        "budget_bias": str(lane_cfg.get("budget_bias") or "standard").strip().lower(),
        "capacity_state": str(lane_snapshot.get("state") or "").strip().lower(),
        "provider": str(provider.get("provider_key") or "").strip(),
        "remaining_percent_of_max": provider.get("remaining_percent_of_max"),
        "estimated_hours_remaining_at_current_pace": provider.get("estimated_hours_remaining_at_current_pace"),
    }


def why_not_cheaper_lane(
    selected_lane: str,
    *,
    allowed_lanes: List[str],
    tier: str,
    escalation_reason: str,
    requires_contract_authority: bool,
    task_meta: Dict[str, Any],
    lane_snapshots: Dict[str, Any],
) -> str:
    lane = str(selected_lane or "").strip().lower()
    if lane == "easy":
        return "easy is already the cheapest eligible lane"
    if lane == "repair":
        if "easy" not in allowed_lanes:
            return "easy is not allowed by task policy"
        if not lane_capacity_available(lane_snapshots.get("easy") or {}):
            return "easy lane capacity is unavailable"
        return "repair is the cheapest implementation lane for bounded code changes"
    if lane == "groundwork":
        if bool(task_meta.get("groundwork_required")):
            return "groundwork is explicitly required by task policy"
        if tier == "groundwork":
            return "groundwork fits slow analysis better than cheaper coding lanes"
        if "easy" not in allowed_lanes and "repair" not in allowed_lanes:
            return "easy and repair are disallowed by task policy"
        if not any(lane_capacity_available(lane_snapshots.get(name) or {}) for name in ("easy", "repair") if name in allowed_lanes):
            return "easy and repair capacity are unavailable"
        return "groundwork is the cheapest eligible analysis lane"
    if lane == "core":
        if escalation_reason == "participant_premium_required":
            return "participant-sponsored premium burst is explicitly required for this slice"
        if escalation_reason == "participant_premium_burst_pressure":
            return "participant-sponsored premium burst was opened because cheap lanes are under pressure"
        if bool(task_meta.get("protected_runtime")):
            return "protected_runtime forces core authority"
        if requires_contract_authority:
            return "protected or merge-ready work requires a high-authority implementation pass"
        if str(task_meta.get("risk_level") or "").strip().lower() in {"medium", "high"}:
            return "risk policy rejected cheaper lanes"
        if tier in {"multi_file_impl", "cross_repo_contract"}:
            return "scope is too broad for cheap implementation lanes"
        if "easy" not in allowed_lanes and "repair" not in allowed_lanes:
            return "easy and repair are not allowed by task policy"
        if not any(lane_capacity_available(lane_snapshots.get(name) or {}) for name in ("easy", "repair") if name in allowed_lanes):
            return "easy and repair capacity are unavailable"
        return "core is the only eligible implementation lane after cheaper lanes were rejected"
    if lane == "jury":
        return "jury is reserved for final signoff, landing authority, or contradiction resolution"
    if lane == "survival":
        if escalation_reason == "capacity_exhausted_survival_fallback":
            return "primary lanes were unavailable, so survival is the emergency fallback"
        return "survival is only used when cheaper primary lanes cannot carry the slice"
    return "lane selected by current route policy"


def decision_requires_serial_review(project_cfg: Dict[str, Any], decision: Dict[str, Any]) -> bool:
    review = project_review_policy(project_cfg)
    lane = str(decision.get("lane") or "").strip().lower()
    reviewer_lane = str(decision.get("required_reviewer_lane") or "").strip().lower()
    task_meta = dict(decision.get("task_meta") or {})
    acceptance_level = str((task_meta.get("acceptance_level")) or "").strip().lower()
    signoff_requirements = [str(item).strip() for item in task_meta.get("signoff_requirements") or [] if str(item).strip()]
    forced_review = lane in {"easy", "repair", "groundwork", "survival"} or bool(signoff_requirements)
    if forced_review:
        return True
    if not (bool(review.get("enabled", True)) and bool(review.get("required_before_queue_advance", True))):
        return False
    return (
        reviewer_lane and reviewer_lane != lane
    ) or acceptance_level in {"reviewed", "merge_ready"}


def encode_review_focus(
    base_focus: str,
    *,
    reviewer_lane: str,
    reviewer_model: str,
    metadata: Optional[Dict[str, Any]] = None,
) -> str:
    parts = [str(base_focus or "").strip()]
    if reviewer_lane:
        parts.append(f"reviewer_lane={reviewer_lane}")
    if reviewer_model:
        parts.append(f"reviewer_model={reviewer_model}")
    for key, value in (metadata or {}).items():
        clean_key = str(key or "").strip()
        clean_value = str(value or "").strip()
        if clean_key and clean_value:
            parts.append(f"{clean_key}={clean_value}")
    return REVIEW_METADATA_SEPARATOR.join(part for part in parts if part)


def decode_review_focus(raw_focus: str) -> Tuple[str, Dict[str, str]]:
    focus_parts: List[str] = []
    metadata: Dict[str, str] = {}
    for part in str(raw_focus or "").split(REVIEW_METADATA_SEPARATOR):
        clean = str(part or "").strip()
        if not clean:
            continue
        if "=" in clean:
            key, value = clean.split("=", 1)
            if value.strip():
                metadata[key] = value.strip()
                continue
        focus_parts.append(clean)
    return REVIEW_METADATA_SEPARATOR.join(focus_parts).strip(), metadata


def review_slice_key(slice_name: str) -> str:
    return re.sub(r"[^a-z0-9._-]+", "-", str(slice_name or "").strip().lower()).strip("-") or "slice"


def metadata_flag(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    return str(value or "").strip().lower() in {"1", "true", "yes", "on"}


def task_final_reviewer_lane(task_meta: Dict[str, Any]) -> str:
    landing_lane = str(task_meta.get("landing_lane") or "").strip().lower()
    if landing_lane:
        return landing_lane
    final_lane = str(task_meta.get("final_reviewer_lane") or "").strip().lower()
    if final_lane:
        return final_lane
    if metadata_flag(task_meta.get("jury_acceptance_required")):
        return "jury"
    return str(task_meta.get("required_reviewer_lane") or "core").strip().lower() or "core"


def review_focus_final_reviewer_lane(metadata: Dict[str, Any]) -> str:
    landing_lane = str(metadata.get("landing_lane") or "").strip().lower()
    if landing_lane:
        return landing_lane
    final_lane = str(metadata.get("final_reviewer_lane") or "").strip().lower()
    if final_lane:
        return final_lane
    if metadata_flag(metadata.get("jury_acceptance_required")):
        return "jury"
    return str(metadata.get("reviewer_lane") or metadata.get("required_reviewer_lane") or "core").strip().lower() or "core"


def review_round_for_dispatch(task_meta: Dict[str, Any], *, execution_lane: str) -> int:
    workflow_kind = str(task_meta.get("workflow_kind") or "default").strip().lower()
    current_round = int(task_meta.get("review_round") or 0)
    if workflow_kind != WORKFLOW_KIND_GROUNDWORK_REVIEW_LOOP:
        return max(1, current_round or 1)
    if str(execution_lane or "").strip().lower() == "core":
        return max(1, current_round or int(task_meta.get("core_rescue_after_round") or 1) or 1)
    return max(1, current_round + 1)


def reviewer_lane_for_dispatch(task_meta: Dict[str, Any], *, execution_lane: str) -> str:
    reviewer_lane = str(task_meta.get("required_reviewer_lane") or "core").strip().lower() or "core"
    if str(task_meta.get("workflow_kind") or "default").strip().lower() != WORKFLOW_KIND_GROUNDWORK_REVIEW_LOOP:
        return reviewer_lane
    if str(execution_lane or "").strip().lower() == "core":
        return task_final_reviewer_lane(task_meta)
    return reviewer_lane


def local_review_target_lane(pr_row: Optional[Dict[str, Any]]) -> Tuple[str, str]:
    _, metadata = decode_review_focus(str((pr_row or {}).get("review_focus") or ""))
    reviewer_lane = str(metadata.get("reviewer_lane") or metadata.get("required_reviewer_lane") or "core").strip().lower() or "core"
    return ("audit_shard" if reviewer_lane == "jury" else "review_shard", reviewer_lane)


def review_focus_metadata(task_meta: Dict[str, Any], *, slice_name: str) -> Dict[str, str]:
    metadata: Dict[str, str] = {"slice_key": review_slice_key(slice_name)}
    for key in (
        "workflow_kind",
        "review_round",
        "max_review_rounds",
        "first_review_required",
        "jury_acceptance_required",
        "allow_credit_burn",
        "allow_paid_fast_lane",
        "allow_core_rescue",
        "core_rescue_after_round",
        "final_reviewer_lane",
        "landing_lane",
    ):
        value = task_meta.get(key)
        if value in (None, "", False):
            continue
        metadata[key] = str(value).strip().lower() if isinstance(value, bool) else str(value).strip()
    return metadata


def accepted_loop_review_status(review_round: int, *, core_used: bool) -> str:
    if core_used:
        return ACCEPTED_AFTER_CORE_STATUS
    round_key = str(max(1, min(int(review_round or 1), 3)))
    return ACCEPTED_AFTER_ROUND_STATUSES.get(round_key, ACCEPTED_AFTER_ROUND_STATUSES["3"])


def review_workflow_kind(pr_row: Optional[Dict[str, Any]] = None) -> str:
    pr = pr_row or {}
    workflow_kind = str(pr.get("workflow_kind") or "").strip().lower()
    if workflow_kind:
        return workflow_kind
    _, metadata = decode_review_focus(str(pr.get("review_focus") or ""))
    return str(metadata.get("workflow_kind") or "default").strip().lower() or "default"


def review_loop_stage(pr_row: Optional[Dict[str, Any]]) -> Optional[str]:
    pr = pr_row or {}
    if review_workflow_kind(pr) != WORKFLOW_KIND_GROUNDWORK_REVIEW_LOOP:
        return None
    review_status = str(pr.get("review_status") or "").strip().lower()
    if review_status in {
        AWAITING_FIRST_REVIEW_STATUS,
        REVIEW_LIGHT_PENDING_STATUS,
        JURY_REVIEW_PENDING_STATUS,
        JURY_REWORK_REQUIRED_STATUS,
        CORE_RESCUE_PENDING_STATUS,
        MANUAL_HOLD_STATUS,
        BLOCKED_CREDIT_BURN_DISABLED_STATUS,
        ACCEPTED_AFTER_CORE_STATUS,
        *ACCEPTED_AFTER_ROUND_STATUSES.values(),
    }:
        return review_status
    review_round = int(pr.get("review_round") or pr.get("local_review_attempts") or 0)
    # review_round tracks the requested/active loop round, not a completed review pass.
    first_review_complete = bool(pr.get("first_review_complete_at"))
    _, metadata = decode_review_focus(str(pr.get("review_focus") or ""))
    reviewer_lane = str(metadata.get("reviewer_lane") or "").strip().lower()
    final_reviewer_lane = review_focus_final_reviewer_lane(metadata)
    jury_acceptance_required = metadata_flag(metadata.get("jury_acceptance_required"))
    if review_status == LOCAL_REVIEW_PENDING_STATUS:
        if reviewer_lane and reviewer_lane == final_reviewer_lane and jury_acceptance_required:
            return JURY_REVIEW_PENDING_STATUS
        return AWAITING_FIRST_REVIEW_STATUS if not first_review_complete else REVIEW_LIGHT_PENDING_STATUS
    if review_status in {"review_fix_required", JURY_REWORK_REQUIRED_STATUS}:
        if bool(pr.get("needs_core_rescue")):
            return CORE_RESCUE_PENDING_STATUS
        return JURY_REWORK_REQUIRED_STATUS
    if review_status == REVIEW_FALLBACK_CLEAN_STATUS:
        accepted_on_round = str(pr.get("accepted_on_round") or "").strip().lower()
        if accepted_on_round == "core":
            return ACCEPTED_AFTER_CORE_STATUS
        if accepted_on_round in ACCEPTED_AFTER_ROUND_STATUSES:
            return ACCEPTED_AFTER_ROUND_STATUSES[accepted_on_round]
    return None


def project_workflow_stage(
    task_meta: Dict[str, Any],
    pr_row: Optional[Dict[str, Any]],
    runtime_status: Optional[str],
) -> Optional[str]:
    if str(task_meta.get("workflow_kind") or "default").strip().lower() != WORKFLOW_KIND_GROUNDWORK_REVIEW_LOOP:
        return None
    stage = review_loop_stage(pr_row)
    if stage:
        return stage
    status = str(runtime_status or "").strip().lower()
    if status in {READY_STATUS, "starting", "running", "verifying"}:
        if bool((pr_row or {}).get("needs_core_rescue")):
            return CORE_RESCUE_PENDING_STATUS
        return GROUNDWORK_PENDING_STATUS
    return None


def choose_review_account_alias(
    config: Dict[str, Any],
    project_cfg: Dict[str, Any],
    *,
    reviewer_lane: str,
) -> Optional[str]:
    preferred_review_aliases = review_account_preferences(project_cfg, reviewer_lane=reviewer_lane)
    ordered_aliases = ordered_project_aliases(project_cfg)
    for alias in preferred_review_aliases:
        clean_alias = str(alias or "").strip()
        if clean_alias and clean_alias not in ordered_aliases:
            ordered_aliases.append(clean_alias)
    ordered_aliases = reorder_aliases_with_preference(
        ordered_aliases,
        preferred_review_aliases,
    )
    ordered_aliases.extend(
        alias
        for alias in shared_lane_fallback_aliases(config, project_cfg, target_lanes=[reviewer_lane])
        if alias not in ordered_aliases
    )
    accounts_cfg = config.get("accounts") or {}
    now = utc_now()
    for alias in ordered_aliases:
        account_cfg = accounts_cfg.get(alias) or {}
        if infer_account_lane(account_cfg, alias=alias) != reviewer_lane:
            continue
        with db() as conn:
            row = conn.execute("SELECT * FROM accounts WHERE alias=?", (alias,)).fetchone()
        if not row:
            continue
        if account_runtime_state(row, account_cfg, now) != "ready":
            continue
        return alias
    return None


def decision_meta_summary(meta: Dict[str, Any]) -> str:
    if not meta:
        return ""
    parts: List[str] = []
    if meta.get("lane"):
        lane = str(meta.get("lane") or "")
        submode = str(meta.get("lane_submode") or "")
        parts.append(f"lane={lane}{f'/{submode}' if submode else ''}")
    if meta.get("selected_profile"):
        parts.append(f"profile={meta['selected_profile']}")
    if meta.get("escalation_reason"):
        parts.append(f"why={meta['escalation_reason']}")
    if meta.get("why_not_cheaper"):
        parts.append(f"cheaper={meta['why_not_cheaper']}")
    if meta.get("predicted_changed_files") is not None:
        parts.append(f"files={meta['predicted_changed_files']}")
    if meta.get("feedback_count") is not None:
        parts.append(f"feedback={meta['feedback_count']}")
    if "spark_eligible" in meta:
        parts.append("spark=yes" if meta.get("spark_eligible") else "spark=no")
    if meta.get("requires_contract_authority"):
        parts.append("contract=yes")
    if meta.get("operator_override_required"):
        parts.append("operator=yes")
    lane_capacity = meta.get("lane_capacity") or {}
    if lane_capacity:
        state = str(lane_capacity.get("state") or "").strip()
        if state:
            parts.append(f"capacity={state}")
        remaining = lane_snapshot_remaining_percent(lane_capacity) if isinstance(lane_capacity, dict) else None
        if remaining is not None:
            parts.append(f"remain={remaining:.1f}%")
    if meta.get("required_reviewer_lane"):
        parts.append(f"reviewer={meta['required_reviewer_lane']}")
    if meta.get("final_reviewer_lane"):
        parts.append(f"final={meta['final_reviewer_lane']}")
    signoff_requirements = [str(item).strip() for item in meta.get("signoff_requirements") or [] if str(item).strip()]
    if signoff_requirements:
        parts.append(f"signoff={'+'.join(signoff_requirements[:3])}")
    return ", ".join(parts)


def selection_trace_summary(trace: List[Dict[str, Any]]) -> str:
    selected = next((item for item in trace if item.get("state") == "selected"), None)
    selected_summary = ""
    if isinstance(selected, dict):
        lane = str(selected.get("requested_lane") or selected.get("lane") or "").strip()
        submode = str(selected.get("lane_submode") or "").strip()
        reason = str(selected.get("escalation_reason") or "").strip()
        selected_summary = ", ".join(
            part for part in [f"lane={lane}{f'/{submode}' if submode else ''}" if lane else "", f"why={reason}" if reason else ""] if part
        )
    skipped: List[str] = []
    for item in trace:
        if item.get("state") == "selected":
            continue
        alias = str(item.get("alias") or "?")
        reason = str(item.get("reason") or item.get("state") or "skipped")
        skipped.append(f"{alias}: {reason}")
    if not skipped:
        return selected_summary
    summary = "; ".join(skipped[:2])
    if len(skipped) > 2:
        summary = f"{summary}; +{len(skipped) - 2} more"
    return "; ".join(part for part in [selected_summary, summary] if part)


def hydrate_spider_decision(row: Dict[str, Any]) -> Dict[str, Any]:
    item = dict(row)
    meta = json_field(item.get("decision_meta_json"), {})
    trace = json_field(item.get("selection_trace_json"), [])
    item["decision_meta"] = meta if isinstance(meta, dict) else {}
    item["selection_trace"] = trace if isinstance(trace, list) else []
    item["decision_meta_summary"] = decision_meta_summary(item["decision_meta"])
    item["selection_trace_summary"] = selection_trace_summary(item["selection_trace"])
    item["skipped_alias_count"] = len([entry for entry in item["selection_trace"] if entry.get("state") != "selected"])
    return item


def latest_spider_decision_by_project(limit: int = 400) -> Dict[str, Dict[str, Any]]:
    if not table_exists("spider_decisions"):
        return {}
    with db() as conn:
        rows = conn.execute("SELECT * FROM spider_decisions ORDER BY id DESC LIMIT ?", (limit,)).fetchall()
    latest: Dict[str, Dict[str, Any]] = {}
    for row in rows:
        project_id = str(row["project_id"] or "").strip()
        if not project_id or project_id in latest:
            continue
        latest[project_id] = hydrate_spider_decision(dict(row))
    return latest


