def publish_project_audit_candidate_runtime(
    config: Dict[str, Any],
    candidate_row: sqlite3.Row,
    *,
    queue_mode: str = "append",
    source: str = "auto",
) -> bool:
    if str(candidate_row["scope_type"] or "") != "project":
        return False
    try:
        project_cfg = get_project_cfg(config, str(candidate_row["scope_id"]))
    except KeyError:
        return False

    project_id = str(project_cfg["id"])
    finding = audit_finding_row(str(candidate_row["scope_type"]), str(candidate_row["scope_id"]), str(candidate_row["finding_key"]))
    task_meta = audit_task_candidate_meta(candidate_row)
    overlay_path = merge_queue_overlay_item(
        project_cfg,
        audit_candidate_queue_overlay_item(candidate_row, task_meta),
        mode=queue_mode,
    )

    feedback_dir = pathlib.Path(project_cfg["path"]) / project_cfg.get("feedback_dir", "feedback")
    feedback_dir.mkdir(parents=True, exist_ok=True)
    note_path = feedback_dir / feedback_filename(f"audit-task-{candidate_row['id']}")
    note_lines = [
        "# Auditor Publication",
        "",
        f"Date: {utc_now().date().isoformat()}",
        f"Candidate ID: {candidate_row['id']}",
        f"Scope: {candidate_row['scope_type']}:{candidate_row['scope_id']}",
        f"Finding Key: {candidate_row['finding_key']}",
        f"Source: {source}",
        "",
        "## Task",
        f"- Title: {candidate_row['title']}",
        f"- Detail: {candidate_row['detail']}",
        "",
    ]
    if finding:
        note_lines.extend(
            [
                "## Finding",
                f"- Severity: {finding['severity']}",
                f"- Title: {finding['title']}",
                f"- Summary: {finding['summary']}",
                "",
            ]
        )
    note_lines.extend(
        [
            "## Publication",
            f"- Queue overlay: {overlay_path}",
            f"- Queue mode: {queue_mode}",
            "",
            "This task was published from the fleet auditor flow.",
        ]
    )
    note_path.write_text("\n".join(note_lines) + "\n", encoding="utf-8")

    with db() as conn:
        row = conn.execute("SELECT * FROM projects WHERE id=?", (project_id,)).fetchone()
    if row:
        update_project_status(
            project_id,
            status=READY_STATUS,
            current_slice=row["current_slice"],
            active_run_id=None,
            cooldown_until=None,
            last_run_at=parse_iso(row["last_run_at"]),
            last_error=None,
            consecutive_failures=0,
            spider_tier=row["spider_tier"],
            spider_model=row["spider_model"],
            spider_reason=row["spider_reason"],
        )

    project_groups = project_group_defs(config, project_id)
    if project_groups:
        group_id = str(project_groups[0].get("id") or "")
        upsert_group_runtime(group_id, signoff_state="open", mark_refill_requested=True)
        log_group_publish_event(
            group_id,
            source=source,
            source_scope_type="project",
            source_scope_id=project_id,
            finding_key=str(candidate_row["finding_key"] or ""),
            candidate_id=int(candidate_row["id"]),
            published_targets=[
                {
                    "target_type": "project",
                    "target_id": project_id,
                    "queue_overlay": str(overlay_path),
                    "feedback_note": str(note_path),
                }
            ],
        )
        log_group_run(
            group_id,
            run_kind="publish",
            phase="proposed_tasks",
            status="published",
            member_projects=[project_id],
            details={
                "source_scope_type": "project",
                "source_scope_id": project_id,
                "candidate_id": int(candidate_row["id"]),
                "finding_key": str(candidate_row["finding_key"] or ""),
                "queue_mode": queue_mode,
            },
        )
    set_audit_candidate_status(int(candidate_row["id"]), "published", resolved=True)
    return True


def publish_group_audit_candidate_runtime(
    config: Dict[str, Any],
    candidate_row: sqlite3.Row,
    *,
    source: str = "auto",
) -> bool:
    if str(candidate_row["scope_type"] or "") != "group":
        return False
    group_id = str(candidate_row["scope_id"] or "").strip()
    group_ids = {str(group.get("id")) for group in config.get("project_groups") or []}
    if not group_id or group_id not in group_ids:
        return False
    finding = audit_finding_row("group", group_id, str(candidate_row["finding_key"]))
    published_root = group_published_root(group_id)
    feedback_root = group_feedback_root(group_id)
    published_root.mkdir(parents=True, exist_ok=True)
    feedback_root.mkdir(parents=True, exist_ok=True)

    files_written: List[Dict[str, Any]] = []
    group_cfg = next((item for item in config.get("project_groups") or [] if str(item.get("id") or "") == group_id), {})
    member_projects = [str(project_id).strip() for project_id in (group_cfg.get("projects") or []) if str(project_id).strip()]
    blockers_path = published_root / "GROUP_BLOCKERS.md"
    blockers_path.write_text(render_group_blockers_markdown(group_id, candidate_row, finding, config), encoding="utf-8")
    files_written.append({"target_type": "group", "target_id": group_id, "path": str(blockers_path), "file_count": 1})

    finding_key = str(candidate_row["finding_key"] or "")
    detail_lower = f"{finding_key} {candidate_row['title']} {candidate_row['detail']}".lower()
    if "contract" in detail_lower or "session" in detail_lower or "dto" in detail_lower or "explain" in detail_lower:
        contract_path = published_root / "CONTRACT_SETS.yaml"
        contract_path.write_text(render_group_contract_sets_yaml(group_id, candidate_row, config), encoding="utf-8")
        files_written.append({"target_type": "group", "target_id": group_id, "path": str(contract_path), "file_count": 1})
    if "milestone" in detail_lower or "scope" in detail_lower or "coverage" in detail_lower:
        milestone_path = published_root / "PROGRAM_MILESTONES.generated.yaml"
        milestone_path.write_text(render_group_program_milestones_yaml(group_id, candidate_row, finding, config), encoding="utf-8")
        files_written.append({"target_type": "group", "target_id": group_id, "path": str(milestone_path), "file_count": 1})

    if len(member_projects) == 1:
        project_id = member_projects[0]
        try:
            project_cfg = get_project_cfg(config, project_id)
        except KeyError:
            project_cfg = None
        if project_cfg:
            overlay_path = merge_queue_overlay_item(
                project_cfg,
                audit_candidate_queue_overlay_item(candidate_row),
                mode="append",
            )
            files_written.append({"target_type": "project", "target_id": project_id, "path": str(overlay_path), "file_count": 1})
            with db() as conn:
                row = conn.execute("SELECT * FROM projects WHERE id=?", (project_id,)).fetchone()
            if row and not row["active_run_id"]:
                update_project_status(
                    project_id,
                    status=READY_STATUS,
                    current_slice=row["current_slice"],
                    active_run_id=None,
                    cooldown_until=None,
                    last_run_at=parse_iso(row["last_run_at"]),
                    last_error=None,
                    consecutive_failures=0,
                    spider_tier=row["spider_tier"],
                    spider_model=row["spider_model"],
                    spider_reason=row["spider_reason"],
                )

    note_path = feedback_root / feedback_filename(f"group-audit-task-{candidate_row['id']}")
    note_lines = [
        "# Group Auditor Publication",
        "",
        f"Date: {utc_now().date().isoformat()}",
        f"Candidate ID: {candidate_row['id']}",
        f"Group: {group_id}",
        f"Finding Key: {candidate_row['finding_key']}",
        f"Source: {source}",
        "",
        "## Task",
        f"- Title: {candidate_row['title']}",
        f"- Detail: {candidate_row['detail']}",
    ]
    if finding:
        note_lines.extend(
            [
                "",
                "## Finding",
                f"- Severity: {finding['severity']}",
                f"- Title: {finding['title']}",
                f"- Summary: {finding['summary']}",
            ]
        )
    note_lines.extend(
        [
            "",
            "## Published Targets",
            *[f"- {item['path']}" for item in files_written],
        ]
    )
    note_path.write_text("\n".join(note_lines) + "\n", encoding="utf-8")
    files_written.append({"target_type": "group", "target_id": group_id, "path": str(note_path), "file_count": 1})

    upsert_group_runtime(group_id, signoff_state="open", mark_refill_requested=True)
    log_group_publish_event(
        group_id,
        source=source,
        source_scope_type="group",
        source_scope_id=group_id,
        finding_key=str(candidate_row["finding_key"] or ""),
        candidate_id=int(candidate_row["id"]),
        published_targets=files_written,
    )
    log_group_run(
        group_id,
        run_kind="publish",
        phase="proposed_tasks",
        status="published",
        member_projects=member_projects,
        details={
            "source_scope_type": "group",
            "source_scope_id": group_id,
            "candidate_id": int(candidate_row["id"]),
            "finding_key": str(candidate_row["finding_key"] or ""),
        },
    )
    set_audit_candidate_status(int(candidate_row["id"]), "published", resolved=True)
    return True


def auto_publish_approved_audit_candidates(config: Dict[str, Any]) -> int:
    if not table_exists("audit_task_candidates"):
        return 0
    with db() as conn:
        project_rows = {row["id"]: row for row in conn.execute("SELECT * FROM projects ORDER BY id").fetchall()}
        candidate_rows = conn.execute(
            """
            SELECT *
            FROM audit_task_candidates
            WHERE status IN ('open', 'approved')
               OR (status='published' AND resolved_at IS NULL)
            ORDER BY CASE status WHEN 'open' THEN 0 WHEN 'approved' THEN 1 ELSE 2 END,
                     CASE scope_type WHEN 'group' THEN 0 ELSE 1 END,
                     scope_id,
                     last_seen_at ASC,
                     task_index ASC
            """
        ).fetchall()
    if not candidate_rows:
        return 0

    published = 0
    registry = load_program_registry(config)
    runtime_rows = group_runtime_rows()
    for candidate in candidate_rows:
        recommended = audit_task_candidate_is_recommended(candidate)
        scope_type = str(candidate["scope_type"] or "").strip()
        scope_id = str(candidate["scope_id"] or "").strip()
        candidate_status = str(candidate["status"] or "").strip().lower()
        category = audit_task_candidate_category(candidate)
        category_auto_heal = auto_heal_category_enabled(
            config,
            category,
            project_id=scope_id if scope_type == "project" else None,
            group_id=scope_id if scope_type == "group" else None,
        )
        if not recommended and not category_auto_heal:
            continue
        if candidate_status == "open" and not recommended:
            continue
        if scope_type == "group":
            if candidate_status == "published":
                continue
            group_cfg = next((item for item in config.get("project_groups") or [] if str(item.get("id")) == scope_id), None)
            if not group_cfg:
                continue
            group_meta = effective_group_meta(group_cfg, registry, runtime_rows)
            if group_is_signed_off(group_meta):
                continue
            project_ids = [str(project_id).strip() for project_id in (group_cfg.get("projects") or []) if str(project_id).strip()]
            if any(project_has_runtime_task(project_id) for project_id in project_ids) and not (recommended and len(project_ids) > 1):
                continue
            if recommended:
                if publish_audit_candidate_via_admin(int(candidate["id"])):
                    published += 1
                continue
            if audit_task_candidate_meta(candidate).get("bootstrap_project"):
                continue
            if publish_group_audit_candidate_runtime(config, candidate, source="auto"):
                published += 1
            continue

        if scope_type != "project":
            continue
        row = project_rows.get(scope_id)
        if not row or project_has_runtime_task(scope_id):
            continue
        queue = json.loads(row["queue_json"] or "[]")
        queue_exhausted = int(row["queue_index"] or 0) >= len(queue)
        try:
            project_cfg = get_project_cfg(config, scope_id)
        except KeyError:
            continue
        overlay_items = queue_overlay_items(project_cfg)
        candidate_text = audit_candidate_queue_text(candidate)
        overlay_has_candidate = candidate_text in overlay_items if candidate_text else False
        project_groups = project_group_defs(config, scope_id)
        if project_groups:
            group_cfg = project_groups[0]
            group_meta = effective_group_meta(group_cfg, registry, runtime_rows)
            if group_is_signed_off(group_meta):
                continue
            member_ids = [str(project_id).strip() for project_id in (group_cfg.get("projects") or []) if str(project_id).strip()]
            if any(project_has_runtime_task(member_id) for member_id in member_ids):
                continue
        if recommended:
            if publish_audit_candidate_via_admin(int(candidate["id"])):
                published += 1
            continue
        if audit_task_candidate_meta(candidate).get("bootstrap_project"):
            continue
        project_status = str(row["status"] or "").strip()
        can_rehydrate_published_candidate = (
            candidate_status == "published"
            and queue_exhausted
            and not overlay_has_candidate
            and project_status in {"complete", SOURCE_BACKLOG_OPEN_STATUS, HEALING_STATUS, QUEUE_REFILLING_STATUS}
        )
        if candidate_status == "published" and not can_rehydrate_published_candidate:
            continue
        queue_mode = "prepend" if candidate_status == "published" else "append"
        if publish_project_audit_candidate_runtime(config, candidate, queue_mode=queue_mode, source="auto"):
            published += 1
    return published


def reconcile_abandoned_runs(config: Optional[Dict[str, Any]] = None) -> None:
    cfg = config or normalize_config()
    max_failures = int(get_policy(cfg, "max_consecutive_failures", 3))
    recovery_failure_cap = max(0, max_failures - 1)
    now_dt = utc_now()
    now = iso(now_dt)
    with db() as conn:
        rows = conn.execute(
            """
            SELECT p.id,
                   p.status,
                   p.current_slice,
                   p.queue_index,
                   p.active_run_id,
                   p.consecutive_failures,
                   rt.package_id AS runtime_task_package_id,
                   rt.task_state
            FROM projects p
            LEFT JOIN runtime_tasks rt ON rt.project_id = p.id AND rt.task_state='running'
            WHERE p.status IN ('starting', 'running', 'verifying')
            ORDER BY p.id
            """
        ).fetchall()
        conn.execute(
            "UPDATE runs SET status='abandoned', finished_at=COALESCE(finished_at, ?) WHERE status IN ('starting', 'running', 'verifying')",
            (now,),
        )
        conn.execute(
            """
            UPDATE projects
            SET status=?,
                active_run_id=NULL,
                consecutive_failures=CASE
                    WHEN consecutive_failures IS NULL THEN 0
                    WHEN consecutive_failures > ? THEN ?
                    ELSE consecutive_failures
                END,
                updated_at=?
            WHERE status IN ('starting', 'running', 'verifying')
            """,
            (READY_STATUS, recovery_failure_cap, recovery_failure_cap, now),
        )
        if table_exists("runtime_tasks"):
            conn.execute(
                """
                UPDATE runtime_tasks
                SET task_state='scheduled',
                    run_id=NULL,
                    started_at=NULL,
                    updated_at=?
                WHERE task_state='running'
                """,
                (now,),
            )
    for row in rows:
        project_id = str(row["id"] or "").strip()
        if not project_id:
            continue
        run_id = int(row["active_run_id"] or 0) or None
        record_project_auto_requeue(
            project_id,
            trigger="abandoned_run_rehydrated",
            reason="controller restart or process loss requeued the active runtime task for rehydration",
            current_slice=row["current_slice"],
            run_id=run_id,
            queue_index=int(row["queue_index"] or 0),
            package_id=str(row["runtime_task_package_id"] or "").strip() or None,
            previous_status=str(row["status"] or "").strip(),
            next_status=READY_STATUS,
            evidence={
                "recovered_at": now,
                "recovery_failure_cap": recovery_failure_cap,
                "runtime_task_requeued": bool(row["runtime_task_package_id"]),
                "task_state_before_requeue": str(row["task_state"] or "").strip(),
                "abandoned_run_id": run_id,
            },
        )
    reconcile_stuck_work_package_runtime_links()
    save_runtime_task_cache_snapshot()


def latest_worker_activity_at(project_cfg: Dict[str, Any], project_row: sqlite3.Row, run_row: Optional[sqlite3.Row]) -> Optional[dt.datetime]:
    timestamps: List[dt.datetime] = []
    state_payload = read_state_file(project_cfg["path"], project_cfg.get("state_file") or ".agent-state.json")
    if isinstance(state_payload, dict):
        heartbeat_at = parse_iso(str(state_payload.get("updated_at_utc") or "").strip())
        if heartbeat_at:
            timestamps.append(heartbeat_at)
    if "last_run_at" in project_row.keys():
        last_run_at = parse_iso(project_row["last_run_at"])
        if last_run_at:
            timestamps.append(last_run_at)
    if run_row:
        if "run_started_at" in run_row.keys():
            started_at = parse_iso(run_row["run_started_at"])
        elif "started_at" in run_row.keys():
            started_at = parse_iso(run_row["started_at"])
        else:
            started_at = None
        if started_at:
            timestamps.append(started_at)
        log_path_text = ""
        if "run_log_path" in run_row.keys():
            log_path_text = str(run_row["run_log_path"] or "").strip()
        elif "log_path" in run_row.keys():
            log_path_text = str(run_row["log_path"] or "").strip()
        if log_path_text:
            log_path = pathlib.Path(log_path_text)
            if log_path.exists():
                timestamps.append(dt.datetime.fromtimestamp(log_path.stat().st_mtime, tz=UTC))
    return max(timestamps) if timestamps else None


def latest_run_activity_at(run_row: sqlite3.Row) -> Optional[dt.datetime]:
    timestamps: List[dt.datetime] = []
    if "run_started_at" in run_row.keys():
        started_at = parse_iso(run_row["run_started_at"])
    elif "started_at" in run_row.keys():
        started_at = parse_iso(run_row["started_at"])
    else:
        started_at = None
    if started_at:
        timestamps.append(started_at)
    log_path_text = ""
    if "run_log_path" in run_row.keys():
        log_path_text = str(run_row["run_log_path"] or "").strip()
    elif "log_path" in run_row.keys():
        log_path_text = str(run_row["log_path"] or "").strip()
    if log_path_text:
        log_path = pathlib.Path(log_path_text)
        if log_path.exists():
            timestamps.append(dt.datetime.fromtimestamp(log_path.stat().st_mtime, tz=UTC))
    return max(timestamps) if timestamps else None


def reconcile_orphaned_active_runs(config: Dict[str, Any]) -> int:
    grace_seconds = max(300, int(get_policy(config, "orphaned_runtime_grace_seconds", 300) or 300))
    max_failures = int(get_policy(config, "max_consecutive_failures", 3))
    recovery_failure_cap = max(0, max_failures - 1)
    now = utc_now()
    with db() as conn:
        rows = conn.execute(
            """
            SELECT p.*,
                   r.id AS run_id,
                   r.job_kind AS run_job_kind,
                   r.status AS run_status,
                   r.started_at AS run_started_at,
                   r.finished_at AS run_finished_at,
                   r.log_path AS run_log_path,
                   r.final_message_path AS run_final_message_path
            FROM projects p
            LEFT JOIN runs r ON r.id = p.active_run_id
            WHERE p.active_run_id IS NOT NULL
               OR p.status IN ('starting', 'running', 'verifying')
            ORDER BY p.id
            """
        ).fetchall()
        unlinked_rows = conn.execute(
            """
            SELECT p.*,
                   r.id AS run_id,
                   r.job_kind AS run_job_kind,
                   r.status AS run_status,
                   r.started_at AS run_started_at,
                   r.finished_at AS run_finished_at,
                   r.log_path AS run_log_path,
                   r.final_message_path AS run_final_message_path
            FROM runs r
            JOIN projects p ON p.id = r.project_id
            WHERE r.status IN ('starting', 'running', 'verifying')
              AND r.finished_at IS NULL
              AND CAST(COALESCE(p.active_run_id, 0) AS INTEGER) <> r.id
            ORDER BY r.id
            """
        ).fetchall()
    recovered = 0
    for row in rows:
        project_id = str(row["id"] or "").strip()
        if not project_id or live_runtime_task_handle(project_id) is not None:
            continue
        task_row = runtime_task_row(project_id)
        task_state = str((task_row or {}).get("task_state") or "").strip().lower()
        if task_state == "scheduled":
            continue
        run_id = int(row["run_id"] or 0)
        run_status = str(row["run_status"] or "").strip().lower()
        project_status = str(row["status"] or "").strip().lower()
        run_finished_at = parse_iso(row["run_finished_at"])
        if run_status not in ACTIVE_RUN_STATUSES and project_status not in ACTIVE_RUN_STATUSES:
            continue
        if run_id and run_finished_at is not None:
            continue
        try:
            project_cfg = get_project_cfg(config, project_id)
        except KeyError:
            if task_row:
                clear_runtime_task(project_id)
            continue
        activity_at = latest_worker_activity_at(project_cfg, row, row)
        if activity_at and activity_at > now - dt.timedelta(seconds=grace_seconds):
            continue
        anchor_at = activity_at or parse_iso(row["run_started_at"]) or parse_iso(row["last_run_at"]) or now
        stale_age_seconds = int(max(0, (now - anchor_at).total_seconds()))
        task_kind = str((task_row or {}).get("task_kind") or row["run_job_kind"] or "coding").strip().lower() or "coding"
        reason = f"controller lost {task_kind} supervision and saw no heartbeat or log activity for {stale_age_seconds}s"
        run_state = "review_failed" if task_kind == "local_review" else "failed"
        if run_id:
            with db() as conn:
                conn.execute(
                    """
                    UPDATE runs
                    SET status=?,
                        finished_at=COALESCE(finished_at, ?),
                        error_class='orphaned_runtime',
                        error_message=COALESCE(error_message, ?)
                    WHERE id=?
                      AND status IN ('starting', 'running', 'verifying')
                    """,
                    (run_state, iso(now), reason, run_id),
                )
        if task_row:
            clear_runtime_task(project_id)
        failures = int(row["consecutive_failures"] or 0)
        if task_kind == "local_review":
            next_status = review_hold_status_for_project(project_id, project_cfg=project_cfg, pr_row=pull_request_row(project_id))
        else:
            failures += 1
            if failures > recovery_failure_cap:
                failures = recovery_failure_cap
            next_status = "blocked" if failures >= max_failures else READY_STATUS
        update_project_status(
            project_id,
            status=next_status,
            current_slice=row["current_slice"],
            active_run_id=None,
            cooldown_until=now + dt.timedelta(seconds=1),
            last_run_at=now,
            last_error=reason,
            consecutive_failures=failures,
            spider_tier=row["spider_tier"],
            spider_model=row["spider_model"],
            spider_reason=row["spider_reason"],
        )
        if next_status == READY_STATUS:
            record_project_auto_requeue(
                project_id,
                trigger="orphaned_runtime_requeued",
                reason=reason,
                current_slice=row["current_slice"],
                run_id=run_id,
                queue_index=int(row["queue_index"] or 0),
                previous_status=str(row["status"] or "").strip(),
                next_status=next_status,
                evidence={
                    "recovered_at": iso(now),
                    "stale_age_seconds": stale_age_seconds,
                    "task_kind": task_kind,
                    "activity_anchor_at": iso(anchor_at),
                    "activity_last_seen_at": iso(activity_at) if activity_at else "",
                },
            )
        recovered += 1
    if recovered:
        reconcile_stuck_work_package_runtime_links()
    recovered_unlinked = 0
    for row in unlinked_rows:
        project_id = str(row["id"] or "").strip()
        run_id = int(row["run_id"] or 0)
        if not project_id or run_id <= 0:
            continue
        task_row = runtime_task_row(project_id)
        task_run_id = int((task_row or {}).get("run_id") or 0)
        if task_run_id == run_id and live_runtime_task_handle(project_id) is not None:
            continue
        run_status = str(row["run_status"] or "").strip().lower()
        if run_status not in ACTIVE_RUN_STATUSES:
            continue
        run_finished_at = parse_iso(row["run_finished_at"])
        if run_finished_at is not None:
            continue
        activity_at = latest_run_activity_at(row)
        if activity_at and activity_at > now - dt.timedelta(seconds=grace_seconds):
            continue
        anchor_at = activity_at or parse_iso(row["run_started_at"]) or now
        stale_age_seconds = int(max(0, (now - anchor_at).total_seconds()))
        reason = f"run is no longer linked from project.active_run_id and saw no log activity for {stale_age_seconds}s"
        with db() as conn:
            conn.execute(
                """
                UPDATE runs
                SET status='failed',
                    finished_at=COALESCE(finished_at, ?),
                    error_class='orphaned_runtime',
                    error_message=COALESCE(error_message, ?)
                WHERE id=?
                  AND status IN ('starting', 'running', 'verifying')
                """,
                (iso(now), reason, run_id),
            )
        if task_run_id == run_id:
            clear_runtime_task(project_id)
        recovered_unlinked += 1
    recovered += recovered_unlinked
    if recovered_unlinked:
        reconcile_stuck_work_package_runtime_links()
    return recovered


def reconcile_stale_worker_sessions(config: Dict[str, Any]) -> int:
    stale_seconds = max(300, int(get_policy(config, "stale_heartbeat_seconds", 1800)))
    max_failures = int(get_policy(config, "max_consecutive_failures", 3))
    cooldown_seconds = int(get_policy(config, "restart_cooldown_seconds", 120))
    now = utc_now()
    recovered = 0
    with db() as conn:
        rows = conn.execute(
            """
            SELECT p.*,
                   r.started_at AS run_started_at,
                   r.log_path AS run_log_path,
                   r.status AS run_status
            FROM projects p
            LEFT JOIN runs r ON r.id = p.active_run_id
            WHERE p.status IN ('starting', 'running', 'verifying')
            ORDER BY p.id
            """
        ).fetchall()
    for row in rows:
        project_id = str(row["id"] or "").strip()
        if not project_id:
            continue
        try:
            project_cfg = get_project_cfg(config, project_id)
        except KeyError:
            continue
        activity_at = latest_worker_activity_at(project_cfg, row, row)
        if not activity_at or activity_at > now - dt.timedelta(seconds=stale_seconds):
            continue
        stale_age_seconds = int(max(0, (now - activity_at).total_seconds()))
        reason = f"worker session went stale after {stale_age_seconds}s without heartbeat or log activity"
        failures = int(row["consecutive_failures"] or 0) + 1
        next_status = "blocked" if failures >= max_failures else READY_STATUS
        cooldown_until = now + dt.timedelta(seconds=cooldown_seconds)
        task = live_runtime_task_handle(project_id)
        if task is not None:
            task.cancel()
        clear_runtime_task(project_id)
        with db() as conn:
            conn.execute(
                """
                UPDATE runs
                SET status='failed',
                    finished_at=COALESCE(finished_at, ?),
                    error_class='stale_heartbeat',
                    error_message=COALESCE(error_message, ?)
                WHERE id=?
                  AND status IN ('starting', 'running', 'verifying')
                """,
                (iso(now), reason, row["active_run_id"]),
            )
        update_project_status(
            project_id,
            status=next_status,
            current_slice=row["current_slice"],
            active_run_id=None,
            cooldown_until=cooldown_until,
            last_run_at=now,
            last_error=reason,
            consecutive_failures=failures,
            spider_tier=row["spider_tier"],
            spider_model=row["spider_model"],
            spider_reason=row["spider_reason"],
        )
        if next_status == READY_STATUS:
            record_project_auto_requeue(
                project_id,
                trigger="stale_worker_session_requeued",
                reason=reason,
                current_slice=row["current_slice"],
                run_id=int(row["active_run_id"] or 0) or None,
                queue_index=int(row["queue_index"] or 0),
                previous_status=str(row["status"] or "").strip(),
                next_status=next_status,
                evidence={
                    "recovered_at": iso(now),
                    "stale_age_seconds": stale_age_seconds,
                    "stale_threshold_seconds": stale_seconds,
                    "cooldown_until": iso(cooldown_until),
                    "activity_last_seen_at": iso(activity_at),
                },
            )
        else:
            open_or_update_incident(
                scope_type="project",
                scope_id=project_id,
                incident_kind=WORKER_STALLED_INCIDENT_KIND,
                severity="high",
                title=f"{project_id} worker lane stalled",
                summary="A worker session exceeded the stale-heartbeat threshold and the controller could not safely auto-requeue it.",
                context={
                    "project_id": project_id,
                    "current_slice": str(row["current_slice"] or "").strip(),
                    "last_error": reason,
                    "stale_age_seconds": stale_age_seconds,
                    "stale_threshold_seconds": stale_seconds,
                    "operator_required": True,
                    "can_resolve": False,
                },
            )
        recovered += 1
    if recovered:
        reconcile_stuck_work_package_runtime_links()
    return recovered


def reconcile_finished_run_links() -> int:
    with db() as conn:
        rows = conn.execute(
            """
            SELECT p.*,
                   r.status AS run_status
            FROM projects p
            LEFT JOIN runs r ON r.id = p.active_run_id
            WHERE p.active_run_id IS NOT NULL
            ORDER BY p.id
            """
        ).fetchall()
    reconciled = 0
    for row in rows:
        run_status = str(row["run_status"] or "").strip().lower()
        if run_status in {"starting", "running", "verifying"}:
            continue
        project_id = str(row["id"] or "").strip()
        if not project_id:
            continue
        clear_runtime_task(project_id)
        status = str(row["status"] or "").strip() or READY_STATUS
        if status in {"starting", "running", "verifying"}:
            status = READY_STATUS
        update_project_status(
            project_id,
            status=status,
            current_slice=row["current_slice"],
            active_run_id=None,
            cooldown_until=parse_iso(row["cooldown_until"]),
            last_run_at=parse_iso(row["last_run_at"]),
            last_error=row["last_error"],
            consecutive_failures=row["consecutive_failures"],
            spider_tier=row["spider_tier"],
            spider_model=row["spider_model"],
            spider_reason=row["spider_reason"],
        )
        reconciled += 1
    if reconciled or table_exists("work_packages"):
        reconciled += reconcile_stuck_work_package_runtime_links()
    return reconciled


def load_yaml(path: pathlib.Path) -> Dict[str, Any]:
    if not path.exists():
        return {}
    try:
        with path.open("r", encoding="utf-8") as f:
            return yaml.safe_load(f) or {}
    except yaml.YAMLError:
        # Generated queue/design overlays are recoverable runtime artifacts. Treat parse failures
        # as empty state so the scheduler can heal them on the next publish instead of crashing.
        if path.name in {"QUEUE.generated.yaml", "PROGRAM_MILESTONES.generated.yaml", "CONTRACT_SETS.yaml"} and (
            STUDIO_DIRNAME in path.parts or "groups" in path.parts
        ):
            return {}
        raise


def save_yaml(path: pathlib.Path, data: Dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp_path = path.with_suffix(path.suffix + ".tmp")
    with tmp_path.open("w", encoding="utf-8") as handle:
        yaml.safe_dump(data, handle, sort_keys=False, allow_unicode=True, width=100000)
    tmp_path.replace(path)


def deep_merge(a: Dict[str, Any], b: Dict[str, Any]) -> Dict[str, Any]:
    out = dict(a)
    for k, v in (b or {}).items():
        if isinstance(out.get(k), dict) and isinstance(v, dict):
            out[k] = deep_merge(out[k], v)
        else:
            out[k] = v
    return out


def normalize_global_account_policy(raw_policy: Any) -> Dict[str, Any]:
    merged = deep_merge(DEFAULT_GLOBAL_ACCOUNT_POLICY, raw_policy if isinstance(raw_policy, dict) else {})
    merged["protected_owner_ids"] = [
        str(item or "").strip()
        for item in merged.get("protected_owner_ids") or []
        if str(item or "").strip()
    ]
    classes = dict(merged.get("classes") or {})
    normalized_classes: Dict[str, Dict[str, Any]] = {}
    for class_name, defaults in DEFAULT_GLOBAL_ACCOUNT_POLICY["classes"].items():
        class_cfg = dict(defaults)
        override = dict(classes.get(class_name) or {})
        class_cfg.update(override)
        class_cfg["drain_policy"] = str(class_cfg.get("drain_policy") or defaults.get("drain_policy") or "").strip().lower()
        class_cfg["allowed_roles"] = [
            str(item or "").strip()
            for item in class_cfg.get("allowed_roles") or defaults.get("allowed_roles") or []
            if str(item or "").strip()
        ]
        class_cfg["eligible_pools"] = [
            str(item or "").strip()
            for item in class_cfg.get("eligible_pools") or defaults.get("eligible_pools") or []
            if str(item or "").strip()
        ]
        class_cfg["requires"] = [
            str(item or "").strip()
            for item in class_cfg.get("requires") or defaults.get("requires") or []
            if str(item or "").strip()
        ]
        normalized_classes[class_name] = class_cfg
    merged["classes"] = normalized_classes
    return merged


def global_account_policy(config: Dict[str, Any]) -> Dict[str, Any]:
    return normalize_global_account_policy((config.get("account_policy") or {}))


def account_owner_id(account_cfg: Any, *, alias: str = "") -> str:
    explicit = str(account_value(account_cfg, "owner_id", "") or "").strip()
    if explicit:
        return explicit
    clean_alias = str(alias or "").strip().lower()
    default_owner_map = {
        "acct-chatgpt-archon": "archon.megalon",
        "acct-chatgpt-b": "the.girscheles",
        "acct-chatgpt-core": "tibor.girschele",
    }
    return default_owner_map.get(clean_alias, "")


def account_classification(account_cfg: Any, *, alias: str = "", policy: Optional[Dict[str, Any]] = None) -> str:
    explicit = str(account_value(account_cfg, "account_class", "") or "").strip().lower()
    if explicit:
        return explicit
    owner_category = str(account_value(account_cfg, "owner_category", "") or "").strip().lower()
    if owner_category == PARTICIPANT_OWNER_CATEGORY or bool(account_value(account_cfg, "participant_burst_lane", False)):
        return PARTICIPANT_FUNDED_ACCOUNT_CLASS
    clean_policy = policy or DEFAULT_GLOBAL_ACCOUNT_POLICY
    owner_id = account_owner_id(account_cfg, alias=alias)
    if owner_id and owner_id in {str(item).strip() for item in clean_policy.get("protected_owner_ids") or [] if str(item).strip()}:
        return PROTECTED_OPERATOR_ACCOUNT_CLASS
    funding_class = str(account_value(account_cfg, "funding_class", "") or "").strip().lower()
    if funding_class:
        return funding_class
    auth_kind = str(account_value(account_cfg, "auth_kind", "") or "").strip().lower()
    if auth_kind == EA_AUTH_KIND:
        return OPERATOR_FUNDED_ACCOUNT_CLASS
    if auth_kind in CHATGPT_AUTH_KINDS:
        return UNCLASSIFIED_CHATGPT_ACCOUNT_CLASS
    return "operator"


def account_class_policy(policy: Dict[str, Any], account_class: str) -> Dict[str, Any]:
    return dict((policy.get("classes") or {}).get(account_class) or {})


def account_drain_policy(account_cfg: Any, *, alias: str = "", policy: Optional[Dict[str, Any]] = None) -> str:
    explicit = str(account_value(account_cfg, "drain_policy", "") or "").strip().lower()
    if explicit:
        return explicit
    clean_policy = policy or DEFAULT_GLOBAL_ACCOUNT_POLICY
    account_class = account_classification(account_cfg, alias=alias, policy=clean_policy)
    return str(account_class_policy(clean_policy, account_class).get("drain_policy") or "remainder").strip().lower()


def account_allowed_roles(account_cfg: Any, *, alias: str = "", policy: Optional[Dict[str, Any]] = None) -> List[str]:
    explicit = [str(item or "").strip() for item in account_value(account_cfg, "allowed_roles", []) or [] if str(item or "").strip()]
    if explicit:
        return explicit
    clean_policy = policy or DEFAULT_GLOBAL_ACCOUNT_POLICY
    account_class = account_classification(account_cfg, alias=alias, policy=clean_policy)
    return [
        str(item or "").strip()
        for item in account_class_policy(clean_policy, account_class).get("allowed_roles") or []
        if str(item or "").strip()
    ]


def account_is_protected_operator(account_cfg: Any, *, alias: str = "", policy: Optional[Dict[str, Any]] = None) -> bool:
    clean_policy = policy or DEFAULT_GLOBAL_ACCOUNT_POLICY
    return account_classification(account_cfg, alias=alias, policy=clean_policy) == PROTECTED_OPERATOR_ACCOUNT_CLASS


def account_is_participant_funded(account_cfg: Any, *, alias: str = "", policy: Optional[Dict[str, Any]] = None) -> bool:
    clean_policy = policy or DEFAULT_GLOBAL_ACCOUNT_POLICY
    return account_classification(account_cfg, alias=alias, policy=clean_policy) == PARTICIPANT_FUNDED_ACCOUNT_CLASS


def account_is_unclassified_chatgpt(account_cfg: Any, *, alias: str = "", policy: Optional[Dict[str, Any]] = None) -> bool:
    clean_policy = policy or DEFAULT_GLOBAL_ACCOUNT_POLICY
    return account_classification(account_cfg, alias=alias, policy=clean_policy) == UNCLASSIFIED_CHATGPT_ACCOUNT_CLASS


def account_token_pool_state(account_cfg: Any, row: Any = None, *, now: Optional[dt.datetime] = None) -> str:
    explicit = str(account_value(account_cfg, "token_pool_state", "") or "").strip().lower()
    if explicit:
        return explicit
    auth_kind = str(account_value(account_cfg, "auth_kind", account_value(row, "auth_kind", "api_key")) or "api_key").strip().lower()
    if auth_kind not in CHATGPT_AUTH_KINDS:
        return "n/a"
    if bool(account_value(account_cfg, "participant_burst_lane", False)):
        runtime_now = now or utc_now()
        state = account_runtime_state(row, account_cfg, runtime_now) if row is not None else str(account_value(account_cfg, "health_state", "ready") or "ready")
        return "valid" if state == "ready" else "invalid"
    if bool(account_value(account_cfg, "explicit_consent", False)) and str(account_value(account_cfg, "health_state", "ready") or "ready").strip().lower() == "ready":
        return "valid"
    return "unknown"


def account_has_explicit_consent(account_cfg: Any) -> bool:
    if account_value(account_cfg, "explicit_consent", None) is not None:
        return bool(account_value(account_cfg, "explicit_consent"))
    return bool(account_value(account_cfg, "participant_burst_lane", False))


def account_dispatch_role(decision: Dict[str, Any], *, emergency_fallback: bool = False) -> str:
    if emergency_fallback:
        return "emergency_fallback"
    lane = str(decision.get("lane") or "").strip().lower()
    if lane == "core" and bool(decision.get("requires_contract_authority")):
        return "core_authority"
    if lane in {"core_authority", "jury", "core_rescue"}:
        return lane
    return ORDINARY_BURST_ACCOUNT_ROLE


def participant_account_requirements_ok(
    account_cfg: Any,
    row: Any = None,
    *,
    now: Optional[dt.datetime] = None,
) -> Tuple[bool, str]:
    if not account_has_explicit_consent(account_cfg):
        return False, "participant consent missing"
    token_pool_state = account_token_pool_state(account_cfg, row, now=now)
    if token_pool_state not in {"valid", "ready"}:
        return False, f"participant token pool {token_pool_state or 'invalid'}"
    return True, ""


def quartermaster_participant_pool_snapshot(
    config: Dict[str, Any],
    *,
    now: Optional[dt.datetime] = None,
) -> Dict[str, Any]:
    runtime_now = now or utc_now()
    accounts_cfg = config.get("accounts") or {}
    global_policy = global_account_policy(config)
    account_rows: Dict[str, sqlite3.Row] = {}
    if table_exists("accounts"):
        with db() as conn:
            account_rows = {
                str(row["alias"] or "").strip(): row
                for row in conn.execute("SELECT * FROM accounts ORDER BY alias").fetchall()
                if str(row["alias"] or "").strip()
            }
    participant_aliases: List[str] = []
    ready_aliases: List[str] = []
    invalid_aliases: List[str] = []
    missing_consent_aliases: List[str] = []
    for alias, account_cfg in accounts_cfg.items():
        clean_alias = str(alias or "").strip()
        if not clean_alias or not account_is_participant_funded(account_cfg, alias=clean_alias, policy=global_policy):
            continue
        participant_aliases.append(clean_alias)
        row = account_rows.get(clean_alias)
        consent_ok = account_has_explicit_consent(account_cfg)
        token_pool_state = account_token_pool_state(account_cfg, row, now=runtime_now)
        pool_state = account_runtime_state(row, account_cfg, runtime_now) if row is not None else str(account_cfg.get("health_state") or "unknown").strip().lower()
        if not consent_ok:
            missing_consent_aliases.append(clean_alias)
            continue
        if token_pool_state not in {"valid", "ready"} or pool_state != "ready":
            invalid_aliases.append(clean_alias)
            continue
        ready_aliases.append(clean_alias)
    return {
        "participant_account_count": len(participant_aliases),
        "ready_accounts": sorted(ready_aliases),
        "invalid_accounts": sorted(invalid_aliases),
        "missing_consent_accounts": sorted(missing_consent_aliases),
        "drainable": bool(ready_aliases),
        "starved": bool(participant_aliases) and not bool(ready_aliases),
    }


def quartermaster_onemin_credit_waste_risk(
    config: Dict[str, Any],
    billing: Dict[str, Any],
    participant_pool: Dict[str, Any],
) -> bool:
    if not bool(participant_pool.get("drainable")):
        return False
    days_remaining_7d_avg = float_or_none(billing.get("days_remaining_including_next_topup_at_7d_avg"))
    if days_remaining_7d_avg is None:
        return False
    now = utc_now()
    cycle_days_remaining = max(0.0, (_month_end(now) - now).total_seconds() / 86400.0)
    if cycle_days_remaining <= 0:
        return False
    quartermaster_cfg = dict(config.get("quartermaster") or {})
    credit_cfg = dict(quartermaster_cfg.get("credit") or {})
    cycle_reserve_percent = max(10.0, float_or_none(credit_cfg.get("cycle_reserve_percent")) or 0.0)
    return days_remaining_7d_avg > (cycle_days_remaining * (1.0 + cycle_reserve_percent / 100.0))


def quartermaster_credit_waste_override_active(plan: Optional[Dict[str, Any]], *, target_lane: str = "") -> bool:
    if str(target_lane or "").strip().lower() not in {"core", "core_booster"}:
        return False
    typed_findings = list((plan or {}).get("typed_findings") or [])
    return any(str(item.get("type") or "").strip() == "onemin_credit_waste_risk" for item in typed_findings if isinstance(item, dict))


def quartermaster_account_order_recommendation(config: Dict[str, Any], target_lane: str) -> Dict[str, Any]:
    plan = quartermaster_capacity_plan()
    target = str(target_lane or "").strip().lower()
    recommendations = dict((plan.get("account_order_recommendations") or {}))
    if isinstance(recommendations.get(target), dict):
        return dict(recommendations.get(target) or {})
    protected_owner_ids = list(global_account_policy(config).get("protected_owner_ids") or [])
    credit_override = quartermaster_credit_waste_override_active(plan, target_lane=target)
    if target == "core_booster":
        participant_pool = quartermaster_participant_pool_snapshot(config)
        preferred = [OPERATOR_FUNDED_ACCOUNT_CLASS, PARTICIPANT_FUNDED_ACCOUNT_CLASS] if credit_override else [PARTICIPANT_FUNDED_ACCOUNT_CLASS, OPERATOR_FUNDED_ACCOUNT_CLASS]
        if not participant_pool.get("drainable"):
            preferred = [OPERATOR_FUNDED_ACCOUNT_CLASS]
        return {
            "preferred_account_classes": preferred,
            "blocked_account_classes": [PROTECTED_OPERATOR_ACCOUNT_CLASS, UNCLASSIFIED_CHATGPT_ACCOUNT_CLASS],
            "credit_waste_override_active": credit_override,
            "protected_owner_ids": protected_owner_ids,
        }
    if target in {"core_authority", "core_rescue", "jury"}:
        return {
            "preferred_account_classes": [PROTECTED_OPERATOR_ACCOUNT_CLASS, OPERATOR_FUNDED_ACCOUNT_CLASS],
            "blocked_account_classes": [PARTICIPANT_FUNDED_ACCOUNT_CLASS, UNCLASSIFIED_CHATGPT_ACCOUNT_CLASS],
            "credit_waste_override_active": False,
            "protected_owner_ids": protected_owner_ids,
        }
    return {
        "preferred_account_classes": [],
        "blocked_account_classes": [],
        "credit_waste_override_active": False,
        "protected_owner_ids": protected_owner_ids,
    }


def normalized_captain_policy(raw_policy: Any, *, default_service_floor: int = 1) -> Dict[str, Any]:
    policy = dict(DEFAULT_CAPTAIN_POLICY)
    if isinstance(raw_policy, dict):
        policy.update(raw_policy)
    policy["priority"] = int(policy.get("priority") or DEFAULT_CAPTAIN_POLICY["priority"])
    policy["service_floor"] = max(0, int(policy.get("service_floor") or default_service_floor))
    policy["shed_order"] = max(0, int(policy.get("shed_order") or DEFAULT_CAPTAIN_POLICY["shed_order"]))
    policy["preemption_policy"] = str(policy.get("preemption_policy") or DEFAULT_CAPTAIN_POLICY["preemption_policy"]).strip() or DEFAULT_CAPTAIN_POLICY["preemption_policy"]
    policy["admission_policy"] = str(policy.get("admission_policy") or DEFAULT_CAPTAIN_POLICY["admission_policy"]).strip() or DEFAULT_CAPTAIN_POLICY["admission_policy"]
    return policy


def normalize_lifecycle_state(value: Any, default: str = "dispatchable") -> str:
    clean = str(value or "").strip().lower() or str(default or "dispatchable").strip().lower()
    return clean if clean in VALID_LIFECYCLE_STATES else str(default or "dispatchable").strip().lower()


def project_dispatch_participates(project: Dict[str, Any]) -> bool:
    return normalize_lifecycle_state(project.get("lifecycle"), "dispatchable") in DISPATCH_PARTICIPATION_LIFECYCLES


def project_dispatch_priority(project: Dict[str, Any]) -> int:
    return int(project.get("dispatch_priority") or 100)


def normalized_project_groups(projects: List[Dict[str, Any]], groups: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    known_projects = {str(project.get("id", "")).strip() for project in projects if str(project.get("id", "")).strip()}
    assigned: set[str] = set()
    normalized: List[Dict[str, Any]] = []
    used_ids: set[str] = set()

    for raw_group in groups or []:
        group = dict(raw_group or {})
        group_id = str(group.get("id", "")).strip()
        if not group_id or group_id in used_ids:
            continue
        cleaned_projects: List[str] = []
        for raw_project_id in group.get("projects") or []:
            project_id = str(raw_project_id).strip()
            if not project_id or project_id not in known_projects or project_id in assigned:
                continue
            cleaned_projects.append(project_id)
            assigned.add(project_id)
        group["projects"] = cleaned_projects
        default_floor = len(cleaned_projects) if str(group.get("mode", "") or "").strip().lower() == "lockstep" and cleaned_projects else 1
        group["captain"] = normalized_captain_policy(group.get("captain"), default_service_floor=default_floor)
        used_ids.add(group_id)
        normalized.append(group)

    for project in projects:
        project_id = str(project.get("id", "")).strip()
        if not project_id or project_id in assigned:
            continue
        group_id = f"solo-{project_id}"
        suffix = 2
        while group_id in used_ids:
            group_id = f"solo-{project_id}-{suffix}"
            suffix += 1
        normalized.append(
            {
                "id": group_id,
                "projects": [project_id],
                "mode": "singleton",
                "contract_sets": [],
                "milestone_source": {},
                "group_roles": list(DEFAULT_SINGLETON_GROUP_ROLES),
                "captain": normalized_captain_policy({}, default_service_floor=1),
                "auto_created": True,
            }
        )
        used_ids.add(group_id)
        assigned.add(project_id)
    return normalized


def load_split_projects() -> List[Dict[str, Any]]:
    if not PROJECTS_DIR.exists() or not PROJECTS_DIR.is_dir():
        return []
    index_data = load_yaml(PROJECT_INDEX_PATH) if PROJECT_INDEX_PATH.exists() else {}
    indexed = [str(item).strip() for item in (index_data.get("projects") or []) if str(item).strip()]
    paths = [PROJECTS_DIR / item for item in indexed] if indexed else sorted(path for path in PROJECTS_DIR.glob("*.yaml") if path.name != PROJECT_INDEX_PATH.name)
    projects: List[Dict[str, Any]] = []
    for path in paths:
        data = load_yaml(path)
        if isinstance(data.get("projects"), list):
            projects.extend(dict(item or {}) for item in data.get("projects") or [] if isinstance(item, dict))
        elif isinstance(data, dict) and str(data.get("id") or "").strip():
            projects.append(dict(data))
        elif isinstance(data, dict):
            continue
    return projects


def merge_split_config(fleet: Dict[str, Any]) -> Dict[str, Any]:
    policies_data = load_yaml(POLICIES_PATH)
    routing_data = load_yaml(ROUTING_PATH)
    groups_data = load_yaml(GROUPS_PATH)
    split_projects = load_split_projects()
    if policies_data:
        fleet["policies"] = dict(policies_data.get("policies") or policies_data)
    if routing_data:
        fleet["spider"] = dict(routing_data.get("spider") or routing_data)
        lanes = routing_data.get("lanes") or {}
        if isinstance(lanes, dict):
            fleet["lanes"] = dict(lanes)
        core_backends = routing_data.get("core_backends") or {}
        if isinstance(core_backends, dict):
            fleet["core_backends"] = dict(core_backends)
    if groups_data:
        fleet["project_groups"] = list(groups_data.get("project_groups") or groups_data.get("groups") or [])
    if split_projects:
        fleet["projects"] = split_projects
    return fleet


def apply_project_queue_task_defaults(project_cfg: Dict[str, Any], item: Any) -> Any:
    defaults = project_cfg.get("queue_task_defaults") or {}
    if not isinstance(defaults, dict) or not defaults:
        return item
    if isinstance(item, dict):
        merged = dict(defaults)
        merged.update(dict(item))
        return merged
    merged = dict(defaults)
    title = normalize_slice_text(item)
    if title:
        merged.setdefault("title", title)
    return merged


def account_cost_budget_enforced(auth_kind: str, configured_lane: str) -> bool:
    clean_auth_kind = str(auth_kind or "").strip().lower()
    clean_lane = str(configured_lane or "").strip().lower()
    if clean_auth_kind == "ea" and clean_lane == "core":
        return False
    return True


def merge_dynamic_participant_accounts(fleet: Dict[str, Any]) -> None:
    accounts = dict(fleet.get("accounts") or {})
    core_backends = normalize_core_backends_config(fleet.get("core_backends"))
    lane_rows = participant_lane_rows(
        statuses=[
            PARTICIPANT_LANE_PENDING_AUTH,
            PARTICIPANT_LANE_ACTIVE,
            PARTICIPANT_LANE_PAUSED,
        ],
        refresh=False,
    )
    for lane_row in lane_rows:
        lane_id = str(lane_row.get("lane_id") or "").strip()
        if not lane_id:
            continue
        account_cfg = participant_lane_account_config(lane_row, core_backends)
        accounts[str(lane_row.get("account_alias") or "").strip()] = account_cfg
    fleet["accounts"] = accounts


def refresh_config_consistency_blockers(config: Dict[str, Any]) -> List[Dict[str, Any]]:
    global _CONFIG_CONSISTENCY_BLOCKERS, _CONFIG_CONSISTENCY_BLOCKER_SIGNATURE

    blockers = blocking_config_consistency_warnings(config)
    _CONFIG_CONSISTENCY_BLOCKERS = blockers
    if not blockers:
        _CONFIG_CONSISTENCY_BLOCKER_SIGNATURE = ""
        return blockers

    parts = []
    for warning in blockers:
        scope_id = str(warning.get("scope_id") or "unknown").strip() or "unknown"
        kind = str(warning.get("kind") or "unknown").strip() or "unknown"
        summary = str(warning.get("summary") or "").strip() or "no summary"
        parts.append(f"{scope_id}:{kind}:{summary}")
    signature = " | ".join(parts)
    if STRICT_CONFIG_CONSISTENCY:
        raise RuntimeError("config_consistency_errors:" + signature)
    if signature != _CONFIG_CONSISTENCY_BLOCKER_SIGNATURE:
        print(f"config_consistency_warnings:{signature}", file=sys.stderr)
        _CONFIG_CONSISTENCY_BLOCKER_SIGNATURE = signature
    return blockers


def config_source_signature() -> Tuple[Tuple[str, int, int], ...]:
    paths: List[pathlib.Path] = [
        CONFIG_PATH,
        ACCOUNTS_PATH,
        POLICIES_PATH,
        ROUTING_PATH,
        GROUPS_PATH,
        PROJECT_INDEX_PATH,
    ]
    if PROJECTS_DIR.exists() and PROJECTS_DIR.is_dir():
        paths.extend(sorted(path for path in PROJECTS_DIR.glob("*.yaml") if path.is_file()))

    signature: List[Tuple[str, int, int]] = []
    for path in paths:
        try:
            stat = path.stat()
        except OSError:
            signature.append((str(path), -1, -1))
            continue
        signature.append((str(path), int(stat.st_mtime_ns), int(stat.st_size)))

    if DB_PATH.exists():
        try:
            with db() as conn:
                table_info = conn.execute("PRAGMA table_info(participant_lanes)").fetchall()
                if not any(str(item["name"]) == "lane_id" for item in table_info):
                    raise sqlite3.Error("participant_lanes schema missing lane_id")
                has_updated_at = any(str(item["name"]) == "updated_at" for item in table_info)
                row = conn.execute(
                    """
                    SELECT COUNT(*) AS lane_count,
                           COALESCE(MAX(lane_id), '') AS max_lane_id
                           """ + (", COALESCE(MAX(updated_at), '') AS max_updated_at" if has_updated_at else "")
                    + """
                    FROM participant_lanes
                    """
                ).fetchone()
            if row:
                lane_count = row["lane_count"] if row["lane_count"] is not None else 0
                if has_updated_at:
                    digest_input = f"{lane_count}|{row['max_lane_id']}|{row['max_updated_at']}"
                else:
                    digest_input = f"{lane_count}|{row['max_lane_id']}"
                participant_digest = hashlib.sha256(digest_input.encode("utf-8")).hexdigest()
                signature.append(("participant_lanes", int(participant_digest[:16], 16), int(lane_count or 0)))
        except sqlite3.Error:
            signature.append(("participant_lanes", -1, -1))
    return tuple(signature)


